/// W1.1 (Fix 4) — fail-closed precondition for the entity/edge write path.
///
/// The W1.1 threadlocal write-boundary assertion in `zaki_postgres.zig`
/// covers `implStore`/`implStoreWithMetadata` only. The async extraction
/// worker (daemon heartbeat → `entity_pipeline.runOnTurn`) writes
/// entities/edges via `upsertEntity`/`upsertMemoryEdgeRich` DIRECTLY on the
/// Manager — it does NOT install the per-turn `ToolTenantContext`
/// threadlocal, so that assertion does not run on this path. Isolation here
/// relies on the queue-row `user_id` parameterized into SQL.
///
/// This is the defensive complement: every entity/edge write carries an
/// explicit `user_id` argument, and a `user_id <= 0` is never a legitimate
/// tenant (valid tenants are positive `zaki_users` ids). A zero/negative id
/// means an uninitialized or corrupted caller — refuse before the row can
/// land. Localized: a single integer precondition, no threadlocal, no new
/// parameters threaded through call sites, no hot-path cost beyond one
/// compare. Fires loud (Sentry) like the W1.1 assertion so the corruption
/// is observable rather than silently writing under a bogus id.
pub const EntityEdgeWriteUserIdViolation = error.EntityEdgeWriteUserIdViolation;

// P1-9 (2026-06-12): how long the `external_identity_status = .unavailable`
// fail-open short-circuit stays latched before `hasExternalIdentity`
// re-probes `public.zaki_users`. A genuinely-absent table keeps the
// noisy-log mitigation (it re-latches each window, ~1 probe per window
// instead of ~200 per session); a transient probe failure self-heals on
// the next re-probe after the window elapses. 5 minutes balances "don't
// hammer a known-absent table" against "don't leave identity verification
// disabled for an entire long-lived Manager after one blip."
const EXTERNAL_IDENTITY_REPROBE_MS: i64 = 5 * 60 * 1000;

// Sentinel latch time meaning "never re-probe" — used by the test-only
// `skipExternalIdentityForTests` bypass so the TTL re-probe (P1-9) can't
// undo the pin mid-test. No real wall-clock milliTimestamp ever equals
// maxInt, so this is unambiguous.
const EXTERNAL_IDENTITY_PIN_FOREVER: i64 = std.math.maxInt(i64);

// P1-3 (2026-06-12): extraction-queue backpressure cap. The daemon worker
// drains the queue at MAX_JOBS_PER_TICK=2 (src/daemon.zig), but the producer
// side (enqueueExtractionJob, called from session-end / boundary paths) was
// unbounded: a burst of session_end checkpoints (mass idle-eviction, a
// reconnect storm, or a single chatty session re-ending repeatedly) could grow
// `extraction_queue` without bound, costing unbounded PG rows and a worker
// backlog that never drains. Two defenses, applied at enqueue time:
//   (1) coalesce — a pending job for the same (user, session, job_type) is
//       reused (oldest-wins): the new enqueue returns the existing job id and
//       inserts nothing. session_end/wiki_link extraction is idempotent w.r.t.
//       re-runs, so coalescing a duplicate (session,kind) never loses work.
//   (2) depth cap — if pending depth is at/over the cap, the oldest pending
//       job is dropped (and logged) to make room for the newer one. Newer
//       work is more representative of current session state; the dropped
//       slice's raw bytes still live in conversation_messages and re-extract
//       on the next idle pass. The cap is global (across users) because the
//       worker is global; per-cell pod isolation keeps single-user load well
//       under it in practice.
const EXTRACTION_QUEUE_DEPTH_CAP: usize = 256;

/// Pure TTL decision for the external-identity fail-open cache (P1-9).
/// Returns true when `hasExternalIdentity` should re-probe `public.zaki_users`
/// rather than short-circuit on the cached `.unavailable` state. Factored out
/// (no Manager / no live PG) so the TTL boundary is unit-testable.
///   - `is_unavailable` false        → not latched → must probe (true).
///   - since == PIN_FOREVER          → test pin → never re-probe (false).
///   - latched, now < since+ttl      → within window → short-circuit (false).
///   - latched, now >= since+ttl     → window elapsed → re-probe (true).
fn shouldReprobeExternalIdentity(is_unavailable: bool, since_ms: i64, now_ms: i64, ttl_ms: i64) bool {
    if (!is_unavailable) return true;
    if (since_ms == EXTERNAL_IDENTITY_PIN_FOREVER) return false;
    return (now_ms - since_ms) >= ttl_ms;
}

fn assertEntityEdgeWriteUserId(user_id: i64) !void {
    if (user_id > 0) return; // happy path — zero behavior change

    var msg_buf: [128]u8 = undefined;
    const msg = std.fmt.bufPrint(
        &msg_buf,
        "refused entity/edge write with non-positive user_id={d}",
        .{user_id},
    ) catch "refused entity/edge write with non-positive user_id (omitted)";
    if (!builtin.is_test) {
        std.log.err("zaki_state: {s}", .{msg});
    }
    sentry_runtime.globalOrFallback().captureError("entity_edge_user_id_violation", msg);
    return error.EntityEdgeWriteUserIdViolation;
}

test "assertEntityEdgeWriteUserId accepts positive user_id" {
    try assertEntityEdgeWriteUserId(1);
    try assertEntityEdgeWriteUserId(2);
    try assertEntityEdgeWriteUserId(std.math.maxInt(i64));
}

test "assertEntityEdgeWriteUserId refuses zero and negative user_id (Fix 4)" {
    try std.testing.expectError(error.EntityEdgeWriteUserIdViolation, assertEntityEdgeWriteUserId(0));
    try std.testing.expectError(error.EntityEdgeWriteUserIdViolation, assertEntityEdgeWriteUserId(-1));
    try std.testing.expectError(error.EntityEdgeWriteUserIdViolation, assertEntityEdgeWriteUserId(std.math.minInt(i64)));
}

