    user_id: i64,
    session_key: []const u8,
    /// Deterministic per-turn id (the agent's run_id). `(user_id, turn_key)`
    /// is UNIQUE; the insert uses ON CONFLICT DO NOTHING for idempotency.
    turn_key: []const u8,
    /// "http" | "daemon" — see EntryKind.toSlice / migration 0004.
    entry_kind: []const u8,
    /// TurnOrigin enum value: user|heartbeat|scheduler|wake|proactive|mcp.
    turn_origin: []const u8,
    model: []const u8,
    input_tokens: u64,
    output_tokens: u64,
    cost_usd: f64,
    /// false → pricing table had no entry; the BFF settles tokens, not $0.
    cost_available: bool,
};

/// **P0-4 (Wave A agent-runtime resilience)** — input to
/// `upsertPendingApproval`. One durable `{schema}.pending_approvals` row per
/// in-flight tool approval (migration 0005). All slices are borrowed for the
/// duration of the call (the impl dupes what it needs for the libpq params),
/// so the caller may free them after return.
pub const PendingApprovalInput = struct {
    /// Stable wire id (`apr-<u64>`) — PRIMARY KEY, also the FE card pin.
    approval_id: []const u8,
    session_key: []const u8,
    /// FK to `{schema}.users(user_id)`. The write self-heals this parent
    /// row via ensureUserRow first, so the FK can never fault.
    user_id: i64,
    tool_name: []const u8,
    tool_call_id: ?[]const u8,
    arguments_json: []const u8,
    reason: []const u8,
    /// RiskLevel slice ("low" | "medium" | "high" | ...).
    risk_level: []const u8,
};

/// **P0-4** — a rehydrated open approval snapshot read back from
/// `{schema}.pending_approvals` on session (re)build. Owned slices; caller
/// must call `deinit`.
pub const PendingApprovalRow = struct {
    approval_id: []u8,
    tool_name: []u8,
    tool_call_id: ?[]u8,
    arguments_json: []u8,
    reason: []u8,
    risk_level: []u8,
    created_at_unix: i64,

    pub fn deinit(self: *@This(), allocator: std.mem.Allocator) void {
        allocator.free(self.approval_id);
        allocator.free(self.tool_name);
        if (self.tool_call_id) |id| allocator.free(id);
        allocator.free(self.arguments_json);
        allocator.free(self.reason);
        allocator.free(self.risk_level);
    }
};

/// **Subagent Pass Phase 1** — borrowed-slice input for upsertSubagentResult.
/// Caller owns the memory; the function dupes everything it needs to persist.
pub const SubagentResultInput = struct {
    result_id: []const u8, // formatted "subagent:<task_id>"
    user_id: i64,
    session_key: []const u8,
    task_id: i64,
    result_json: []const u8, // Phase-1: {status,text}; Phase-2: full SubagentResult JSON
};

/// **Subagent Pass Phase 1** — an owned-slice row rehydrated from
/// {schema}.subagent_results. Call deinit() to free all slices.
pub const SubagentResultRow = struct {
    result_id: []const u8,
    session_key: []const u8,
    task_id: i64,
    result_json: []const u8,

    pub fn deinit(self: SubagentResultRow, allocator: std.mem.Allocator) void {
        allocator.free(self.result_id);
        allocator.free(self.session_key);
        allocator.free(self.result_json);
    }
};

pub const ArtifactVersionRow = struct {
    artifact_id: []u8,
    version: u64,
    parent_version: ?u64,
    content: []u8,
    content_hash: []u8,
    created_at_unix: i64,
    author: []u8,
    change_summary: ?[]u8,

    pub fn deinit(self: *@This(), allocator: std.mem.Allocator) void {
        allocator.free(self.artifact_id);
        allocator.free(self.content);
        allocator.free(self.content_hash);
        allocator.free(self.author);
        if (self.change_summary) |s| allocator.free(s);
    }
};

pub const ArtifactHistoryRow = struct {
    version: u64,
    parent_version: ?u64,
    author: []u8,
    created_at_unix: i64,
    change_summary: ?[]u8,
    content_hash: []u8,

    pub fn deinit(self: *@This(), allocator: std.mem.Allocator) void {
        allocator.free(self.author);
        if (self.change_summary) |s| allocator.free(s);
        allocator.free(self.content_hash);
    }
};

/// Test-only helper: build a unique schema name of the form
/// `<prefix>_<microTimestamp>`. `buf` must be ≥ 96 bytes. The 28+ inline
/// `bufPrint(..., "<some_prefix>_{d}", .{microTimestamp()})` call sites
/// in this file (and `src/session.zig` / `tests/agent/...`) should
/// migrate to this helper in a follow-up cleanup sweep — one source of
/// truth instead of 29.
pub fn buildTestSchemaName(buf: []u8, prefix: []const u8) ![]const u8 {
    return try std.fmt.bufPrint(buf, "{s}_{d}", .{ prefix, std.time.microTimestamp() });
}

pub fn freeArtifactRows(allocator: std.mem.Allocator, list: []ArtifactRow) void {
    for (list) |*r| r.deinit(allocator);
    allocator.free(list);
}

pub fn freeArtifactHistoryRows(allocator: std.mem.Allocator, list: []ArtifactHistoryRow) void {
    for (list) |*r| r.deinit(allocator);
    allocator.free(list);
}

