const ManagerImpl = struct {
    const PoolEntry = struct {
        conn: *c.PGconn,
        in_use: bool,
        last_used_s: i64,
    };

    const ConnLease = struct {
        conn: *c.PGconn,
        entry_index: usize,
        released: bool = false,
    };

    /// V1.14.12 (Memory audit Finding 3 fix, 2026-05-19) —
    /// connection-pinned transaction.
    ///
    /// PostgreSQL transactions are connection-scoped. Before TxnLease,
    /// the pattern `try self.exec("BEGIN")` + subsequent
    /// `self.execParams(...)` calls each acquired AND RELEASED a pool
    /// connection per call. Under any concurrent load:
    ///   - BEGIN ran on conn-X, immediately returned conn-X to the pool
    ///   - the next INSERT acquired conn-Y (auto-committing
    ///     independently, no active transaction on conn-Y)
    ///   - the `errdefer` ROLLBACK ran on conn-Z (no transaction there
    ///     either — silent no-op)
    ///
    /// Default pool_max is 4 (memory backend) / 16 (state backend), so
    /// the bug is real under any multi-goroutine load.
    ///
    /// TxnLease holds ONE connection across all statements between
    /// begin and commit/rollback, restoring the atomicity contract.
    /// Use it for any multi-statement transaction:
    ///
    ///     var txn = try mgr.beginTransaction();
    ///     defer txn.deinit(); // rollback-if-not-committed safety
    ///     const r1 = try txn.execParams(q1, &p1, &l1);
    ///     c.PQclear(r1);
    ///     // ... more statements on the same pinned conn ...
    ///     try txn.commit();
    ///
    /// commit() and rollback() are idempotent — safe to call multiple
    /// times. deinit() is a no-op after commit/rollback. The intended
    /// idiom is `defer txn.deinit()` + explicit `try txn.commit()` at
    /// the success path; on error the defer's rollback fires.
    pub const TxnLease = struct {
        mgr: *Self,
        lease: ConnLease,
        conn_healthy: bool = true,
        finalized: bool = false,

        /// Run a query on the pinned connection. NO pool acquire.
        pub fn exec(self: *TxnLease, query: []const u8) !*c.PGresult {
            const query_z = try self.mgr.allocator.dupeZ(u8, query);
            defer self.mgr.allocator.free(query_z);
            const result = c.PQexec(self.lease.conn, query_z) orelse {
                self.conn_healthy = false;
                return error.ExecFailed;
            };
            const status = c.PQresultStatus(result);
            if (status != c.PGRES_COMMAND_OK and status != c.PGRES_TUPLES_OK) {
                if (c.PQstatus(self.lease.conn) != c.CONNECTION_OK) self.conn_healthy = false;
                // Finding C fix (coordinator review, 2026-05-21): gate the
                // failure log on !builtin.is_test. A failed postgres op here
                // returns error.ExecFailed to the caller, which owns severity
                // classification. Negative-path tests (e.g.
                // postgres_pool_releases_on_exec_error) intentionally provoke
                // the failure; an unconditional log.err trips the Zig test
                // runner's logged-error check, failing the build even though
                // the test itself passed. Production (is_test=false) still logs.
                if (!builtin.is_test) log.err("postgres txn exec failed: {s}", .{c.PQerrorMessage(self.lease.conn)});
                capturePostgresExecFailure("postgres txn exec failed", c.PQerrorMessage(self.lease.conn));
                c.PQclear(result);
                return error.ExecFailed;
            }
            return result;
        }

        /// Run a parameterized query on the pinned connection. NO pool acquire.
        pub fn execParams(self: *TxnLease, query: []const u8, params: []const ?[*:0]const u8, lengths: []const c_int) !*c.PGresult {
            const query_z = try self.mgr.allocator.dupeZ(u8, query);
            defer self.mgr.allocator.free(query_z);
            // Postgres UTF-8 write guard — see sanitizeParamsForUtf8.
            var safe = try sanitizeParamsForUtf8(self.mgr.allocator, params, lengths);
            defer safe.deinit();
            const n: c_int = @intCast(safe.params.len);
            const result = c.PQexecParams(
                self.lease.conn,
                query_z,
                n,
                null,
                safe.params.ptr,
                safe.lengths.ptr,
                null,
                0,
            ) orelse {
                self.conn_healthy = false;
                return error.ExecFailed;
            };
            const status = c.PQresultStatus(result);
            if (status != c.PGRES_COMMAND_OK and status != c.PGRES_TUPLES_OK) {
                if (c.PQstatus(self.lease.conn) != c.CONNECTION_OK) self.conn_healthy = false;
                // Finding C fix (2026-05-21): gate on !builtin.is_test — see TxnLease.exec.
                if (!builtin.is_test) log.err("postgres txn execParams failed: {s}", .{c.PQerrorMessage(self.lease.conn)});
                capturePostgresExecFailure("postgres txn execParams failed", c.PQerrorMessage(self.lease.conn));
                c.PQclear(result);
                return error.ExecFailed;
            }
            return result;
        }

        /// Commit the transaction and release the pinned connection.
        /// Idempotent: subsequent commit/rollback/deinit calls are no-ops.
        pub fn commit(self: *TxnLease) !void {
            if (self.finalized) return;
            const result = self.exec("COMMIT") catch |err| {
                // COMMIT failed — attempt ROLLBACK so the conn returns
                // clean (or unhealthy) instead of stuck in an open txn.
                self.rollback();
                return err;
            };
            c.PQclear(result);
            self.finalized = true;
            self.mgr.releaseConn(&self.lease, self.conn_healthy);
        }

        /// Rollback the transaction (best-effort) and release the conn.
        /// Idempotent. If ROLLBACK itself fails, marks the conn unhealthy
        /// so releaseConn closes it (don't return a poisoned conn to pool).
        pub fn rollback(self: *TxnLease) void {
            if (self.finalized) return;
            if (self.exec("ROLLBACK")) |result| {
                c.PQclear(result);
            } else |_| {
                self.conn_healthy = false;
            }
            self.finalized = true;
            self.mgr.releaseConn(&self.lease, self.conn_healthy);
        }

        /// Defensive rollback-if-not-finalized. Always safe to call.
        /// Designed for `defer txn.deinit()` paired with an explicit
        /// `try txn.commit()` at the success path.
        pub fn deinit(self: *TxnLease) void {
            if (!self.finalized) self.rollback();
        }
    };

    pub const PoolDebugSnapshot = struct {
        pool_max: u32,
        open_conns: u32,
        in_use: u32,
        waiters: u32,
        acquire_timeouts: u64,
    };

    allocator: std.mem.Allocator,
    conn_string_z: [:0]u8,
    schema_raw_buf: [64]u8,
    schema_raw_len: usize,
    secrets_enabled: bool,
    master_key: ?[security_secrets.KEY_LEN]u8,
    pool_entries: std.ArrayListUnmanaged(PoolEntry),
    pool_mutex: std.Thread.Mutex,
    pool_cond: std.Thread.Condition,
    pool_max: u32,
    pool_opening: u32,
    pool_waiters: u32,
    pool_acquire_timeouts: u64,
    statement_timeout_ms: u32,
    lock_timeout_ms: u32,
    // F6 (2026-05-10): cached existence flag for the cross-schema
    // `public.zaki_users` FK target. When the zaki-prod backend isn't
    // co-located (nullalis-only dev / standalone deploys), the table
    // doesn't exist. Without this cache, every `hasExternalIdentity`
    // call hits the noisy `relation does not exist` postgres error path
    // — a real bench run logged ~200 of these in one session. First
    // failure sets this flag true; subsequent calls short-circuit
    // silently. Reset to .unknown on a new connection (future: cell
    // pod hot-swap).
    //
    // P1-9 (2026-06-12): the `.unavailable` short-circuit is now TTL'd.
    // Pre-P1-9 a SINGLE transient probe failure (e.g. a momentary
    // ExecFailed / ConnectionFailed while public.zaki_users was reachable
    // but the conn blipped) latched `.unavailable` for the whole Manager
    // lifetime — permanently disabling identity verification and silently
    // turning the gate fully fail-open. We keep the fail-open behavior
    // WITHIN the TTL window (so the noisy-log mitigation still holds for a
    // genuinely-absent table) but re-probe after the window so a transient
    // failure self-heals. `external_identity_unavailable_since_ms` is the
    // monotonic-ish wall-clock (milliTimestamp) of the latching failure.
    external_identity_status: enum { unknown, available, unavailable } = .unknown,
    external_identity_unavailable_since_ms: i64 = 0,

    pub const ClaimedJob = struct {
        id: []u8,
        user_id: i64,
        session_id: []u8,
        workspace_path: []u8,
        raw_job_json: []u8,

        pub fn deinit(self: *@This(), allocator: std.mem.Allocator) void {
            allocator.free(self.id);
            allocator.free(self.session_id);
            allocator.free(self.workspace_path);
            allocator.free(self.raw_job_json);
        }
    };

    pub const UserSessionStore = struct {
        allocator: std.mem.Allocator,
        manager: *ManagerImpl,
        user_id: i64,

        pub fn init(allocator: std.mem.Allocator, manager_ptr: *anyopaque, user_id: i64) !UserSessionStore {
            const manager: *ManagerImpl = @ptrCast(@alignCast(manager_ptr));
            return .{
                .allocator = allocator,
                .manager = manager,
                .user_id = user_id,
            };
        }

        pub fn deinit(_: *UserSessionStore) void {}

        pub fn sessionStore(self: *UserSessionStore) memory_root.SessionStore {
            return .{
                .ptr = self,
                .vtable = &.{
                    .saveMessage = saveMessage,
                    .saveMessageRich = saveMessageRich,
                    .loadMessages = loadMessages,
                    .clearMessages = clearMessages,
                    .clearAutoSaved = clearAutoSaved,
                    .saveCompletionEvent = saveCompletionEventBridge,
                    .loadCompletionEvents = loadCompletionEventsBridge,
                    .deleteCompletionEvent = deleteCompletionEventBridge,
                },
            };
        }

        fn saveMessage(ptr: *anyopaque, session_id: []const u8, role: []const u8, content: []const u8) anyerror!void {
            const self: *UserSessionStore = @ptrCast(@alignCast(ptr));
            try self.manager.saveSessionMessage(self.user_id, session_id, role, content);
        }

        /// P1-5 — bridge the optional rich save to the Manager's column-aware
        /// persist path so a reloaded assistant turn carries its tool_calls +
        /// reasoning.
        fn saveMessageRich(ptr: *anyopaque, session_id: []const u8, role: []const u8, content: []const u8, tool_calls_json: ?[]const u8, reasoning: ?[]const u8) anyerror!void {
            const self: *UserSessionStore = @ptrCast(@alignCast(ptr));
            try self.manager.saveSessionMessageRich(self.user_id, session_id, role, content, tool_calls_json, reasoning);
        }

        fn loadMessages(ptr: *anyopaque, allocator: std.mem.Allocator, session_id: []const u8) anyerror![]memory_root.MessageEntry {
            const self: *UserSessionStore = @ptrCast(@alignCast(ptr));
            return try self.manager.loadSessionMessages(allocator, self.user_id, session_id);
        }

        fn clearMessages(ptr: *anyopaque, session_id: []const u8) anyerror!void {
            const self: *UserSessionStore = @ptrCast(@alignCast(ptr));
            try self.manager.clearSessionMessages(self.user_id, session_id);
        }

        fn clearAutoSaved(ptr: *anyopaque, session_id: ?[]const u8) anyerror!void {
            const self: *UserSessionStore = @ptrCast(@alignCast(ptr));
            try self.manager.clearAutoSavedMemory(self.user_id, session_id);
        }

        fn saveCompletionEventBridge(ptr: *anyopaque, allocator: std.mem.Allocator, session_id: []const u8, channel: ?[]const u8, account_id: ?[]const u8, chat_id: ?[]const u8, content: []const u8) anyerror![]u8 {
            const self: *UserSessionStore = @ptrCast(@alignCast(ptr));
            return try self.manager.saveCompletionEvent(allocator, self.user_id, session_id, channel, account_id, chat_id, content);
        }

        fn loadCompletionEventsBridge(ptr: *anyopaque, allocator: std.mem.Allocator, session_id: []const u8) anyerror![]memory_root.CompletionEvent {
            const self: *UserSessionStore = @ptrCast(@alignCast(ptr));
            return try self.manager.loadCompletionEvents(allocator, self.user_id, session_id);
        }

        fn deleteCompletionEventBridge(ptr: *anyopaque, event_id: []const u8) anyerror!void {
            const self: *UserSessionStore = @ptrCast(@alignCast(ptr));
            try self.manager.deleteCompletionEvent(self.user_id, event_id);
        }
    };

    const Self = @This();

    pub fn init(allocator: std.mem.Allocator, cfg: config_types.StateConfig) !Self {
        try pg_helpers.validateIdentifier(cfg.postgres.schema);
        if (cfg.postgres.connection_string.len == 0) return error.MissingConnectionString;

        const conn_string = try allocator.dupeZ(u8, cfg.postgres.connection_string);
        errdefer allocator.free(conn_string);

        var schema_raw_buf: [64]u8 = undefined;
        @memset(&schema_raw_buf, 0);
        @memcpy(schema_raw_buf[0..cfg.postgres.schema.len], cfg.postgres.schema);

        var manager = Self{
            .allocator = allocator,
            .conn_string_z = conn_string,
            .schema_raw_buf = schema_raw_buf,
            .schema_raw_len = cfg.postgres.schema.len,
            .secrets_enabled = true,
            .master_key = null,
            .pool_entries = .empty,
            .pool_mutex = .{},
            .pool_cond = .{},
            .pool_max = std.math.clamp(cfg.postgres.pool_max, 1, 256),
            .pool_opening = 0,
            .pool_waiters = 0,
            .pool_acquire_timeouts = 0,
            .statement_timeout_ms = cfg.postgres.statement_timeout_ms,
            .lock_timeout_ms = cfg.postgres.lock_timeout_ms,
        };

        manager.secrets_enabled = true;
        manager.master_key = try loadMasterKey(allocator, cfg.secrets.master_key_env);
        try manager.migrate();
        return manager;
    }

    pub fn deinit(self: *Self) void {
        self.closeAllPoolConns();
        self.pool_entries.deinit(self.allocator);
        self.allocator.free(self.conn_string_z);
    }

    pub fn debugPoolSnapshot(self: *Self) PoolDebugSnapshot {
        self.pool_mutex.lock();
        defer self.pool_mutex.unlock();
        var in_use: u32 = 0;
        for (self.pool_entries.items) |entry| {
            if (entry.in_use) in_use += 1;
        }
        return .{
            .pool_max = self.pool_max,
            .open_conns = @intCast(self.pool_entries.items.len),
            .in_use = in_use,
            .waiters = self.pool_waiters,
            .acquire_timeouts = self.pool_acquire_timeouts,
        };
    }

    /// Raw (unquoted) tenant schema name. `pub` so cross-module tests (e.g. the
    /// subagent_results PG recovery tests in subagent.zig) can build the
    /// DROP SCHEMA cleanup query under the postgres engine.
    pub fn schemaRaw(self: *const Self) []const u8 {
        return self.schema_raw_buf[0..self.schema_raw_len];
    }

    /// Test-only helper: `DROP SCHEMA IF EXISTS <self.schema> CASCADE`.
    /// Used by cross-module integration tests that provision a
    /// throwaway schema (e.g. gateway.zig D11 vault route tests) and
    /// need to drop it on teardown without re-importing pg_helpers in
    /// the caller. The schema name is validated + quoted before the
    /// DDL runs, matching every other DDL path in this module.
    pub fn dropSchemaForTests(self: *Self) !void {
        try pg_helpers.validateIdentifier(self.schemaRaw());
        const schema_q = try pg_helpers.quoteIdentifier(self.allocator, self.schemaRaw());
        defer self.allocator.free(schema_q);
        const drop_sql = try std.fmt.allocPrint(self.allocator, "DROP SCHEMA IF EXISTS {s} CASCADE", .{schema_q});
        defer self.allocator.free(drop_sql);
        const result = try self.exec(drop_sql);
        c.PQclear(result);
    }

    fn applySessionSettingsToConn(self: *Self, conn: *c.PGconn) !void {
        if (self.statement_timeout_ms > 0) {
            var buf: [64]u8 = undefined;
            const value = try std.fmt.bufPrint(&buf, "SET statement_timeout = {d}", .{self.statement_timeout_ms});
            const query_z = try self.allocator.dupeZ(u8, value);
            defer self.allocator.free(query_z);
            const result = c.PQexec(conn, query_z) orelse return error.ExecFailed;
            defer c.PQclear(result);
            const status = c.PQresultStatus(result);
            if (status != c.PGRES_COMMAND_OK and status != c.PGRES_TUPLES_OK) return error.ExecFailed;
        }
        if (self.lock_timeout_ms > 0) {
            var buf: [64]u8 = undefined;
            const value = try std.fmt.bufPrint(&buf, "SET lock_timeout = {d}", .{self.lock_timeout_ms});
            const query_z = try self.allocator.dupeZ(u8, value);
            defer self.allocator.free(query_z);
            const result = c.PQexec(conn, query_z) orelse return error.ExecFailed;
            defer c.PQclear(result);
            const status = c.PQresultStatus(result);
            if (status != c.PGRES_COMMAND_OK and status != c.PGRES_TUPLES_OK) return error.ExecFailed;
        }
    }

    fn openConn(self: *Self) !*c.PGconn {
        const conn = c.PQconnectdb(self.conn_string_z.ptr) orelse return error.ConnectionFailed;
        errdefer c.PQfinish(conn);
        if (c.PQstatus(conn) != c.CONNECTION_OK) return error.ConnectionFailed;
        try self.applySessionSettingsToConn(conn);
        return conn;
    }

    fn acquireConn(self: *Self, wait_ms: u32) !ConnLease {
        const start_ms = std.time.milliTimestamp();
        while (true) {
            self.pool_mutex.lock();

            for (self.pool_entries.items, 0..) |*entry, idx| {
                if (!entry.in_use) {
                    entry.in_use = true;
                    entry.last_used_s = std.time.timestamp();
                    self.pool_mutex.unlock();
                    return .{ .conn = entry.conn, .entry_index = idx };
                }
            }

            if (self.pool_entries.items.len + self.pool_opening < self.pool_max) {
                self.pool_opening += 1;
                self.pool_mutex.unlock();

                const conn = self.openConn() catch |err| {
                    self.pool_mutex.lock();
                    self.pool_opening -= 1;
                    self.pool_cond.signal();
                    self.pool_mutex.unlock();
                    return err;
                };

                self.pool_mutex.lock();
                self.pool_opening -= 1;

                if (self.pool_entries.items.len >= self.pool_max) {
                    c.PQfinish(conn);
                    self.pool_cond.signal();
                    self.pool_mutex.unlock();
                    continue;
                }

                const entry_idx = self.pool_entries.items.len;
                try self.pool_entries.append(self.allocator, .{
                    .conn = conn,
                    .in_use = true,
                    .last_used_s = std.time.timestamp(),
                });
                self.pool_mutex.unlock();
                return .{ .conn = conn, .entry_index = entry_idx };
            }

            if (wait_ms == 0) {
                self.pool_waiters += 1;
                self.pool_cond.wait(&self.pool_mutex);
                self.pool_waiters -= 1;
                self.pool_mutex.unlock();
                continue;
            }

            const now_ms = std.time.milliTimestamp();
            const elapsed_ms: u64 = @intCast(@max(0, now_ms - start_ms));
            if (elapsed_ms >= wait_ms) {
                self.pool_acquire_timeouts += 1;
                self.pool_mutex.unlock();
                return error.ConnectionPoolBusy;
            }
            const remaining_ms = wait_ms - elapsed_ms;

            self.pool_waiters += 1;
            self.pool_cond.timedWait(&self.pool_mutex, remaining_ms * std.time.ns_per_ms) catch |err| switch (err) {
                error.Timeout => {
                    self.pool_waiters -= 1;
                    self.pool_acquire_timeouts += 1;
                    self.pool_mutex.unlock();
                    return error.ConnectionPoolBusy;
                },
            };
            self.pool_waiters -= 1;
            self.pool_mutex.unlock();
        }
    }

    fn releaseConn(self: *Self, lease: *ConnLease, healthy: bool) void {
        if (lease.released) return;

        self.pool_mutex.lock();
        defer self.pool_mutex.unlock();

        if (self.pool_entries.items.len == 0) {
            lease.released = true;
            return;
        }

        var idx = if (lease.entry_index < self.pool_entries.items.len) lease.entry_index else self.pool_entries.items.len - 1;
        if (self.pool_entries.items[idx].conn != lease.conn) {
            var found = false;
            for (self.pool_entries.items, 0..) |entry, entry_idx| {
                if (entry.conn == lease.conn) {
                    idx = entry_idx;
                    found = true;
                    break;
                }
            }
            if (!found) {
                lease.released = true;
                return;
            }
        }

        const conn_ok = c.PQstatus(lease.conn) == c.CONNECTION_OK;
        if (!healthy or !conn_ok) {
            c.PQfinish(self.pool_entries.items[idx].conn);
            _ = self.pool_entries.swapRemove(idx);
        } else {
            self.pool_entries.items[idx].in_use = false;
            self.pool_entries.items[idx].last_used_s = std.time.timestamp();
        }

        lease.released = true;
        self.pool_cond.signal();
    }

    fn closeAllPoolConns(self: *Self) void {
        self.pool_mutex.lock();
        defer self.pool_mutex.unlock();
        for (self.pool_entries.items) |entry| {
            c.PQfinish(entry.conn);
        }
        self.pool_entries.clearRetainingCapacity();
    }

    /// H6 (boot hardening): a lightweight liveness ping for the DB —
    /// `SELECT 1` on a pooled connection. Returns an error if the query
    /// fails (DB unreachable, conn dead, pool exhausted). The gateway
    /// maintenance thread runs this on a steady-state cadence and maps the
    /// result to health.markComponentOk/Error("db", …); /ready aggregates
    /// the registry and sheds a pod whose Postgres went away post-boot.
    /// Deliberately trivial (no schema, no params) so it measures only
    /// "can we round-trip a query to Postgres right now".
    pub fn pingHealth(self: *Self) !void {
        const result = try self.exec("SELECT 1");
        c.PQclear(result);
    }

    /// H4 (boot hardening): a process-wide constant key for the migration
    /// advisory lock. Stable, arbitrary 64-bit value (chosen once; must NOT
    /// change across releases or two versions would not serialize against
    /// each other). pg_advisory_lock keys are per-database, so all tenant
    /// schemas in one DB share this single migration lock — exactly the
    /// intent: serialize EVERY migrate() across every pod for a given DB.
    pub const MIGRATION_ADVISORY_LOCK_KEY: i64 = 0x7A41_4B49_4D49_4752; // "zAKIMIGR" mnemonic

    /// H4: total bounded wait for the migration lock before giving up. A pod
    /// that cannot acquire the lock within this window FAILS its migrate()
    /// (error.MigrationLockTimeout) rather than proceeding unlocked — we
    /// never run migrations without the lock. Transaction-scoped advisory
    /// locks auto-release when the holder's txn ends or its connection drops
    /// (pod crash), so a stuck lock self-heals; this bound just prevents an
    /// unbounded boot hang.
    const MIGRATION_LOCK_MAX_WAIT_MS: i64 = 60_000;
    const MIGRATION_LOCK_RETRY_SLEEP_MS: u64 = 100;

    /// pgBouncer-transaction fix: process-wide serialization of migrate()
    /// across ALL Manager instances in this process. Each tenant runtime scope
    /// builds its OWN Manager with its own pool (see tenant_runtime_scope.zig),
    /// so a per-Manager lock would not serialize them — this container-level
    /// (static) mutex does. It prevents an intra-pod thundering herd of
    /// advisory-lock probes against pgBouncer's small backend budget; the
    /// cross-pod serialization is the advisory xact lock (acquireMigrationXactLock).
    var g_migration_mutex: std.Thread.Mutex = .{};

    /// TEST-ONLY since the pgBouncer-transaction fix: production migration
    /// locking uses `acquireMigrationXactLock`. This SESSION-scoped probe is NOT
    /// pooler-safe (the lock does not survive the backend returning to a
    /// transaction-mode pool), so tests using it must run against DIRECT PG.
    /// Runs `SELECT pg_try_advisory_lock($key)` on a specific connection and
    /// returns whether the lock was granted. Non-blocking.
    fn tryAdvisoryLockOnConn(self: *Self, conn: *c.PGconn, key: i64) !bool {
        _ = self;
        var buf: [96]u8 = undefined;
        const q = try std.fmt.bufPrintZ(&buf, "SELECT pg_try_advisory_lock({d})", .{key});
        const result = c.PQexec(conn, q.ptr) orelse return error.ExecFailed;
        defer c.PQclear(result);
        if (c.PQresultStatus(result) != c.PGRES_TUPLES_OK) return error.ExecFailed;
        if (c.PQntuples(result) < 1) return error.ExecFailed;
        const val = c.PQgetvalue(result, 0, 0);
        // libpq renders bool as "t"/"f".
        return val[0] == 't';
    }

    /// TEST-ONLY since the pgBouncer-transaction fix (see tryAdvisoryLockOnConn):
    /// production migration locking auto-releases at COMMIT, never via a manual
    /// unlock. Best-effort `SELECT pg_advisory_unlock($key)` on a specific
    /// connection — best-effort because the lock also auto-releases on
    /// connection close; a failed unlock here is logged (test-gated) but must
    /// not mask the migration outcome.
    fn advisoryUnlockOnConn(self: *Self, conn: *c.PGconn, key: i64) void {
        var buf: [96]u8 = undefined;
        const q = std.fmt.bufPrintZ(&buf, "SELECT pg_advisory_unlock({d})", .{key}) catch return;
        const result = c.PQexec(conn, q.ptr) orelse {
            if (!builtin.is_test) log.warn("migration advisory unlock failed to execute", .{});
            return;
        };
        c.PQclear(result);
        _ = self;
    }

    /// pgBouncer-transaction fix: take the migration advisory lock as a
    /// TRANSACTION-scoped lock on the pinned `txn` connection, retrying with a
    /// bounded total wait. The NON-blocking pg_try_advisory_xact_lock is used so
    /// the per-connection lock_timeout (2s) never aborts the wait — the bounded
    /// retry loop owns the timeout. The lock is held until the caller
    /// COMMITs/ROLLBACKs the txn (auto-release: NO manual pg_advisory_unlock,
    /// which is what made the unlock land on a different pooled backend and emit
    /// "you don't own a lock of type ExclusiveLock"). On timeout returns
    /// error.MigrationLockTimeout WITHOUT migrating — we never migrate unlocked.
    fn acquireMigrationXactLock(self: *Self, txn: *TxnLease) !void {
        _ = self;
        var buf: [96]u8 = undefined;
        const q = try std.fmt.bufPrint(&buf, "SELECT pg_try_advisory_xact_lock({d})", .{MIGRATION_ADVISORY_LOCK_KEY});
        const start_ms = std.time.milliTimestamp();
        while (true) {
            const result = try txn.exec(q);
            const granted = c.PQntuples(result) >= 1 and c.PQgetvalue(result, 0, 0)[0] == 't';
            c.PQclear(result);
            if (granted) return;

            const elapsed_ms = std.time.milliTimestamp() - start_ms;
            if (elapsed_ms >= MIGRATION_LOCK_MAX_WAIT_MS) {
                if (!builtin.is_test) log.err(
                    "migration advisory lock not acquired within {d}ms — another pod may be mid-migration; refusing to migrate unlocked",
                    .{MIGRATION_LOCK_MAX_WAIT_MS},
                );
                return error.MigrationLockTimeout;
            }
            std.Thread.sleep(MIGRATION_LOCK_RETRY_SLEEP_MS * std.time.ns_per_ms);
        }
    }

    /// Apply the embedded schema migrations for this tenant. Called internally
    /// by `init`; also `pub` so cross-module PG tests (subagent_results
    /// recovery in subagent.zig) can re-create the schema after a DROP in
    /// setup/teardown under the postgres engine.
    ///
    /// Serialization (boot hardening, pgBouncer-transaction safe):
    ///   1. A process-global mutex serializes migrate() across the many
    ///      per-tenant Manager instances in THIS pod (no intra-pod herd).
    ///   2. The migration advisory lock is held as a pg_try_advisory_xact_lock
    ///      inside an OPEN transaction on one pinned connection. The open txn
    ///      pins that backend through pgBouncer (pool_mode=transaction), so the
    ///      lock survives the whole migration; COMMIT auto-releases it. The
    ///      former session-level pg_advisory_lock did NOT survive: pgBouncer
    ///      returned the backend to the pool after the bare acquire statement,
    ///      so it never serialized across pods and the manual unlock landed on a
    ///      different backend ("you don't own a lock of type ExclusiveLock").
    /// Without this, a rolling-update / HPA scale-out runs two pods' migrate()
    /// concurrently — deadlock risk today, outright corruption once a
    /// non-idempotent 0002+ migration ships.
    pub fn migrate(self: *Self) !void {
        // (1) Serialize migrate() within this process (across Manager instances).
        g_migration_mutex.lock();
        defer g_migration_mutex.unlock();

        // Structural invariant: the lock txn pins ONE connection for the whole
        // migration, while migrateLocked() needs at least one MORE (per-statement
        // DDL via execMigrateStatement, plus a nested beginTransaction in
        // migrations.run() for unapplied 0002+). A single-connection pool would
        // self-starve, so require >= 2 and fail fast with a clear message
        // instead of a confusing ConnectionPoolBusy stall. (Prod=8, staging=4.)
        if (self.pool_max < 2) {
            if (!builtin.is_test) log.err(
                "migrate requires pool_max >= 2 (1 conn pins the advisory lock, DDL runs on another); got {d}",
                .{self.pool_max},
            );
            return error.MigrationPoolTooSmall;
        }

        // (2) Hold the migration advisory lock as a transaction-scoped lock on a
        // single pinned connection. beginTransaction() runs BEGIN and keeps the
        // conn — the open txn pins the backend through pgBouncer.
        var txn = try self.beginTransaction();
        defer txn.deinit(); // rollback + release if we don't reach commit()

        // The lock conn is idle-in-transaction while migrateLocked() runs DDL on
        // OTHER pooled conns — make sure it is never reaped mid-migration. We
        // disable ONLY the idle-in-transaction reaper here; statement_timeout
        // stays in force (it bounds each individual DDL statement, not the idle
        // wait), so do NOT "tidy up" by also resetting statement_timeout.
        {
            const r = try txn.exec("SET LOCAL idle_in_transaction_session_timeout = 0");
            c.PQclear(r);
        }

        try self.acquireMigrationXactLock(&txn);
        try self.migrateLocked();
        try txn.commit(); // releases the advisory xact lock + returns the conn
    }

    /// H4: the actual migration body, run while the caller holds the
    /// migration advisory lock (see `migrate`). Never call directly except
    /// from `migrate` — it assumes the lock is held.
    fn migrateLocked(self: *Self) !void {
        const statements = [_][]const u8{
            "CREATE SCHEMA IF NOT EXISTS {schema}",
            "CREATE EXTENSION IF NOT EXISTS pgcrypto",
            "CREATE EXTENSION IF NOT EXISTS vector",
            \\CREATE TABLE IF NOT EXISTS {schema}.users (
            \\    user_id BIGINT PRIMARY KEY,
            \\    workspace_path TEXT NOT NULL,
            \\    agent_name TEXT,
            \\    onboarding_completed BOOLEAN NOT NULL DEFAULT FALSE,
            \\    onboarding_completed_at TIMESTAMPTZ,
            \\    status TEXT NOT NULL DEFAULT 'active',
            \\    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
            \\    updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
            \\)
            ,
            "ALTER TABLE {schema}.users ADD CONSTRAINT users_user_id_fkey FOREIGN KEY (user_id) REFERENCES public.zaki_users(id) ON DELETE CASCADE",
            \\CREATE TABLE IF NOT EXISTS {schema}.user_config (
            \\    user_id BIGINT PRIMARY KEY REFERENCES {schema}.users(user_id) ON DELETE CASCADE,
            \\    config JSONB NOT NULL DEFAULT '{}'::jsonb,
            \\    version INT NOT NULL DEFAULT 1,
            \\    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
            \\    updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
            \\)
            ,
            \\CREATE TABLE IF NOT EXISTS {schema}.user_secrets (
            \\    user_id BIGINT NOT NULL REFERENCES {schema}.users(user_id) ON DELETE CASCADE,
            \\    key TEXT NOT NULL,
            \\    ciphertext BYTEA NOT NULL,
            \\    nonce BYTEA NOT NULL,
            \\    aad TEXT NOT NULL,
            \\    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
            \\    updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
            \\    PRIMARY KEY (user_id, key)
            \\)
            ,
            // D8 (S2.16) — audit trail for every secret mutation. One
            // row per attempt (success or failure). Operators can
            // see "who did what when" without ever seeing plaintext.
            \\CREATE TABLE IF NOT EXISTS {schema}.secret_mutations (
            \\    id TEXT PRIMARY KEY DEFAULT encode(gen_random_bytes(16), 'hex'),
            \\    user_id BIGINT NOT NULL REFERENCES {schema}.users(user_id) ON DELETE CASCADE,
            \\    key TEXT NOT NULL,
            \\    action TEXT NOT NULL,
            \\    actor TEXT,
            \\    outcome TEXT NOT NULL,
            \\    detail TEXT,
            \\    at TIMESTAMPTZ NOT NULL DEFAULT NOW()
            \\)
            ,
            "CREATE INDEX IF NOT EXISTS idx_secret_mutations_user_at ON {schema}.secret_mutations(user_id, at DESC)",
            \\CREATE TABLE IF NOT EXISTS {schema}.sessions (
            \\    id TEXT PRIMARY KEY,
            \\    user_id BIGINT NOT NULL REFERENCES {schema}.users(user_id) ON DELETE CASCADE,
            \\    session_key TEXT NOT NULL UNIQUE,
            \\    kind TEXT NOT NULL,
            \\    title TEXT,
            \\    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
            \\    updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
            \\)
            ,
            \\CREATE TABLE IF NOT EXISTS {schema}.messages (
            \\    id TEXT PRIMARY KEY DEFAULT encode(gen_random_bytes(16), 'hex'),
            \\    session_id TEXT NOT NULL REFERENCES {schema}.sessions(id) ON DELETE CASCADE,
            \\    user_id BIGINT REFERENCES {schema}.users(user_id) ON DELETE CASCADE,
            \\    role TEXT NOT NULL,
            \\    channel TEXT,
            \\    account_id TEXT,
            \\    chat_id TEXT,
            \\    source TEXT NOT NULL DEFAULT 'app',
            \\    content TEXT NOT NULL,
            \\    tool_name TEXT,
            \\    tool_call JSONB,
            \\    tool_result JSONB,
            \\    request_id TEXT,
            \\    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
            \\)
            ,
            "CREATE INDEX IF NOT EXISTS idx_messages_user_created ON {schema}.messages(user_id, created_at DESC)",
            "CREATE INDEX IF NOT EXISTS idx_messages_session_created ON {schema}.messages(session_id, created_at ASC)",
            \\CREATE TABLE IF NOT EXISTS {schema}.completion_events (
            \\    id TEXT PRIMARY KEY,
            \\    user_id BIGINT NOT NULL REFERENCES {schema}.users(user_id) ON DELETE CASCADE,
            \\    session_id TEXT NOT NULL REFERENCES {schema}.sessions(id) ON DELETE CASCADE,
            \\    channel TEXT,
            \\    account_id TEXT,
            \\    chat_id TEXT,
            \\    content TEXT NOT NULL,
            \\    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
            \\)
            ,
            "CREATE INDEX IF NOT EXISTS idx_completion_events_user_session_created ON {schema}.completion_events(user_id, session_id, created_at ASC, id ASC)",
            \\CREATE TABLE IF NOT EXISTS {schema}.memories (
            \\    id TEXT PRIMARY KEY,
            \\    user_id BIGINT NOT NULL REFERENCES {schema}.users(user_id) ON DELETE CASCADE,
            \\    session_id TEXT REFERENCES {schema}.sessions(id) ON DELETE SET NULL,
            \\    key TEXT NOT NULL UNIQUE,
            \\    content TEXT NOT NULL,
            \\    content_hash TEXT,
            \\    memory_type TEXT NOT NULL DEFAULT 'core',
            \\    embedding VECTOR,
            \\    metadata JSONB NOT NULL DEFAULT '{}'::jsonb,
            \\    importance_score DOUBLE PRECISION DEFAULT 0.5,
            \\    confidence_score DOUBLE PRECISION DEFAULT 0.8,
            \\    access_count INT DEFAULT 0,
            \\    last_accessed_at TIMESTAMPTZ,
            \\    user_verified BOOLEAN DEFAULT FALSE,
            \\    source_channel TEXT,
            \\    source_message_id TEXT,
            \\    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
            \\    updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
            \\)
            ,
            "CREATE INDEX IF NOT EXISTS idx_memories_user ON {schema}.memories(user_id)",
            "CREATE INDEX IF NOT EXISTS idx_memories_hash ON {schema}.memories(user_id, content_hash)",
            "ALTER TABLE {schema}.memories DROP CONSTRAINT IF EXISTS memories_key_key",
            "CREATE UNIQUE INDEX IF NOT EXISTS idx_memories_user_key ON {schema}.memories(user_id, key)",
            // V1.5 day-2 — Graphiti bi-temporal model. `valid_to` is the
            // unix-epoch second when this memory entry stops being valid;
            // `NULL` means always-valid. V1.5 always writes NULL; V1.6
            // correction classifier + MemoryViewer-correction populate it.
            // Retrieval filters use `(valid_to IS NULL OR valid_to >
            // EXTRACT(EPOCH FROM NOW())::bigint)` so superseded entries
            // never reach the agent. Partial index — most rows stay NULL.
            "ALTER TABLE {schema}.memories ADD COLUMN IF NOT EXISTS valid_to BIGINT",
            "CREATE INDEX IF NOT EXISTS idx_memories_valid_to ON {schema}.memories(valid_to) WHERE valid_to IS NOT NULL",

            // ── V1.6 schema (commit 2 of V1.6 work order) ────────────────
            //
            // All ALTERs are `ADD COLUMN IF NOT EXISTS` — instant metadata-
            // only on populated tables (no row rewrite). Indexes are partial
            // where appropriate to keep cost low on rows that won't have
            // the field populated until extraction backfills them.
            //
            // Reference: `docs/v1.6-v1.7-spec.md` §4.1
            //   + `docs/v1.5.5-compaction-fidelity-final.md` (substrate gates)
            //   + `nullalis_audit.md` §E.1 (gap mapping)

            // V1.6 atomic-fact extraction (Mem0/Graphiti typed-edge schema)
            "ALTER TABLE {schema}.memories ADD COLUMN IF NOT EXISTS subject TEXT",
            "ALTER TABLE {schema}.memories ADD COLUMN IF NOT EXISTS predicate TEXT",
            "ALTER TABLE {schema}.memories ADD COLUMN IF NOT EXISTS object_key TEXT",
            "ALTER TABLE {schema}.memories ADD COLUMN IF NOT EXISTS link_type TEXT",
            // attribution: 'agent_tool' | 'extraction_classifier' | 'compose'
            //   per spec D4 — distinguishes write-source for cosine-dedup
            "ALTER TABLE {schema}.memories ADD COLUMN IF NOT EXISTS attribution TEXT",
            // attributed_to: 'user' | 'assistant' | 'assistant_offer'
            //   per Mem0 V3 — who said the thing the fact reflects
            "ALTER TABLE {schema}.memories ADD COLUMN IF NOT EXISTS attributed_to TEXT",

            // V1.6 Graphiti six-field bi-temporal — extends V1.5's lone valid_to
            //   created_at exists already (TIMESTAMPTZ system time)
            //   valid_to exists already (event-time end)
            //   valid_at = event time when fact became true
            //   invalid_at = event time when fact stopped (synonym for valid_to but
            //     kept distinct in case future refinements need both)
            //   expired_at = system time of close-out (when the row was
            //     marked superseded; differs from invalid_at when correcting
            //     historical facts)
            //   reference_time = originating episode's valid_at
            //   episodes[] = source episode/session UUIDs (multi-source attribution)
            "ALTER TABLE {schema}.memories ADD COLUMN IF NOT EXISTS valid_at BIGINT",
            "ALTER TABLE {schema}.memories ADD COLUMN IF NOT EXISTS invalid_at BIGINT",
            "ALTER TABLE {schema}.memories ADD COLUMN IF NOT EXISTS expired_at BIGINT",
            "ALTER TABLE {schema}.memories ADD COLUMN IF NOT EXISTS reference_time BIGINT",
            "ALTER TABLE {schema}.memories ADD COLUMN IF NOT EXISTS episodes TEXT[] DEFAULT '{}'",

            // V1.6 retrieval + supersession (Mem0 + supermemory parity)
            //   lemmatized = pre-processed BM25 surface (V1.6 commit 3 wires)
            //   is_latest = false on superseded rows (supermemory parity)
            //   parent_memory_id = supermemory-style version chain
            "ALTER TABLE {schema}.memories ADD COLUMN IF NOT EXISTS lemmatized TEXT",
            "ALTER TABLE {schema}.memories ADD COLUMN IF NOT EXISTS is_latest BOOLEAN DEFAULT TRUE",
            "ALTER TABLE {schema}.memories ADD COLUMN IF NOT EXISTS parent_memory_id TEXT",

            // V1.6 source attribution (M4 from spec §4.10) — answer "where
            // did ZAKI learn this?" on the brain page. existing schema has
            // source_channel + source_message_id; V1.6 adds session_id +
            // snippet for /brain/memory/{key} drilldown UX.
            "ALTER TABLE {schema}.memories ADD COLUMN IF NOT EXISTS source_session_id TEXT",
            "ALTER TABLE {schema}.memories ADD COLUMN IF NOT EXISTS source_snippet TEXT",

            // V1.6 indexes — partial where the field is sparsely populated
            "CREATE INDEX IF NOT EXISTS idx_memories_subject ON {schema}.memories(user_id, subject) WHERE subject IS NOT NULL",
            // V1.6 commit 6 review (W1 fix): expression index on the JSONB
            // path because findRelatedExtractedMemories queries
            // `metadata->>'subject'` (not the typed `subject` column —
            // upsertMemoryWithMetadata writes JSONB only). Without this,
            // the contradiction-judge candidate fetch falls back to a
            // user-scoped seq-scan + sort. Cheap to maintain (only fires
            // when subject is in the JSONB).
            "CREATE INDEX IF NOT EXISTS idx_memories_metadata_subject ON {schema}.memories(user_id, (metadata->>'subject')) WHERE metadata ? 'subject'",
            "CREATE INDEX IF NOT EXISTS idx_memories_object_key ON {schema}.memories(user_id, object_key) WHERE object_key IS NOT NULL",
            "CREATE INDEX IF NOT EXISTS idx_memories_parent ON {schema}.memories(user_id, parent_memory_id) WHERE parent_memory_id IS NOT NULL",
            "CREATE INDEX IF NOT EXISTS idx_memories_is_latest ON {schema}.memories(user_id, is_latest) WHERE is_latest = TRUE",
            // GIN over lemmatized field — V1.6 commit 3 will populate the
            // column + switch BM25 surface to use this index.
            "CREATE INDEX IF NOT EXISTS idx_memories_lemmatized ON {schema}.memories USING gin (to_tsvector('simple', lemmatized))",
            // V1.6 commit 3 lazy backfill — populate `lemmatized` for any
            // pre-V1.6 row that doesn't have it yet. Uses Postgres's
            // Unicode-aware `lower()` (multilingual-safe). New writes go
            // through the richer Zig `lemmatizeForBm25` path with stopword
            // removal; backfill is intentionally a strict subset (basic
            // lowercasing) to avoid running heuristics on rows we didn't
            // capture at write time.
            "UPDATE {schema}.memories SET lemmatized = lower(content) WHERE lemmatized IS NULL",

            // V1.7a-5 (spec seam 3) — link_type column backfill from metadata.
            //
            // The link_type TEXT column was added in V1.6 cmt5 schema migration
            // (line 1062) but never populated by writers until V1.7a-5. Existing
            // memories with metadata containing "link_type" need a one-shot
            // backfill so /brain/memory/{key} drilldown surfaces consistent
            // values across pre/post-V1.7a-5 rows. Idempotent: WHERE
            // link_type IS NULL ensures re-running migrate() only touches
            // unbackfilled rows. Skips rows whose metadata never had
            // link_type at all (those stay NULL — the FE renders them
            // without the category badge, same as legacy non-extracted memories).
            "UPDATE {schema}.memories SET link_type = (metadata->>'link_type') " ++
                "WHERE link_type IS NULL AND metadata IS NOT NULL " ++
                "AND metadata ? 'link_type'",

            // ── V1.7 schema ────────────────────────────────────────────────
            //
            // seen_in_session_count: incremented each time the same key is
            // written from a DIFFERENT session. When count >= 2 the fact
            // has survived two independent sessions → eligible for Tier-3
            // (core) promotion. Default 1 so existing rows don't immediately
            // promote on boot. ADD COLUMN IF NOT EXISTS → safe on old DBs.
            "ALTER TABLE {schema}.memories ADD COLUMN IF NOT EXISTS seen_in_session_count INTEGER NOT NULL DEFAULT 1",

            // V1.6 entity vector plane (separate from memory_vectors per
            // spec §D7 — entity-name embeddings live at different
            // granularity than memory-content embeddings; mixing them
            // cross-contaminates cosine ANN). Used by V1.6 commit 7
            // entity coreference (cosine ≥ 0.95 threshold per Mem0).
            // VECTOR(1024) matches the production embedding model
            // intfloat/multilingual-e5-large-instruct (config.json:90).
            // pgvector requires a dimension on columns indexed by ivfflat;
            // changing model dimensions in the future requires a migration.
            \\CREATE TABLE IF NOT EXISTS {schema}.memory_entities (
            \\    id TEXT PRIMARY KEY,
            \\    user_id BIGINT NOT NULL REFERENCES {schema}.users(user_id) ON DELETE CASCADE,
            \\    name TEXT NOT NULL,
            \\    name_lower TEXT NOT NULL,
            \\    entity_type TEXT NOT NULL DEFAULT 'PROPER',
            \\    name_embedding VECTOR(1024),
            \\    linked_memory_ids TEXT[] DEFAULT '{}',
            \\    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
            \\    updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
            \\    UNIQUE (user_id, name_lower)
            \\)
            ,
            "CREATE INDEX IF NOT EXISTS idx_entities_user ON {schema}.memory_entities(user_id)",
            // ivfflat lists tuned for 5-50K rows per user; revisit if
            // production sees larger entity counts (uncommon — entities
            // are typically nouns/proper-names, much sparser than memories)
            "CREATE INDEX IF NOT EXISTS idx_entities_vec ON {schema}.memory_entities USING ivfflat (name_embedding vector_cosine_ops) WITH (lists = 100)",

            // V1.6 commit 7 — materialized typed-edge graph (Gap 1 from
            // memory pipeline handoff 2026-05-02).
            //
            // Until now the (subject, predicate, object) triples lived ONLY
            // in JSONB metadata, requiring an O(N) seq-scan in
            // gateway.buildBrainTypedEdges to reconstruct the graph on each
            // /brain/graph request. Real edges in a real table:
            //   - speed up brain rendering (index lookups vs JSONB extraction)
            //   - unblock graph-aware retrieval (neighbor traversal)
            //   - feed real edge_count into importance scoring (was half-blind
            //     when called outside the brain-graph context)
            //
            // Schema follows the same bi-temporal model as memories:
            //   valid_to / invalid_at / expired_at — set when the source or
            //     target memory is closed-out via setMemoryInvalidation
            //     (cascading from V1.6 cmt6).
            //   is_latest — supermemory parity; UI filters default to TRUE.
            //   confidence — pulled from extraction LLM's per-fact confidence.
            //   attribution — 'extraction_classifier' today; future write
            //     paths (agent_tool, compose) tag their origin.
            //
            // UNIQUE (user_id, source_key, predicate, target_key) WHERE is_latest
            //   ensures the same triple cannot accumulate duplicate edges
            //   (defends against Pass C re-extracting the same fact across
            //   sessions — pairs with V1.6 5b.3 MD5 dedup at the memory level).
            \\CREATE TABLE IF NOT EXISTS {schema}.memory_edges (
            \\    id BIGSERIAL PRIMARY KEY,
            \\    user_id BIGINT NOT NULL REFERENCES {schema}.users(user_id) ON DELETE CASCADE,
            \\    source_key TEXT NOT NULL,
            \\    target_key TEXT NOT NULL,
            \\    predicate TEXT NOT NULL,
            \\    attribution TEXT,
            \\    confidence FLOAT,
            \\    weight FLOAT NOT NULL DEFAULT 1.0,
            \\    valid_from BIGINT,
            \\    valid_to BIGINT,
            \\    invalid_at BIGINT,
            \\    expired_at BIGINT,
            \\    is_latest BOOLEAN NOT NULL DEFAULT TRUE,
            \\    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
            \\)
            ,
            "CREATE INDEX IF NOT EXISTS idx_edges_source ON {schema}.memory_edges(user_id, source_key) WHERE is_latest",
            "CREATE INDEX IF NOT EXISTS idx_edges_target ON {schema}.memory_edges(user_id, target_key) WHERE is_latest",
            "CREATE UNIQUE INDEX IF NOT EXISTS idx_edges_triple ON {schema}.memory_edges(user_id, source_key, predicate, target_key) WHERE is_latest",
            // Validity index — drives the cascade-on-close from
            // setMemoryInvalidation. Partial because invalid edges are
            // append-only / archived, not actively queried.
            "CREATE INDEX IF NOT EXISTS idx_edges_validity ON {schema}.memory_edges(user_id, valid_to) WHERE valid_to IS NOT NULL",

            // V1.14 — edge richness columns. Three additive columns,
            // each optional (NULL by default for backwards-compat with
            // existing rows; new writes populate when extractor emits
            // the data).
            //
            // 1. `fact` (TEXT) — the FULL SENTENCE describing the
            //    relationship, not just the predicate code. e.g. "Alfred
            //    works at NovaNuggets as the founder" rather than just
            //    the predicate "WORKS_AT". Inspired by Graphiti's
            //    EntityEdge.fact field. Brain page rendering becomes
            //    scannable; agent recall returns prose instead of triple
            //    soup. Populated by extraction LLM (the "text" field of
            //    ExtractedMemory was already produced; we just plumb it
            //    to the edge row).
            //
            // 2. `temporal_anchor_unix` (BIGINT) — when the FACT became
            //    true in user-time (extracted from episode content),
            //    distinct from `valid_from` which is write-time. When
            //    user says "I joined Google in 2020", we capture both:
            //    `valid_from` = today (we wrote it now), and
            //    `temporal_anchor_unix` = 2020-01-01 (when fact began).
            //    Enables "what did I know on April 1?" point-in-time
            //    queries that today blur together.
            //
            // 3. `episodes` (TEXT[]) — array of memory keys that
            //    contributed to this edge. First-class provenance chain
            //    (today provenance lives in `attribution` + memory_events
            //    audit but is hard to traverse). When user asks "why do
            //    you think Alfred works at Google?", we can list the
            //    source messages. Defaults to empty array; new writes
            //    append the source memory key on insert AND on
            //    ON-CONFLICT-bump (so re-mentions accumulate provenance
            //    just like weight accumulates evidence).
            "ALTER TABLE {schema}.memory_edges ADD COLUMN IF NOT EXISTS fact TEXT",
            "ALTER TABLE {schema}.memory_edges ADD COLUMN IF NOT EXISTS temporal_anchor_unix BIGINT",
            "ALTER TABLE {schema}.memory_edges ADD COLUMN IF NOT EXISTS episodes TEXT[] DEFAULT '{}'",
            "ALTER TABLE {schema}.memory_edges ADD COLUMN IF NOT EXISTS extraction_pass TEXT",
            "ALTER TABLE {schema}.memory_edges ADD COLUMN IF NOT EXISTS session_boundary_id BIGINT",

            // V1.6 commit 16 — one-shot backfill: populate memory_edges from
            // existing JSONB triples on legacy memories. Idempotent via the
            // partial UNIQUE INDEX on (user_id, source_key, predicate,
            // target_key) WHERE is_latest — re-running migrate is safe.
            //
            // target_key shape mirrors extraction_persist.deriveEntityKey:
            //   'entity_' + first 16 hex chars of sha256(lower(object))
            // (pgcrypto's digest() returns bytea; encode → hex → substring.
            //  pgcrypto is installed by the cmt0 CREATE EXTENSION above.)
            //
            // Skips closed-out rows (valid_to in past) so cascade semantics
            // stay consistent with cmt6/cmt7 — closed-out memories can't
            // resurrect edges via backfill.
            //
            // Confidence: defaults to 1.0 when metadata.confidence absent
            // (legacy V1.5 rows). Attribution: defaults to
            // 'extraction_classifier' since pre-cmt7 extraction was the
            // only writer of subject/predicate/object metadata.
            //
            // Cost: O(N) over rows with metadata.subject populated. On
            // Nova's user_id=1 dev DB this is a small number; production
            // scale will run during a maintenance window.
            // V1.7a-4 (closes V1.6 ship-review WR-02): both Zig sites
            // (extraction_persist.deriveEntityKey + commands.deriveSessionEndEntityKey)
            // now route through extraction_persist.lowerForEntityKey, a
            // Unicode-aware helper covering ASCII A-Z + Latin-1 Supplement
            // + Cyrillic + Greek uppercase → lowercase. PG's `lower(...)`
            // matches this in standard UTF-8 locales (en_US.UTF-8 etc. —
            // the production deployment target) for those ranges. C-locale
            // PG would lowercase ASCII ONLY and diverge for everything else,
            // so production MUST run a UTF-8 locale (`SHOW lc_collate`
            // should not be 'C' or 'POSIX').
            //
            // **Migration note:** the cmt16 backfill is INSERT...ON CONFLICT
            // DO NOTHING. It does NOT rewrite already-existing memory_edges
            // rows. So pre-V1.7a-4 tenants with non-ASCII uppercase entity
            // names retain their old ASCII-only-keyed rows. The shift to
            // the new Unicode-folded key only happens when a NEW write for
            // the same surface form arrives — extraction_persist creates a
            // new entity_<unicode_hash> row, leaving the old ASCII row
            // orphaned. Manual cleanup recommended for tenants with
            // high-volume non-ASCII entity history (a one-shot UPDATE that
            // recomputes target_key for affected rows). Rare in practice —
            // extraction prompt emits canonical lowercase by design.
            "INSERT INTO {schema}.memory_edges (user_id, source_key, target_key, predicate, attribution, confidence, valid_from) " ++
                "SELECT user_id, key AS source_key, " ++
                "'entity_' || substring(encode(digest(lower(metadata->>'object'), 'sha256'), 'hex') from 1 for 16) AS target_key, " ++
                "metadata->>'predicate' AS predicate, " ++
                "COALESCE(metadata->>'attribution', 'extraction_classifier') AS attribution, " ++
                "COALESCE((metadata->>'confidence')::float, 1.0) AS confidence, " ++
                "EXTRACT(EPOCH FROM created_at)::bigint AS valid_from " ++
                "FROM {schema}.memories " ++
                "WHERE metadata IS NOT NULL " ++
                "AND metadata ? 'subject' " ++
                "AND metadata ? 'predicate' " ++
                "AND metadata ? 'object' " ++
                "AND length(metadata->>'object') > 0 " ++
                "AND length(metadata->>'predicate') > 0 " ++
                "AND (valid_to IS NULL OR valid_to > EXTRACT(EPOCH FROM NOW())::bigint) " ++
                "ON CONFLICT (user_id, source_key, predicate, target_key) WHERE is_latest DO NOTHING",
            \\CREATE TABLE IF NOT EXISTS {schema}.memory_events (
            \\    id TEXT PRIMARY KEY,
            \\    user_id BIGINT NOT NULL REFERENCES {schema}.users(user_id) ON DELETE CASCADE,
            \\    memory_id TEXT,
            \\    event_type TEXT NOT NULL,
            \\    payload JSONB NOT NULL DEFAULT '{}'::jsonb,
            \\    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
            \\)
            ,

            // V1.13 Day 1 — Working Memory (Layer 0).
            //
            // 15 hot slots per (user_id, session_id). Persists across turns
            // within a session; flushes to canonical memory at session end.
            // Renders into the volatile system prompt block at top of every
            // prompt — agent always has open loops, active goals, recent
            // emotional context, identity facts in mind without rebuilding
            // from prose recall every turn.
            //
            // slot_id is stable position 0..14 — eviction reuses slot_ids
            // (lowest composite-priority evicted on overflow); slot 0 and 1
            // reserved for pinned identity facts.
            //
            // slot_type: open_loop | active_goal | emotional | identity |
            //            relationship | decision | recent_entity |
            //            skill_state | temporal | open_question
            //
            // importance: 0..1 composite (recency × explicit_signal × retrieval_count).
            // pinned: never evicted regardless of priority (identity facts).
            // source_key: optional ref to memories table key that birthed
            //   this slot — lets the slot promote-back a related memory
            //   into recall context if the slot fires.
            //
            // V1.13 architectural rule: this is the ONLY working-memory
            // surface. No parallel session-scoped slot tables. Future
            // procedural / dream extensions write through the same row
            // shape with their own slot_type values.
            \\CREATE TABLE IF NOT EXISTS {schema}.working_memory (
            \\    user_id BIGINT NOT NULL REFERENCES {schema}.users(user_id) ON DELETE CASCADE,
            \\    session_id TEXT NOT NULL,
            \\    slot_id INT NOT NULL,
            \\    slot_type TEXT NOT NULL,
            \\    content TEXT NOT NULL,
            \\    source_key TEXT,
            \\    importance FLOAT NOT NULL DEFAULT 0.5,
            \\    pinned BOOLEAN NOT NULL DEFAULT FALSE,
            \\    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
            \\    last_touched_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
            \\    PRIMARY KEY (user_id, session_id, slot_id)
            \\)
            ,
            "CREATE INDEX IF NOT EXISTS idx_wm_session ON {schema}.working_memory(user_id, session_id, last_touched_at DESC)",
            // HI-01 fix (REVIEW V1.13 Day 1): dropped idx_wm_priority.
            // The prior partial index on (user_id, session_id, importance
            // DESC) WHERE NOT pinned was dead — listWorkingMemorySlots
            // ORDERs BY the composite expression `importance × exp(-age/3600)`
            // (not raw importance), so PG's planner couldn't use the
            // index. idx_wm_session covers the (user_id, session_id)
            // WHERE clause; the ORDER BY is a small in-memory sort over
            // ≤15 rows per session — no index needed.

            // V1.13 Day 2 — Extraction queue (HI-01 real fix).
            //
            // Entity_pipeline + session_end consolidation are async background
            // work — moving them off the agent turn loop into the heartbeat
            // worker lane (daemon.zig::heartbeatThread). The queue table
            // brokers between enqueue (per-turn-end / session-end fast path)
            // and process (heartbeat tick).
            //
            // job_type:  'wiki_link' | 'session_end' | 'backfill'
            // status:    'pending' | 'running' | 'done' | 'failed'
            // payload:   JSONB — {turn_text: ..., recent_entries: [...], ...}
            //
            // Worker uses SELECT FOR UPDATE SKIP LOCKED to claim jobs
            // concurrency-safe across multiple heartbeat instances (per-cell
            // pod isolation makes this rare today, but the pattern is
            // defense-in-depth for shared deployments).
            //
            // Retries: failed jobs flip to 'failed' after 3 attempts; the
            // application layer (extraction_queue.zig) decides retry policy.
            // For wiki_link / session_end, terminal failure is acceptable —
            // canonical conversation_messages is the source of truth and
            // the next pass will re-extract on idle eviction.
            \\CREATE TABLE IF NOT EXISTS {schema}.extraction_queue (
            \\    id BIGSERIAL PRIMARY KEY,
            \\    user_id BIGINT NOT NULL REFERENCES {schema}.users(user_id) ON DELETE CASCADE,
            \\    session_id TEXT NOT NULL,
            \\    job_type TEXT NOT NULL,
            \\    payload JSONB NOT NULL DEFAULT '{}'::jsonb,
            \\    enqueued_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
            \\    started_at TIMESTAMPTZ,
            \\    completed_at TIMESTAMPTZ,
            \\    status TEXT NOT NULL DEFAULT 'pending',
            \\    attempts INT NOT NULL DEFAULT 0,
            \\    last_error TEXT
            \\)
            ,
            "CREATE INDEX IF NOT EXISTS idx_xq_pending ON {schema}.extraction_queue(user_id, enqueued_at) WHERE status = 'pending'",
            "CREATE INDEX IF NOT EXISTS idx_xq_status ON {schema}.extraction_queue(status, enqueued_at)",

            // V1.13 Day 4 — Procedural memory (Layer 6).
            //
            // Skills today are static .md files in the workspace. Every
            // invocation reads from scratch — no learning from practice.
            // skill_executions captures the trace of each skill run so
            // future invocations can recall: what was assumed, what
            // worked, what the user pushed back on, what to do
            // differently next time.
            //
            // Capture is auto: turns with ≥3 tool calls that look like
            // a skill execution get traced. Recall happens at
            // skill-tool invocation time — last 3 traces of the same
            // skill_name for this user are injected into the prompt.
            //
            // Schema notes:
            //   skill_name: free-form string (e.g. "content-strategy");
            //              eventually constrained to skill_registry.
            //   task_summary: 1-line description from the user's turn.
            //   steps_executed: JSONB array of {step, tools_used,
            //                  output_excerpt, success}.
            //   assumptions_made: JSONB array of strings.
            //   user_feedback: derived heuristically from next turn
            //                 (positive if user continues, neutral
            //                 if not, negative on explicit pushback).
            //   outcome_quality: 0..1, agent self-assessed at capture
            //                   time, refined by feedback signal.
            \\CREATE TABLE IF NOT EXISTS {schema}.skill_executions (
            \\    id BIGSERIAL PRIMARY KEY,
            \\    user_id BIGINT NOT NULL REFERENCES {schema}.users(user_id) ON DELETE CASCADE,
            \\    session_id TEXT,
            \\    skill_name TEXT NOT NULL,
            \\    task_summary TEXT,
            \\    steps_executed JSONB NOT NULL DEFAULT '[]'::jsonb,
            \\    assumptions_made JSONB NOT NULL DEFAULT '[]'::jsonb,
            \\    user_feedback TEXT,
            \\    outcome_quality FLOAT,
            \\    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
            \\)
            ,
            "CREATE INDEX IF NOT EXISTS idx_skill_exec_user_time ON {schema}.skill_executions(user_id, skill_name, created_at DESC)",

            \\CREATE TABLE IF NOT EXISTS {schema}.channel_state (
            \\    user_id BIGINT PRIMARY KEY REFERENCES {schema}.users(user_id) ON DELETE CASCADE,
            \\    telegram JSONB NOT NULL DEFAULT '{}'::jsonb,
            \\    app JSONB NOT NULL DEFAULT '{}'::jsonb,
            \\    channels JSONB NOT NULL DEFAULT '{}'::jsonb,
            \\    updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
            \\)
            ,
            // S7 — back-fill the generic per-channel control-plane column
            // on deployments whose channel_state predates it. Telegram keeps
            // its dedicated `telegram` column; slack/discord/email/whatsapp
            // connection metadata lives under per-channel keys in `channels`.
            "ALTER TABLE {schema}.channel_state ADD COLUMN IF NOT EXISTS channels JSONB NOT NULL DEFAULT '{}'::jsonb",
            \\CREATE TABLE IF NOT EXISTS {schema}.telegram_updates (
            \\    user_id BIGINT NOT NULL REFERENCES {schema}.users(user_id) ON DELETE CASCADE,
            \\    update_id BIGINT NOT NULL,
            \\    received_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
            \\    PRIMARY KEY (user_id, update_id)
            \\)
            ,
            \\CREATE TABLE IF NOT EXISTS {schema}.channel_identity_bindings (
            \\    id TEXT PRIMARY KEY,
            \\    user_id BIGINT NOT NULL REFERENCES {schema}.users(user_id) ON DELETE CASCADE,
            \\    channel TEXT NOT NULL,
            \\    account_id TEXT NOT NULL,
            \\    principal_key TEXT NOT NULL,
            \\    scope_key TEXT NOT NULL,
            \\    thread_key TEXT,
            \\    thread_key_norm TEXT NOT NULL DEFAULT '',
            \\    peer_kind TEXT,
            \\    peer_id TEXT,
            \\    metadata JSONB NOT NULL DEFAULT '{}'::jsonb,
            \\    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
            \\    updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
            \\)
            ,
            "CREATE UNIQUE INDEX IF NOT EXISTS idx_channel_identity_unique ON {schema}.channel_identity_bindings(channel, account_id, principal_key, scope_key, thread_key_norm)",
            "CREATE INDEX IF NOT EXISTS idx_channel_identity_user_channel ON {schema}.channel_identity_bindings(user_id, channel)",
            "CREATE INDEX IF NOT EXISTS idx_channel_identity_lookup ON {schema}.channel_identity_bindings(channel, account_id, principal_key, scope_key, thread_key_norm)",
            // S7 — browser-extension device registry (user-facing
            // pair/inventory/revoke + last-command/timeout state). FK to
            // users cascades on GDPR delete.
            \\CREATE TABLE IF NOT EXISTS {schema}.extension_devices (
            \\    id TEXT PRIMARY KEY DEFAULT encode(gen_random_bytes(16), 'hex'),
            \\    user_id BIGINT NOT NULL REFERENCES {schema}.users(user_id) ON DELETE CASCADE,
            \\    label TEXT NOT NULL DEFAULT '',
            \\    status TEXT NOT NULL DEFAULT 'active',
            \\    paired_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
            \\    last_seen_at TIMESTAMPTZ,
            \\    last_command TEXT,
            \\    last_command_at TIMESTAMPTZ,
            \\    last_error TEXT,
            \\    last_error_at TIMESTAMPTZ
            \\)
            ,
            "CREATE INDEX IF NOT EXISTS idx_extension_devices_user ON {schema}.extension_devices(user_id, status)",
            // S7 — user-managed model-provider profiles (OpenAI-compatible
            // / BYOK). API key lives in user_secrets; this row holds only
            // non-secret metadata. FK cascades on GDPR delete.
            \\CREATE TABLE IF NOT EXISTS {schema}.provider_profiles (
            \\    id TEXT PRIMARY KEY DEFAULT encode(gen_random_bytes(16), 'hex'),
            \\    user_id BIGINT NOT NULL REFERENCES {schema}.users(user_id) ON DELETE CASCADE,
            \\    label TEXT NOT NULL DEFAULT '',
            \\    provider_kind TEXT NOT NULL,
            \\    base_url TEXT NOT NULL,
            \\    auth_style TEXT NOT NULL DEFAULT 'bearer',
            \\    model_allowlist JSONB NOT NULL DEFAULT '[]'::jsonb,
            \\    default_model TEXT,
            \\    policy_state TEXT NOT NULL DEFAULT 'active',
            \\    last_test JSONB,
            \\    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
            \\    updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
            \\)
            ,
            "CREATE INDEX IF NOT EXISTS idx_provider_profiles_user ON {schema}.provider_profiles(user_id)",
            \\CREATE TABLE IF NOT EXISTS {schema}.heartbeat (
            \\    user_id BIGINT PRIMARY KEY REFERENCES {schema}.users(user_id) ON DELETE CASCADE,
            \\    config JSONB NOT NULL DEFAULT '{}'::jsonb,
            \\    last_evaluated_at TIMESTAMPTZ,
            \\    last_triggered_at TIMESTAMPTZ,
            \\    updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
            \\)
            ,
            \\CREATE TABLE IF NOT EXISTS {schema}.onboarding (
            \\    user_id BIGINT PRIMARY KEY REFERENCES {schema}.users(user_id) ON DELETE CASCADE,
            \\    state JSONB NOT NULL DEFAULT '{"completed":false}'::jsonb,
            \\    updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
            \\)
            ,
            \\CREATE TABLE IF NOT EXISTS {schema}.tenant_user_leases (
            \\    user_id BIGINT PRIMARY KEY REFERENCES {schema}.users(user_id) ON DELETE CASCADE,
            \\    owner_id TEXT NOT NULL,
            \\    lease_token TEXT NOT NULL,
            \\    lease_until TIMESTAMPTZ NOT NULL,
            \\    updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
            \\)
            ,
            "CREATE INDEX IF NOT EXISTS idx_tenant_user_leases_owner_until ON {schema}.tenant_user_leases(owner_id, lease_until DESC)",
            \\CREATE TABLE IF NOT EXISTS {schema}.jobs (
            \\    id TEXT PRIMARY KEY,
            \\    user_id BIGINT NOT NULL REFERENCES {schema}.users(user_id) ON DELETE CASCADE,
            \\    session_id TEXT REFERENCES {schema}.sessions(id) ON DELETE SET NULL,
            \\    kind TEXT NOT NULL,
            \\    schedule_type TEXT NOT NULL,
            \\    cron_expr TEXT,
            \\    run_at TIMESTAMPTZ,
            \\    timezone TEXT NOT NULL,
            \\    payload JSONB NOT NULL DEFAULT '{}'::jsonb,
            \\    raw_job JSONB NOT NULL DEFAULT '{}'::jsonb,
            \\    delivery JSONB NOT NULL DEFAULT '{}'::jsonb,
            \\    enabled BOOLEAN NOT NULL DEFAULT TRUE,
            \\    quiet_hours_policy JSONB NOT NULL DEFAULT '{}'::jsonb,
            \\    retry_budget INT NOT NULL DEFAULT 3,
            \\    retry_count INT NOT NULL DEFAULT 0,
            \\    next_run_at TIMESTAMPTZ,
            \\    last_run_at TIMESTAMPTZ,
            \\    last_status TEXT,
            \\    last_error TEXT,
            \\    lease_owner TEXT,
            \\    lease_until TIMESTAMPTZ,
            \\    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
            \\    updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
            \\)
            ,
            "CREATE INDEX IF NOT EXISTS idx_jobs_due ON {schema}.jobs(enabled, next_run_at)",
            "CREATE INDEX IF NOT EXISTS idx_jobs_user_due ON {schema}.jobs(user_id, next_run_at)",
            \\CREATE TABLE IF NOT EXISTS {schema}.job_runs (
            \\    id TEXT PRIMARY KEY,
            \\    job_id TEXT NOT NULL REFERENCES {schema}.jobs(id) ON DELETE CASCADE,
            \\    user_id BIGINT NOT NULL REFERENCES {schema}.users(user_id) ON DELETE CASCADE,
            \\    started_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
            \\    finished_at TIMESTAMPTZ,
            \\    status TEXT NOT NULL,
            \\    output TEXT,
            \\    error TEXT,
            \\    trace JSONB NOT NULL DEFAULT '{}'::jsonb
            \\)
            ,
            \\CREATE TABLE IF NOT EXISTS {schema}.tasks (
            \\    id TEXT NOT NULL,
            \\    user_id BIGINT NOT NULL REFERENCES {schema}.users(user_id) ON DELETE CASCADE,
            \\    session_id TEXT REFERENCES {schema}.sessions(id) ON DELETE SET NULL,
            \\    request_session_id TEXT REFERENCES {schema}.sessions(id) ON DELETE SET NULL,
            \\    label TEXT NOT NULL,
            \\    prompt TEXT NOT NULL,
            \\    status TEXT NOT NULL,
            \\    result TEXT,
            \\    error TEXT,
            \\    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
            \\    started_at TIMESTAMPTZ,
            \\    completed_at TIMESTAMPTZ,
            \\    PRIMARY KEY (user_id, id)
            \\)
            ,
            "ALTER TABLE {schema}.tasks ADD COLUMN IF NOT EXISTS request_session_id TEXT REFERENCES {schema}.sessions(id) ON DELETE SET NULL",
            "ALTER TABLE {schema}.tasks DROP CONSTRAINT IF EXISTS tasks_pkey",
            "ALTER TABLE {schema}.tasks ADD PRIMARY KEY (user_id, id)",

            // S10.2 — bootstrap the schema_migrations tracker table +
            // record the legacy initial schema as version 1. The new
            // framework module at `src/migrations.zig` (S10.1) is the
            // path for future migrations 0002+. For 0001 we don't
            // re-run the full DDL via the framework because the
            // legacy loop above already did it (idempotently); we
            // just record it as applied so future migrations land
            // through the framework with full version-tracking
            // semantics. ON CONFLICT DO NOTHING makes this safe to
            // re-run on every boot during the legacy-loop transition
            // period.
            \\CREATE TABLE IF NOT EXISTS {schema}.schema_migrations (
            \\    version INTEGER PRIMARY KEY,
            \\    name TEXT NOT NULL,
            \\    applied_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
            \\)
            ,
            "INSERT INTO {schema}.schema_migrations (version, name) VALUES (1, '0001_initial_schema') ON CONFLICT (version) DO NOTHING",

            // ── V1.7a-9a — Communities (label-propagation auto-clustering) ──
            //
            // community_id on memories table:
            //   - Nullable INTEGER. NULL = unassigned (new memories before
            //     first recompute, OR archived memories — recompute leaves
            //     them as-was for historical record).
            //   - Stable across recomputes via hash of top-K-importance
            //     member keys (computed in src/agent/communities.zig).
            //
            // memory_communities table: per-(user, community) name + counts.
            //   - name_source distinguishes 'llm' vs 'fallback' for telemetry
            //     and FE styling (e.g. dim auto-fallback names).
            //   - generated_at enables stale-name detection on next recompute.
            //   - member_set_hash gates LLM re-call: only re-name when the
            //     top-K member set changes (cost control).
            "ALTER TABLE {schema}.memories ADD COLUMN IF NOT EXISTS community_id INTEGER",
            // Partial index on the live + brain-visible subset matches the
            // typical /brain/graph + /brain/communities query shape.
            "CREATE INDEX IF NOT EXISTS idx_memories_community ON {schema}.memories(user_id, community_id) WHERE is_latest AND community_id IS NOT NULL",
            \\CREATE TABLE IF NOT EXISTS {schema}.memory_communities (
            \\    user_id BIGINT NOT NULL REFERENCES {schema}.users(user_id) ON DELETE CASCADE,
            \\    community_id INTEGER NOT NULL,
            \\    name TEXT,
            \\    name_source TEXT,
            \\    member_count INTEGER NOT NULL DEFAULT 0,
            \\    member_set_hash TEXT,
            \\    generated_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
            \\    PRIMARY KEY (user_id, community_id)
            \\)
            ,
            // ── Wave 2C — canvas/artifacts backend (v1.14.21) ──────────
            //
            // Mirrors `src/migrations/0002_artifacts.sql` but rendered
            // here as idempotent CREATE TABLE IF NOT EXISTS so the
            // legacy migrate() loop applies it cleanly. The 0002 SQL
            // file is registered in `src/migrations.zig::MIGRATIONS` for
            // when we wire `migrations.run()` into this function
            // post-v1 — at that point this inline block + the legacy
            // loop go away together, and the framework runs every
            // migration exactly once. See deferred-register D62.
            //
            // Why inline now: the migrations framework has tests but
            // ZERO production callers — `migrations.run()` is never
            // invoked from this function. Plumbing the RunnerContext
            // through is a real refactor; the artifacts schema is
            // shipping for v1 commercial so the inline path is the
            // smallest safe change that gets the tables created on
            // every boot (idempotent, fail-soft, matches the existing
            // pattern for every other table in this file).
            \\CREATE TABLE IF NOT EXISTS {schema}.artifacts (
            \\    id              UUID PRIMARY KEY DEFAULT gen_random_uuid(),
            \\    user_id         BIGINT NOT NULL REFERENCES {schema}.users(user_id) ON DELETE CASCADE,
            \\    session_id      TEXT,
            \\    title           TEXT NOT NULL,
            \\    kind            TEXT NOT NULL CHECK (kind IN (
            \\        'markdown','code','html','svg','json','mermaid','plaintext'
            \\    )),
            \\    created_at_unix BIGINT NOT NULL,
            \\    updated_at_unix BIGINT NOT NULL,
            \\    current_version BIGINT NOT NULL DEFAULT 1,
            \\    is_shared       BOOLEAN NOT NULL DEFAULT FALSE,
            \\    share_code      TEXT UNIQUE,
            \\    share_expires_at_unix BIGINT,
            \\    metadata_jsonb  JSONB NOT NULL DEFAULT '{}'::jsonb
            \\)
            ,
            "CREATE INDEX IF NOT EXISTS idx_artifacts_user_updated ON {schema}.artifacts(user_id, updated_at_unix DESC)",
            "CREATE INDEX IF NOT EXISTS idx_artifacts_share_code ON {schema}.artifacts(share_code) WHERE share_code IS NOT NULL",
            \\CREATE TABLE IF NOT EXISTS {schema}.artifact_versions (
            \\    id              BIGSERIAL PRIMARY KEY,
            \\    artifact_id     UUID NOT NULL REFERENCES {schema}.artifacts(id) ON DELETE CASCADE,
            \\    version         BIGINT NOT NULL,
            \\    parent_version  BIGINT,
            \\    content         TEXT NOT NULL,
            \\    content_hash    TEXT NOT NULL,
            \\    created_at_unix BIGINT NOT NULL,
            \\    author          TEXT NOT NULL CHECK (author IN ('agent','user')),
            \\    change_summary  TEXT,
            \\    UNIQUE (artifact_id, version)
            \\)
            ,
            // v1.14.23 WARN-3: canonical name is `idx_artifact_versions_artifact_version`
            // — matches the migration file at src/migrations/0002_artifacts.sql:84.
            // Pre-fix, the inline path used `_artifact_ver` while migrations.run()
            // used `_artifact_version`; both `IF NOT EXISTS` succeeded, persisting
            // two indexes on the same (artifact_id, version DESC) columns →
            // storage bloat + double-write cost on every artifact_versions write.
            // Post-fix: the inline-loop path is now a no-op on post-D62 DBs
            // (idempotent, same name as migrations.run); fresh DBs get exactly
            // one canonical-named index. Drop of the legacy `_artifact_ver`
            // index on already-migrated DBs is intentionally NOT done here —
            // operators should run `DROP INDEX IF EXISTS idx_artifact_versions_artifact_ver`
            // manually as a one-shot during their next maintenance window.
            "CREATE INDEX IF NOT EXISTS idx_artifact_versions_artifact_version ON {schema}.artifact_versions(artifact_id, version DESC)",
        };

        for (statements) |template| {
            const query = try self.buildQuery(template);
            defer self.allocator.free(query);
            const result = try self.execMigrateStatement(template, query);
            if (result) |pg_result| c.PQclear(pg_result);
        }

        // ── D62 (2026-05-25) — wire src/migrations.zig framework ──────
        //
        // After the legacy idempotent loop above has bootstrapped the
        // schema_migrations tracker (v1 row inserted via ON CONFLICT
        // DO NOTHING), invoke the versioned-migration framework so any
        // 0002+ entries land through it with full version-tracking
        // semantics (transactional apply + once-per-DB enforcement).
        //
        // Why this runs AFTER the legacy loop, not instead of it:
        //   - 0001's full DDL is already covered by the legacy loop
        //     (idempotent CREATE IF NOT EXISTS guards).
        //   - migrations.run() sees v=1 already applied → skips 0001
        //     body, applies 0002+ once.
        //   - Failures here surface (no canIgnoreMigrateError swallow);
        //     0002_artifacts.sql is idempotent for the dual-path window
        //     so the framework can safely re-create tables the inline
        //     loop already made.
        //
        // Once the inline artifacts block (lines ~2240+) is deleted in a
        // follow-up commit, the framework becomes the sole creator for
        // 0002+ tables and 0002_artifacts.sql can drop its IF NOT EXISTS
        // guards to become a true pure-diff migration.
        try migrationsRunForManager(self);
    }

    /// D62 adapter glue: build a `migrations.RunnerContext` that wraps
    /// this Manager's connection-pool primitives + `{schema}`-substituting
    /// `buildQuery`, then invoke `migrations.run()`. Extracted so tests can
    /// exercise the wiring independently of the legacy loop and so the
    /// adapter struct (which holds transient transaction state) lives in
    /// its own stack frame.
    fn migrationsRunForManager(self: *Self) !void {
        var adapter = MigrationsAdapter{ .mgr = self };
        defer adapter.deinit();
        try migrations.run(adapter.context());
    }

    /// D62 adapter: maps `migrations.RunnerContext`'s 7-callback vtable
    /// onto this Manager's `exec` / `beginTransaction` / `buildQuery`
    /// primitives. A single instance is created per `migrate()` call
    /// and owns at most one in-flight `TxnLease` between `begin` and
    /// `commit`/`rollback`. Connection pinning is mandatory: BEGIN on
    /// conn-X is meaningless on conn-Y, so the same TxnLease handles
    /// every `exec` and `recordApplied` issued inside the transaction.
    const MigrationsAdapter = struct {
        mgr: *Self,
        /// Pinned-connection lease populated by `begin`, consumed by
        /// `commit` / `rollback`. Null outside of a transaction (the
        /// runner execs the schema_migrations DDL + the `isApplied`
        /// SELECTs auto-committed on a one-shot pool connection).
        txn: ?TxnLease = null,

        fn deinit(self: *MigrationsAdapter) void {
            // Defensive: if a transaction is still open when the
            // adapter is torn down (e.g. runner panicked between begin
            // and commit), roll it back so the pool conn isn't poisoned.
            if (self.txn) |*t| t.deinit();
        }

        fn context(self: *MigrationsAdapter) migrations.RunnerContext {
            return .{
                .exec = execImpl,
                .begin = beginImpl,
                .commit = commitImpl,
                .rollback = rollbackImpl,
                .isApplied = isAppliedImpl,
                .recordApplied = recordAppliedImpl,
                .buildQuery = buildQueryImpl,
                .freeQuery = freeQueryImpl,
                .ctx = @ptrCast(self),
            };
        }

        fn execImpl(ctx: *anyopaque, query: []const u8) anyerror!void {
            const self: *MigrationsAdapter = @ptrCast(@alignCast(ctx));
            if (self.txn) |*t| {
                const result = try t.exec(query);
                c.PQclear(result);
            } else {
                const result = try self.mgr.exec(query);
                c.PQclear(result);
            }
        }

        fn beginImpl(ctx: *anyopaque) anyerror!void {
            const self: *MigrationsAdapter = @ptrCast(@alignCast(ctx));
            if (self.txn != null) return error.NestedTransactionNotSupported;
            self.txn = try self.mgr.beginTransaction();
        }

        fn commitImpl(ctx: *anyopaque) anyerror!void {
            const self: *MigrationsAdapter = @ptrCast(@alignCast(ctx));
            if (self.txn) |*t| {
                try t.commit();
                self.txn = null;
            }
        }

        fn rollbackImpl(ctx: *anyopaque) anyerror!void {
            const self: *MigrationsAdapter = @ptrCast(@alignCast(ctx));
            if (self.txn) |*t| {
                t.rollback();
                self.txn = null;
            }
        }

        fn isAppliedImpl(ctx: *anyopaque, version: u32) anyerror!bool {
            const self: *MigrationsAdapter = @ptrCast(@alignCast(ctx));
            const q = try self.mgr.buildQuery(
                "SELECT 1 FROM {schema}.schema_migrations WHERE version = $1 LIMIT 1",
            );
            defer self.mgr.allocator.free(q);

            var ver_buf: [16]u8 = undefined;
            const ver_s = try std.fmt.bufPrintZ(&ver_buf, "{d}", .{version});

            // Use the pinned txn conn if we're already inside one (rare
            // for isApplied, but the runner makes no guarantee about
            // ordering). The non-txn path acquires a one-shot pool conn.
            const result = if (self.txn) |*t|
                try t.execParams(q, &.{ver_s.ptr}, &.{@as(c_int, @intCast(ver_s.len))})
            else
                try self.mgr.execParams(q, &.{ver_s.ptr}, &.{@as(c_int, @intCast(ver_s.len))});
            defer c.PQclear(result);
            return c.PQntuples(result) > 0;
        }

        fn recordAppliedImpl(ctx: *anyopaque, version: u32, name: []const u8) anyerror!void {
            const self: *MigrationsAdapter = @ptrCast(@alignCast(ctx));
            const q = try self.mgr.buildQuery(
                "INSERT INTO {schema}.schema_migrations (version, name) VALUES ($1, $2) ON CONFLICT (version) DO NOTHING",
            );
            defer self.mgr.allocator.free(q);

            var ver_buf: [16]u8 = undefined;
            const ver_s = try std.fmt.bufPrintZ(&ver_buf, "{d}", .{version});
            const name_z = try self.mgr.allocator.dupeZ(u8, name);
            defer self.mgr.allocator.free(name_z);

            // Must run on the pinned txn conn when one is open so the
            // version-row insert rolls back atomically with the DDL.
            // The runner ALWAYS calls recordApplied while a transaction
            // is open for transactional migrations; for concurrent_only
            // migrations the runner wraps recordApplied in its own
            // begin/commit pair, so the txn lease is set then too.
            if (self.txn) |*t| {
                const result = try t.execParams(
                    q,
                    &.{ ver_s.ptr, name_z.ptr },
                    &.{ @as(c_int, @intCast(ver_s.len)), @as(c_int, @intCast(name.len)) },
                );
                c.PQclear(result);
            } else {
                // Defensive fallback — the runner contract has it always
                // call recordApplied inside a transaction, but tolerate
                // a stray call so we don't lose the version marker.
                const result = try self.mgr.execParams(
                    q,
                    &.{ ver_s.ptr, name_z.ptr },
                    &.{ @as(c_int, @intCast(ver_s.len)), @as(c_int, @intCast(name.len)) },
                );
                c.PQclear(result);
            }
        }

        fn buildQueryImpl(ctx: *anyopaque, template: []const u8) anyerror![]const u8 {
            const self: *MigrationsAdapter = @ptrCast(@alignCast(ctx));
            // Self.buildQuery returns [:0]u8 (sentinel-terminated, since
            // it backs libpq's null-terminated query interface). The
            // RunnerContext API is []const u8 — we coerce the slice but
            // freeQueryImpl below reconstructs the [:0]u8 view so
            // Allocator.free reads the right allocation size (sentinel
            // slices use len+1 bytes; non-sentinel use len).
            const z = try self.mgr.buildQuery(template);
            return z;
        }

        fn freeQueryImpl(ctx: *anyopaque, query: []const u8) void {
            const self: *MigrationsAdapter = @ptrCast(@alignCast(ctx));
            // Reconstruct the [:0]u8 view of the same allocation so
            // Allocator.free deallocates len+1 bytes — the original
            // size emitted by buildQuery / toOwnedSliceSentinel. A
            // plain `free(query)` (over []const u8) would leak the
            // sentinel byte per call.
            const z: [:0]const u8 = query.ptr[0..query.len :0];
            self.mgr.allocator.free(z);
        }
    };

    pub fn provisionUser(self: *Self, user_id: i64, workspace_path: []const u8) !void {
        if (try self.hasExternalIdentity(user_id)) |exists| {
            if (!exists) return error.IdentityUserNotFound;
        }
        var user_buf: [32]u8 = undefined;
        const user_s = try std.fmt.bufPrintZ(&user_buf, "{d}", .{user_id});
        const workspace_z = try self.allocator.dupeZ(u8, workspace_path);
        defer self.allocator.free(workspace_z);
        var key_buf: [128]u8 = undefined;
        const session_key = zaki_session.userMainSessionKey(&key_buf, user_s);
        const session_key_z = try self.allocator.dupeZ(u8, session_key);
        defer self.allocator.free(session_key_z);

        // P1-7 (2026-06-12): all 6 provisioning inserts run inside a SINGLE
        // connection-pinned transaction (same TxnLease pattern as
        // createArtifact). Pre-P1-7 each was a separate autocommit
        // statement on a (potentially different) pooled connection, so a
        // mid-provision failure (e.g. the heartbeat insert) left a
        // half-provisioned user — a users row with no config/sessions, or
        // vice versa. Wrapping in one txn makes provisioning all-or-nothing:
        // any failed insert rolls the whole batch back. The runtime
        // self-heal paths (P0-6 ensureUserRow, P1-8 below) backfill the
        // users row defensively, but provisioning itself must not leave a
        // torn state behind.
        var txn = try self.beginTransaction();
        defer txn.deinit();

        try self.txnExecNoResult(
            &txn,
            "INSERT INTO {schema}.users (user_id, workspace_path) VALUES ($1, $2) " ++
                "ON CONFLICT (user_id) DO UPDATE SET workspace_path = EXCLUDED.workspace_path, updated_at = NOW()",
            &.{ user_s.ptr, workspace_z },
            &.{ @as(c_int, @intCast(user_s.len)), @as(c_int, @intCast(workspace_path.len)) },
        );
        try self.txnExecNoResult(
            &txn,
            "INSERT INTO {schema}.user_config (user_id) VALUES ($1) ON CONFLICT (user_id) DO NOTHING",
            &.{user_s.ptr},
            &.{@as(c_int, @intCast(user_s.len))},
        );
        try self.txnExecNoResult(
            &txn,
            "INSERT INTO {schema}.heartbeat (user_id) VALUES ($1) ON CONFLICT (user_id) DO NOTHING",
            &.{user_s.ptr},
            &.{@as(c_int, @intCast(user_s.len))},
        );
        try self.txnExecNoResult(
            &txn,
            "INSERT INTO {schema}.channel_state (user_id) VALUES ($1) ON CONFLICT (user_id) DO NOTHING",
            &.{user_s.ptr},
            &.{@as(c_int, @intCast(user_s.len))},
        );
        try self.txnExecNoResult(
            &txn,
            "INSERT INTO {schema}.onboarding (user_id) VALUES ($1) ON CONFLICT (user_id) DO NOTHING",
            &.{user_s.ptr},
            &.{@as(c_int, @intCast(user_s.len))},
        );
        try self.txnExecNoResult(
            &txn,
            "INSERT INTO {schema}.sessions (id, user_id, session_key, kind, title) VALUES ($1, $2, $1, 'main', 'Main') ON CONFLICT (session_key) DO NOTHING",
            &.{ session_key_z, user_s.ptr },
            &.{ @as(c_int, @intCast(session_key.len)), @as(c_int, @intCast(user_s.len)) },
        );

        try txn.commit();
    }

    /// Run a parameterized, no-result-needed write on an open TxnLease.
    /// Mirrors `execParamsNoResult` (schema substitution via buildQuery)
    /// but pins the statement to the transaction's connection instead of
    /// acquiring a one-shot pool conn. Used by provisionUser (P1-7) so the
    /// provisioning inserts share one all-or-nothing transaction.
    fn txnExecNoResult(self: *Self, txn: *TxnLease, template: []const u8, params: []const ?[*:0]const u8, lengths: []const c_int) !void {
        const query = try self.buildQuery(template);
        defer self.allocator.free(query);
        const result = try txn.execParams(query, params, lengths);
        c.PQclear(result);
    }

    /// Test-only — forcibly preset the external-identity gate so
    /// `hasExternalIdentity` returns null without probing
    /// `public.zaki_users`. Use this from S6 verification-matrix tests
    /// that want to provision a synthetic `user_id` regardless of
    /// whether the zaki_users identity table happens to exist in the
    /// test database (which is the difference between a pristine
    /// pgvector container vs one that's been used by prior test runs).
    ///
    /// Production code paths MUST NOT call this. The check exists to
    /// prevent provisioning shadow users that bypass the auth surface;
    /// disabling it in production would be a security hole. The
    /// `comptime` guard below makes a production call a COMPILE-TIME
    /// error — there is no runtime path to invoke this from a release
    /// build. (Same pattern as `env_rebrand.resetForTests`.)
    pub fn skipExternalIdentityForTests(self: *Self) void {
        if (!@import("builtin").is_test) {
            @compileError("Manager.skipExternalIdentityForTests called outside test build — this bypass disables the public.zaki_users identity gate and is forbidden in production");
        }
        self.external_identity_status = .unavailable;
        // P1-9: pin the latch FOREVER so the new TTL re-probe doesn't undo
        // the test bypass mid-test (a 0 timestamp would otherwise read as
        // "window long elapsed" → re-probe).
        self.external_identity_unavailable_since_ms = EXTERNAL_IDENTITY_PIN_FOREVER;
    }

    pub fn hasExternalIdentity(self: *Self, user_id: i64) !?bool {
        // F6 (2026-05-10): short-circuit when we've already learned the
        // `public.zaki_users` table doesn't exist in this deployment.
        // The first call probes; if it fails with a missing-table error,
        // subsequent calls within the TTL window return null silently.
        // Without this guard a long bench logged ~200 identical
        // `relation does not exist` errors.
        //
        // P1-9 (2026-06-12): the short-circuit is TTL'd. A SINGLE transient
        // probe failure no longer latches `.unavailable` forever (which
        // would permanently disable identity verification — fully fail-open
        // for the Manager's whole life). Within EXTERNAL_IDENTITY_REPROBE_MS
        // we keep failing open (preserves F6's noisy-log mitigation for a
        // genuinely-absent table); after the window we re-probe so a
        // transient blip self-heals back to `.available`.
        const now_ms = std.time.milliTimestamp();
        if (!shouldReprobeExternalIdentity(
            self.external_identity_status == .unavailable,
            self.external_identity_unavailable_since_ms,
            now_ms,
            EXTERNAL_IDENTITY_REPROBE_MS,
        )) {
            return null;
        }

        var user_buf: [32]u8 = undefined;
        const user_s = try std.fmt.bufPrintZ(&user_buf, "{d}", .{user_id});
        const query =
            "SELECT 1 FROM public.zaki_users WHERE id = $1 LIMIT 1";

        const result = self.execParams(query, &.{user_s.ptr}, &.{@as(c_int, @intCast(user_s.len))}) catch |err| switch (err) {
            // Compatibility mode: keep provisioning behavior when the identity
            // table is inaccessible in this runtime. F6: cache the
            // unavailability so the next calls (within the TTL) don't repeat
            // the noisy error log. P1-9: (re)stamp the latch time so the
            // window restarts from THIS failure — a still-absent table
            // re-latches each window (~1 probe/window), a recovered table
            // probes once and flips back to `.available` below.
            error.ExecFailed, error.ConnectionFailed => {
                self.external_identity_status = .unavailable;
                self.external_identity_unavailable_since_ms = now_ms;
                return null;
            },
            else => return err,
        };
        defer c.PQclear(result);

        // Successful probe — clear any prior `.unavailable` latch so the
        // gate is fully re-enabled (self-heal complete).
        self.external_identity_status = .available;
        return c.PQntuples(result) > 0;
    }

    pub fn getConfigJson(self: *Self, allocator: std.mem.Allocator, user_id: i64) ![]u8 {
        return self.getJsonValue(allocator, user_id, "user_config", "config", "{}");
    }

    pub fn putConfigJson(self: *Self, user_id: i64, json: []const u8) !void {
        const q = try self.buildQuery(
            "INSERT INTO {schema}.user_config (user_id, config, updated_at) VALUES ($1, $2::jsonb, NOW()) " ++
                "ON CONFLICT (user_id) DO UPDATE SET config = EXCLUDED.config, version = {schema}.user_config.version + 1, updated_at = NOW()",
        );
        defer self.allocator.free(q);
        try self.execJsonUpsert(q, user_id, json);
    }

    pub fn listUserConfigRows(self: *Self, allocator: std.mem.Allocator) ![]UserConfigRow {
        const q = try self.buildQuery(
            "SELECT user_id, config::text FROM {schema}.user_config ORDER BY user_id ASC",
        );
        defer self.allocator.free(q);
        const result = try self.exec(q);
        defer c.PQclear(result);
        const rows: usize = @intCast(c.PQntuples(result));
        const out = try allocator.alloc(UserConfigRow, rows);
        var initialized: usize = 0;
        errdefer {
            for (out[0..initialized]) |*row| row.deinit(allocator);
            allocator.free(out);
        }
        for (0..rows) |i| {
            const row_idx: c_int = @intCast(i);
            const user_text = try dupeResultValue(allocator, result, row_idx, 0);
            defer allocator.free(user_text);
            out[i] = .{
                .user_id = try std.fmt.parseInt(i64, user_text, 10),
                .config_json = try dupeResultValue(allocator, result, row_idx, 1),
            };
            initialized += 1;
        }
        return out;
    }

    pub fn getHeartbeatJson(self: *Self, allocator: std.mem.Allocator, user_id: i64) ![]u8 {
        return self.getJsonValue(allocator, user_id, "heartbeat", "config", "{}");
    }

    pub fn putHeartbeatJson(self: *Self, user_id: i64, json: []const u8) !void {
        const q = try self.buildQuery(
            "INSERT INTO {schema}.heartbeat (user_id, config, updated_at) VALUES ($1, $2::jsonb, NOW()) " ++
                "ON CONFLICT (user_id) DO UPDATE SET config = EXCLUDED.config, updated_at = NOW()",
        );
        defer self.allocator.free(q);
        try self.execJsonUpsert(q, user_id, json);
    }

    pub fn getOnboardingJson(self: *Self, allocator: std.mem.Allocator, user_id: i64) ![]u8 {
        return self.getJsonValue(allocator, user_id, "onboarding", "state", "{\"completed\":false,\"completed_at_s\":null}");
    }

    pub fn putOnboardingJson(self: *Self, user_id: i64, json: []const u8) !void {
        const q = try self.buildQuery(
            "WITH onboarding_upsert AS (" ++
                "INSERT INTO {schema}.onboarding (user_id, state, updated_at) VALUES ($1, $2::jsonb, NOW()) " ++
                "ON CONFLICT (user_id) DO UPDATE SET state = EXCLUDED.state, updated_at = NOW() " ++
                "RETURNING user_id" ++
                ") " ++
                "UPDATE {schema}.users SET onboarding_completed = COALESCE(($2::jsonb->>'completed')::boolean, false), " ++
                "onboarding_completed_at = CASE WHEN COALESCE(($2::jsonb->>'completed')::boolean, false) THEN NOW() ELSE NULL END, updated_at = NOW() " ++
                "WHERE user_id IN (SELECT user_id FROM onboarding_upsert)",
        );
        defer self.allocator.free(q);
        try self.execJsonUpsert(q, user_id, json);
    }

    pub fn getTelegramStateJson(self: *Self, allocator: std.mem.Allocator, user_id: i64) ![]u8 {
        return self.getJsonValue(allocator, user_id, "channel_state", "telegram", "{}");
    }

    pub fn putTelegramStateJson(self: *Self, user_id: i64, json: []const u8) !void {
        const q = try self.buildQuery(
            "INSERT INTO {schema}.channel_state (user_id, telegram, updated_at) VALUES ($1, $2::jsonb, NOW()) " ++
                "ON CONFLICT (user_id) DO UPDATE SET telegram = EXCLUDED.telegram, updated_at = NOW()",
        );
        defer self.allocator.free(q);
        try self.execJsonUpsert(q, user_id, json);
    }

    pub fn deleteTelegramState(self: *Self, user_id: i64) !void {
        const q = try self.buildQuery(
            "UPDATE {schema}.channel_state SET telegram = '{}'::jsonb, updated_at = NOW() WHERE user_id = $1",
        );
        defer self.allocator.free(q);
        var user_buf: [32]u8 = undefined;
        const user_s = try std.fmt.bufPrintZ(&user_buf, "{d}", .{user_id});
        const params = [_]?[*:0]const u8{user_s.ptr};
        const lengths = [_]c_int{@intCast(user_s.len)};
        const result = try self.execParams(q, &params, &lengths);
        c.PQclear(result);
    }

    // ── S7 — generic per-channel control-plane state ───────────────────
    //
    // Non-secret connection metadata (status flags, account/host ids,
    // last-test result) for the user-managed channels (slack, discord,
    // email, whatsapp) lives under per-channel keys in the
    // `channel_state.channels` JSONB column. Credentials NEVER land here —
    // they go to the encrypted `user_secrets` vault via putSecret. The
    // channel key is always a bound parameter ($2), so the caller's
    // allowlist (channel_control.fromKey) is the only trust boundary.

    /// Return the JSON object stored for `channel` (e.g. "slack"), or
    /// "{}" when absent. Caller owns the returned slice.
    pub fn getChannelStateJson(self: *Self, allocator: std.mem.Allocator, user_id: i64, channel: []const u8) ![]u8 {
        const q = try self.buildQuery(
            "SELECT COALESCE(channels->$2, '{}'::jsonb)::text FROM {schema}.channel_state WHERE user_id = $1",
        );
        defer self.allocator.free(q);
        var user_buf: [32]u8 = undefined;
        const user_s = try std.fmt.bufPrintZ(&user_buf, "{d}", .{user_id});
        const channel_z = try self.allocator.dupeZ(u8, channel);
        defer self.allocator.free(channel_z);
        const params = [_]?[*:0]const u8{ user_s.ptr, channel_z };
        const lengths = [_]c_int{ @intCast(user_s.len), @intCast(channel.len) };
        const result = try self.execParams(q, &params, &lengths);
        defer c.PQclear(result);
        if (c.PQntuples(result) == 0) return allocator.dupe(u8, "{}");
        return dupeResultValue(allocator, result, 0, 0);
    }

    /// Merge `json` (a JSON object) under the `channel` key, preserving
    /// other channels' state. Upserts the channel_state row if missing.
    pub fn putChannelStateJson(self: *Self, user_id: i64, channel: []const u8, json: []const u8) !void {
        const q = try self.buildQuery(
            "INSERT INTO {schema}.channel_state (user_id, channels, updated_at) VALUES ($1, jsonb_build_object($2::text, $3::jsonb), NOW()) " ++
                "ON CONFLICT (user_id) DO UPDATE SET channels = COALESCE({schema}.channel_state.channels, '{}'::jsonb) || jsonb_build_object($2::text, $3::jsonb), updated_at = NOW()",
        );
        defer self.allocator.free(q);
        var user_buf: [32]u8 = undefined;
        const user_s = try std.fmt.bufPrintZ(&user_buf, "{d}", .{user_id});
        const channel_z = try self.allocator.dupeZ(u8, channel);
        defer self.allocator.free(channel_z);
        const json_z = try self.allocator.dupeZ(u8, json);
        defer self.allocator.free(json_z);
        const params = [_]?[*:0]const u8{ user_s.ptr, channel_z, json_z };
        const lengths = [_]c_int{ @intCast(user_s.len), @intCast(channel.len), @intCast(json.len) };
        const result = try self.execParams(q, &params, &lengths);
        c.PQclear(result);
    }

    /// Remove the `channel` key from the user's channel_state (disconnect).
    pub fn deleteChannelStateJson(self: *Self, user_id: i64, channel: []const u8) !void {
        const q = try self.buildQuery(
            "UPDATE {schema}.channel_state SET channels = COALESCE(channels, '{}'::jsonb) - $2::text, updated_at = NOW() WHERE user_id = $1",
        );
        defer self.allocator.free(q);
        var user_buf: [32]u8 = undefined;
        const user_s = try std.fmt.bufPrintZ(&user_buf, "{d}", .{user_id});
        const channel_z = try self.allocator.dupeZ(u8, channel);
        defer self.allocator.free(channel_z);
        const params = [_]?[*:0]const u8{ user_s.ptr, channel_z };
        const lengths = [_]c_int{ @intCast(user_s.len), @intCast(channel.len) };
        const result = try self.execParams(q, &params, &lengths);
        c.PQclear(result);
    }

    // ── S7 — extension device registry ─────────────────────────────────

    /// Register a new device for the user and return its server-minted id.
    pub fn pairExtensionDevice(self: *Self, allocator: std.mem.Allocator, user_id: i64, label: []const u8) ![]u8 {
        const q = try self.buildQuery(
            "INSERT INTO {schema}.extension_devices (user_id, label) VALUES ($1, $2) RETURNING id",
        );
        defer self.allocator.free(q);
        var user_buf: [32]u8 = undefined;
        const user_s = try std.fmt.bufPrintZ(&user_buf, "{d}", .{user_id});
        const label_z = try self.allocator.dupeZ(u8, label);
        defer self.allocator.free(label_z);
        const params = [_]?[*:0]const u8{ user_s.ptr, label_z };
        const lengths = [_]c_int{ @intCast(user_s.len), @intCast(label.len) };
        const result = try self.execParams(q, &params, &lengths);
        defer c.PQclear(result);
        if (c.PQntuples(result) == 0) return error.DeviceInsertFailed;
        return dupeResultValue(allocator, result, 0, 0);
    }

    /// List the user's devices, newest first.
    pub fn listExtensionDevices(self: *Self, allocator: std.mem.Allocator, user_id: i64) ![]ExtensionDeviceRow {
        const q = try self.buildQuery(
            "SELECT id, label, status, EXTRACT(EPOCH FROM paired_at)::bigint, " ++
                "EXTRACT(EPOCH FROM last_seen_at)::bigint, last_command, " ++
                "EXTRACT(EPOCH FROM last_command_at)::bigint, last_error, " ++
                "EXTRACT(EPOCH FROM last_error_at)::bigint " ++
                "FROM {schema}.extension_devices WHERE user_id = $1 ORDER BY paired_at DESC",
        );
        defer self.allocator.free(q);
        var user_buf: [32]u8 = undefined;
        const user_s = try std.fmt.bufPrintZ(&user_buf, "{d}", .{user_id});
        const params = [_]?[*:0]const u8{user_s.ptr};
        const lengths = [_]c_int{@intCast(user_s.len)};
        const result = try self.execParams(q, &params, &lengths);
        defer c.PQclear(result);
        const nrows: usize = @intCast(@max(0, c.PQntuples(result)));
        if (nrows == 0) return allocator.alloc(ExtensionDeviceRow, 0);

        const rows = try allocator.alloc(ExtensionDeviceRow, nrows);
        var initialized: usize = 0;
        errdefer {
            for (rows[0..initialized]) |r| r.deinit(allocator);
            allocator.free(rows);
        }
        for (0..nrows) |i| {
            const ri: c_int = @intCast(i);
            const id = try dupeResultValue(allocator, result, ri, 0);
            errdefer allocator.free(id);
            const label = try dupeResultValue(allocator, result, ri, 1);
            errdefer allocator.free(label);
            const status = try dupeResultValue(allocator, result, ri, 2);
            errdefer allocator.free(status);

            const paired_raw = try dupeResultValue(allocator, result, ri, 3);
            defer allocator.free(paired_raw);
            const paired_at_unix = std.fmt.parseInt(i64, paired_raw, 10) catch return error.InvalidTimestamp;

            const last_seen = try parseNullableEpochCol(allocator, result, ri, 4);
            const last_command: ?[]const u8 = if (c.PQgetisnull(result, ri, 5) == 1) null else try dupeResultValue(allocator, result, ri, 5);
            errdefer if (last_command) |v| allocator.free(v);
            const last_command_at = try parseNullableEpochCol(allocator, result, ri, 6);
            const last_error: ?[]const u8 = if (c.PQgetisnull(result, ri, 7) == 1) null else try dupeResultValue(allocator, result, ri, 7);
            errdefer if (last_error) |v| allocator.free(v);
            const last_error_at = try parseNullableEpochCol(allocator, result, ri, 8);

            rows[i] = .{
                .id = id,
                .label = label,
                .status = status,
                .paired_at_unix = paired_at_unix,
                .last_seen_at_unix = last_seen,
                .last_command = last_command,
                .last_command_at_unix = last_command_at,
                .last_error = last_error,
                .last_error_at_unix = last_error_at,
            };
            initialized += 1;
        }
        return rows;
    }

    /// Mark a device revoked. Returns false if no matching device.
    pub fn revokeExtensionDevice(self: *Self, user_id: i64, device_id: []const u8) !bool {
        const q = try self.buildQuery(
            "UPDATE {schema}.extension_devices SET status = 'revoked' WHERE user_id = $1 AND id = $2",
        );
        defer self.allocator.free(q);
        var user_buf: [32]u8 = undefined;
        const user_s = try std.fmt.bufPrintZ(&user_buf, "{d}", .{user_id});
        const id_z = try self.allocator.dupeZ(u8, device_id);
        defer self.allocator.free(id_z);
        const params = [_]?[*:0]const u8{ user_s.ptr, id_z };
        const lengths = [_]c_int{ @intCast(user_s.len), @intCast(device_id.len) };
        const result = try self.execParams(q, &params, &lengths);
        defer c.PQclear(result);
        const affected = c.PQcmdTuples(result);
        if (affected == null) return false;
        return !std.mem.eql(u8, std.mem.span(affected), "0");
    }

    /// Record runtime state (heartbeat + optional last command / error) for
    /// an active device. Intended for the WS runtime to call; the UI reads
    /// it back via listExtensionDevices. Returns false if no active match.
    pub fn recordExtensionDeviceState(self: *Self, user_id: i64, device_id: []const u8, last_command: ?[]const u8, last_error: ?[]const u8) !bool {
        const q = try self.buildQuery(
            "UPDATE {schema}.extension_devices SET last_seen_at = NOW(), " ++
                "last_command = COALESCE($3, last_command), " ++
                "last_command_at = CASE WHEN $3 IS NOT NULL THEN NOW() ELSE last_command_at END, " ++
                "last_error = COALESCE($4, last_error), " ++
                "last_error_at = CASE WHEN $4 IS NOT NULL THEN NOW() ELSE last_error_at END " ++
                "WHERE user_id = $1 AND id = $2 AND status = 'active'",
        );
        defer self.allocator.free(q);
        var user_buf: [32]u8 = undefined;
        const user_s = try std.fmt.bufPrintZ(&user_buf, "{d}", .{user_id});
        const id_z = try self.allocator.dupeZ(u8, device_id);
        defer self.allocator.free(id_z);
        const cmd_z: ?[*:0]const u8 = if (last_command) |v| (try self.allocator.dupeZ(u8, v)).ptr else null;
        defer if (cmd_z) |p| self.allocator.free(std.mem.span(p));
        const err_z: ?[*:0]const u8 = if (last_error) |v| (try self.allocator.dupeZ(u8, v)).ptr else null;
        defer if (err_z) |p| self.allocator.free(std.mem.span(p));
        const params = [_]?[*:0]const u8{ user_s.ptr, id_z, cmd_z, err_z };
        const lengths = [_]c_int{ @intCast(user_s.len), @intCast(device_id.len), @intCast(if (last_command) |v| v.len else 0), @intCast(if (last_error) |v| v.len else 0) };
        const result = try self.execParams(q, &params, &lengths);
        defer c.PQclear(result);
        const affected = c.PQcmdTuples(result);
        if (affected == null) return false;
        return !std.mem.eql(u8, std.mem.span(affected), "0");
    }

    // ── S7 — provider profiles ─────────────────────────────────────────

    pub fn createProviderProfile(
        self: *Self,
        allocator: std.mem.Allocator,
        user_id: i64,
        label: []const u8,
        provider_kind: []const u8,
        base_url: []const u8,
        auth_style: []const u8,
        model_allowlist_json: []const u8,
        default_model: ?[]const u8,
    ) ![]u8 {
        const q = try self.buildQuery(
            "INSERT INTO {schema}.provider_profiles (user_id, label, provider_kind, base_url, auth_style, model_allowlist, default_model) " ++
                "VALUES ($1, $2, $3, $4, $5, $6::jsonb, $7) RETURNING id",
        );
        defer self.allocator.free(q);
        var user_buf: [32]u8 = undefined;
        const user_s = try std.fmt.bufPrintZ(&user_buf, "{d}", .{user_id});
        const label_z = try self.allocator.dupeZ(u8, label);
        defer self.allocator.free(label_z);
        const kind_z = try self.allocator.dupeZ(u8, provider_kind);
        defer self.allocator.free(kind_z);
        const url_z = try self.allocator.dupeZ(u8, base_url);
        defer self.allocator.free(url_z);
        const auth_z = try self.allocator.dupeZ(u8, auth_style);
        defer self.allocator.free(auth_z);
        const allow_z = try self.allocator.dupeZ(u8, model_allowlist_json);
        defer self.allocator.free(allow_z);
        const dm_z: ?[*:0]const u8 = if (default_model) |v| (try self.allocator.dupeZ(u8, v)).ptr else null;
        defer if (dm_z) |p| self.allocator.free(std.mem.span(p));
        const params = [_]?[*:0]const u8{ user_s.ptr, label_z, kind_z, url_z, auth_z, allow_z, dm_z };
        const lengths = [_]c_int{ @intCast(user_s.len), @intCast(label.len), @intCast(provider_kind.len), @intCast(base_url.len), @intCast(auth_style.len), @intCast(model_allowlist_json.len), @intCast(if (default_model) |v| v.len else 0) };
        const result = try self.execParams(q, &params, &lengths);
        defer c.PQclear(result);
        if (c.PQntuples(result) == 0) return error.ProviderInsertFailed;
        return dupeResultValue(allocator, result, 0, 0);
    }

    const provider_select_cols =
        "id, label, provider_kind, base_url, auth_style, model_allowlist::text, default_model, policy_state, last_test::text, " ++
        "EXTRACT(EPOCH FROM created_at)::bigint, EXTRACT(EPOCH FROM updated_at)::bigint";

    fn parseProviderProfileRow(allocator: std.mem.Allocator, result: *c.PGresult, ri: c_int) !ProviderProfileRow {
        const id = try dupeResultValue(allocator, result, ri, 0);
        errdefer allocator.free(id);
        const label = try dupeResultValue(allocator, result, ri, 1);
        errdefer allocator.free(label);
        const kind = try dupeResultValue(allocator, result, ri, 2);
        errdefer allocator.free(kind);
        const base_url = try dupeResultValue(allocator, result, ri, 3);
        errdefer allocator.free(base_url);
        const auth_style = try dupeResultValue(allocator, result, ri, 4);
        errdefer allocator.free(auth_style);
        const allow = try dupeResultValue(allocator, result, ri, 5);
        errdefer allocator.free(allow);
        const default_model: ?[]const u8 = if (c.PQgetisnull(result, ri, 6) == 1) null else try dupeResultValue(allocator, result, ri, 6);
        errdefer if (default_model) |v| allocator.free(v);
        const policy = try dupeResultValue(allocator, result, ri, 7);
        errdefer allocator.free(policy);
        const last_test: ?[]const u8 = if (c.PQgetisnull(result, ri, 8) == 1) null else try dupeResultValue(allocator, result, ri, 8);
        errdefer if (last_test) |v| allocator.free(v);
        const created_raw = try dupeResultValue(allocator, result, ri, 9);
        defer allocator.free(created_raw);
        const updated_raw = try dupeResultValue(allocator, result, ri, 10);
        defer allocator.free(updated_raw);
        return .{
            .id = id,
            .label = label,
            .provider_kind = kind,
            .base_url = base_url,
            .auth_style = auth_style,
            .model_allowlist_json = allow,
            .default_model = default_model,
            .policy_state = policy,
            .last_test_json = last_test,
            .created_at_unix = std.fmt.parseInt(i64, created_raw, 10) catch return error.InvalidTimestamp,
            .updated_at_unix = std.fmt.parseInt(i64, updated_raw, 10) catch return error.InvalidTimestamp,
        };
    }

    pub fn listProviderProfiles(self: *Self, allocator: std.mem.Allocator, user_id: i64) ![]ProviderProfileRow {
        const q = try self.buildQuery("SELECT " ++ provider_select_cols ++ " FROM {schema}.provider_profiles WHERE user_id = $1 ORDER BY created_at DESC");
        defer self.allocator.free(q);
        var user_buf: [32]u8 = undefined;
        const user_s = try std.fmt.bufPrintZ(&user_buf, "{d}", .{user_id});
        const params = [_]?[*:0]const u8{user_s.ptr};
        const lengths = [_]c_int{@intCast(user_s.len)};
        const result = try self.execParams(q, &params, &lengths);
        defer c.PQclear(result);
        const nrows: usize = @intCast(@max(0, c.PQntuples(result)));
        if (nrows == 0) return allocator.alloc(ProviderProfileRow, 0);
        const rows = try allocator.alloc(ProviderProfileRow, nrows);
        var initialized: usize = 0;
        errdefer {
            for (rows[0..initialized]) |r| r.deinit(allocator);
            allocator.free(rows);
        }
        for (0..nrows) |i| {
            rows[i] = try parseProviderProfileRow(allocator, result, @intCast(i));
            initialized += 1;
        }
        return rows;
    }

    pub fn getProviderProfile(self: *Self, allocator: std.mem.Allocator, user_id: i64, id: []const u8) !?ProviderProfileRow {
        const q = try self.buildQuery("SELECT " ++ provider_select_cols ++ " FROM {schema}.provider_profiles WHERE user_id = $1 AND id = $2");
        defer self.allocator.free(q);
        var user_buf: [32]u8 = undefined;
        const user_s = try std.fmt.bufPrintZ(&user_buf, "{d}", .{user_id});
        const id_z = try self.allocator.dupeZ(u8, id);
        defer self.allocator.free(id_z);
        const params = [_]?[*:0]const u8{ user_s.ptr, id_z };
        const lengths = [_]c_int{ @intCast(user_s.len), @intCast(id.len) };
        const result = try self.execParams(q, &params, &lengths);
        defer c.PQclear(result);
        if (c.PQntuples(result) == 0) return null;
        return try parseProviderProfileRow(allocator, result, 0);
    }

    pub fn updateProviderProfile(
        self: *Self,
        user_id: i64,
        id: []const u8,
        label: ?[]const u8,
        base_url: ?[]const u8,
        auth_style: ?[]const u8,
        model_allowlist_json: ?[]const u8,
        default_model: ?[]const u8,
        policy_state: ?[]const u8,
    ) !bool {
        const q = try self.buildQuery(
            "UPDATE {schema}.provider_profiles SET " ++
                "label = COALESCE($3, label), " ++
                "base_url = COALESCE($4, base_url), " ++
                "auth_style = COALESCE($5, auth_style), " ++
                "model_allowlist = COALESCE($6::jsonb, model_allowlist), " ++
                "default_model = COALESCE($7, default_model), " ++
                "policy_state = COALESCE($8, policy_state), " ++
                "updated_at = NOW() WHERE user_id = $1 AND id = $2",
        );
        defer self.allocator.free(q);
        var user_buf: [32]u8 = undefined;
        const user_s = try std.fmt.bufPrintZ(&user_buf, "{d}", .{user_id});
        const id_z = try self.allocator.dupeZ(u8, id);
        defer self.allocator.free(id_z);
        const label_z: ?[*:0]const u8 = if (label) |v| (try self.allocator.dupeZ(u8, v)).ptr else null;
        defer if (label_z) |p| self.allocator.free(std.mem.span(p));
        const url_z: ?[*:0]const u8 = if (base_url) |v| (try self.allocator.dupeZ(u8, v)).ptr else null;
        defer if (url_z) |p| self.allocator.free(std.mem.span(p));
        const auth_z: ?[*:0]const u8 = if (auth_style) |v| (try self.allocator.dupeZ(u8, v)).ptr else null;
        defer if (auth_z) |p| self.allocator.free(std.mem.span(p));
        const allow_z: ?[*:0]const u8 = if (model_allowlist_json) |v| (try self.allocator.dupeZ(u8, v)).ptr else null;
        defer if (allow_z) |p| self.allocator.free(std.mem.span(p));
        const dm_z: ?[*:0]const u8 = if (default_model) |v| (try self.allocator.dupeZ(u8, v)).ptr else null;
        defer if (dm_z) |p| self.allocator.free(std.mem.span(p));
        const policy_z: ?[*:0]const u8 = if (policy_state) |v| (try self.allocator.dupeZ(u8, v)).ptr else null;
        defer if (policy_z) |p| self.allocator.free(std.mem.span(p));
        const params = [_]?[*:0]const u8{ user_s.ptr, id_z, label_z, url_z, auth_z, allow_z, dm_z, policy_z };
        const lengths = [_]c_int{
            @intCast(user_s.len),
            @intCast(id.len),
            @intCast(if (label) |v| v.len else 0),
            @intCast(if (base_url) |v| v.len else 0),
            @intCast(if (auth_style) |v| v.len else 0),
            @intCast(if (model_allowlist_json) |v| v.len else 0),
            @intCast(if (default_model) |v| v.len else 0),
            @intCast(if (policy_state) |v| v.len else 0),
        };
        const result = try self.execParams(q, &params, &lengths);
        defer c.PQclear(result);
        const affected = c.PQcmdTuples(result);
        if (affected == null) return false;
        return !std.mem.eql(u8, std.mem.span(affected), "0");
    }

