    }

    pub fn getArtifactByShareCode(
        self: *Self,
        allocator: std.mem.Allocator,
        share_code: []const u8,
        now_unix: i64,
    ) !?ArtifactRow {
        // Conservative — silently ignore expired shares (treat as 404).
        // The handler returns the same 404 for unknown / revoked /
        // expired so a guesser can't distinguish "valid but expired"
        // from "never existed."
        const q = try self.buildQuery(
            "SELECT id::text, user_id, COALESCE(session_id, ''), title, kind, created_at_unix, updated_at_unix, current_version, is_shared, share_code, COALESCE(share_expires_at_unix::text, ''), metadata_jsonb::text " ++
                "FROM {schema}.artifacts WHERE share_code = $1 AND is_shared = TRUE AND (share_expires_at_unix IS NULL OR share_expires_at_unix > $2::bigint)",
        );
        defer self.allocator.free(q);
        const code_z = try self.allocator.dupeZ(u8, share_code);
        defer self.allocator.free(code_z);
        var now_buf: [32]u8 = undefined;
        const now_s = try std.fmt.bufPrintZ(&now_buf, "{d}", .{now_unix});
        const params = [_]?[*:0]const u8{ code_z.ptr, now_s.ptr };
        const lengths = [_]c_int{ @intCast(share_code.len), @intCast(now_s.len) };
        const result = try self.execParams(q, &params, &lengths);
        defer c.PQclear(result);
        if (c.PQntuples(result) == 0) return null;

        // Column order differs slightly here — user_id is at col 1, rest shifted.
        const aid = try dupeResultValue(allocator, result, 0, 0);
        errdefer allocator.free(aid);
        const uid_str = try dupeResultValue(allocator, result, 0, 1);
        defer allocator.free(uid_str);
        const sid_raw = try dupeResultValue(allocator, result, 0, 2);
        defer allocator.free(sid_raw);
        const sid_owned: ?[]u8 = if (sid_raw.len == 0) null else try allocator.dupe(u8, sid_raw);
        errdefer if (sid_owned) |s| allocator.free(s);
        const title = try dupeResultValue(allocator, result, 0, 3);
        errdefer allocator.free(title);
        const kind = try dupeResultValue(allocator, result, 0, 4);
        errdefer allocator.free(kind);
        const created_str = try dupeResultValue(allocator, result, 0, 5);
        defer allocator.free(created_str);
        const updated_str = try dupeResultValue(allocator, result, 0, 6);
        defer allocator.free(updated_str);
        const ver_str = try dupeResultValue(allocator, result, 0, 7);
        defer allocator.free(ver_str);
        const is_shared_str = try dupeResultValue(allocator, result, 0, 8);
        defer allocator.free(is_shared_str);
        const share_code_out = try dupeResultValue(allocator, result, 0, 9);
        errdefer allocator.free(share_code_out);
        const expires_raw = try dupeResultValue(allocator, result, 0, 10);
        defer allocator.free(expires_raw);
        const meta_out = try dupeResultValue(allocator, result, 0, 11);
        errdefer allocator.free(meta_out);

        return .{
            .id = aid,
            .user_id = std.fmt.parseInt(i64, uid_str, 10) catch 0,
            .session_id = sid_owned,
            .title = title,
            .kind = kind,
            .created_at_unix = std.fmt.parseInt(i64, created_str, 10) catch 0,
            .updated_at_unix = std.fmt.parseInt(i64, updated_str, 10) catch 0,
            .current_version = std.fmt.parseInt(u64, ver_str, 10) catch 1,
            .is_shared = std.mem.eql(u8, is_shared_str, "t") or std.mem.eql(u8, is_shared_str, "true"),
            .share_code = share_code_out,
            .share_expires_at_unix = if (expires_raw.len == 0) null else (std.fmt.parseInt(i64, expires_raw, 10) catch null),
            .metadata_jsonb = meta_out,
        };
    }

    pub fn deleteArtifact(self: *Self, user_id: i64, artifact_id: []const u8) !bool {
        var user_buf: [32]u8 = undefined;
        const user_s = try std.fmt.bufPrintZ(&user_buf, "{d}", .{user_id});
        const artifact_id_z = try self.allocator.dupeZ(u8, artifact_id);
        defer self.allocator.free(artifact_id_z);
        const q = try self.buildQuery(
            "DELETE FROM {schema}.artifacts WHERE id = $1::uuid AND user_id = $2",
        );
        defer self.allocator.free(q);
        const params = [_]?[*:0]const u8{ artifact_id_z.ptr, user_s.ptr };
        const lengths = [_]c_int{ @intCast(artifact_id.len), @intCast(user_s.len) };
        const result = self.execParams(q, &params, &lengths) catch |err| switch (err) {
            error.ExecFailed => return false,
            else => return err,
        };
        defer c.PQclear(result);
        const tag = c.PQcmdTuples(result);
        if (tag == null) return false;
        const tag_slice = std.mem.span(tag);
        return tag_slice.len > 0 and !std.mem.eql(u8, tag_slice, "0");
    }

    // ── Sprint 3 (2026-05-28, prod-readiness) — durable trace shares ──
    //
    // Mirrors the artifact-share pattern above:
    //   * `setTraceShare` — INSERT new live share. Errors with the
    //     INSERT-violated unique-partial-index if a live share for
    //     (user, run) already exists (the gateway translates this to
    //     409 Conflict for the FE).
    //   * `clearTraceShare` — soft-delete via `revoked = TRUE`. Allows
    //     a fresh share for the same run without losing the audit row.
    //     Returns true when a row was actually flipped (false on no-op).
    //   * `getTraceByShareCode` — public lookup. Filters revoked +
    //     expired so the conservative-404 surface stays uniform across
    //     "unknown / revoked / expired".
    //   * `countLiveTraceSharesForUser` — D64 spam-cap enforcement
    //     (was an in-memory counter; now backed by PG).

    pub fn setTraceShare(
        self: *Self,
        user_id: i64,
        run_id: []const u8,
        share_code: []const u8,
        events_json: []const u8,
        created_at_unix: i64,
        expires_at_unix: i64,
    ) !void {
        var user_buf: [32]u8 = undefined;
        const user_s = try std.fmt.bufPrintZ(&user_buf, "{d}", .{user_id});
        const run_z = try self.allocator.dupeZ(u8, run_id);
        defer self.allocator.free(run_z);
        const code_z = try self.allocator.dupeZ(u8, share_code);
        defer self.allocator.free(code_z);
        const events_z = try self.allocator.dupeZ(u8, events_json);
        defer self.allocator.free(events_z);
        var created_buf: [32]u8 = undefined;
        const created_s = try std.fmt.bufPrintZ(&created_buf, "{d}", .{created_at_unix});
        var expires_buf: [32]u8 = undefined;
        const expires_s = try std.fmt.bufPrintZ(&expires_buf, "{d}", .{expires_at_unix});

        // `$4::json` (NOT `::jsonb`) — see migrations/0003_trace_shares.sql
        // for the rationale. `JSON` preserves byte-exact input; `JSONB`
        // would normalize (reorder keys, strip whitespace) and break the
        // public-share contract that bytes returned by the public GET
        // match the bytes the gateway emitted at share-create time.
        const q = try self.buildQuery(
            "INSERT INTO {schema}.trace_shares " ++
                "(share_code, user_id, run_id, events_json, created_at_unix, expires_at_unix, revoked) " ++
                "VALUES ($1, $2, $3, $4::json, $5::bigint, $6::bigint, FALSE)",
        );
        defer self.allocator.free(q);
        const params = [_]?[*:0]const u8{
            code_z.ptr, user_s.ptr, run_z.ptr, events_z.ptr, created_s.ptr, expires_s.ptr,
        };
        const lengths = [_]c_int{
            @intCast(share_code.len),  @intCast(user_s.len),    @intCast(run_id.len),
            @intCast(events_json.len), @intCast(created_s.len), @intCast(expires_s.len),
        };
        const result = try self.execParams(q, &params, &lengths);
        c.PQclear(result);
    }

    pub fn clearTraceShare(self: *Self, user_id: i64, run_id: []const u8) !bool {
        var user_buf: [32]u8 = undefined;
        const user_s = try std.fmt.bufPrintZ(&user_buf, "{d}", .{user_id});
        const run_z = try self.allocator.dupeZ(u8, run_id);
        defer self.allocator.free(run_z);

        const q = try self.buildQuery(
            "UPDATE {schema}.trace_shares SET revoked = TRUE " ++
                "WHERE user_id = $1::bigint AND run_id = $2 AND NOT revoked",
        );
        defer self.allocator.free(q);
        const params = [_]?[*:0]const u8{ user_s.ptr, run_z.ptr };
        const lengths = [_]c_int{ @intCast(user_s.len), @intCast(run_id.len) };
        const result = try self.execParams(q, &params, &lengths);
        defer c.PQclear(result);
        const tag = c.PQcmdTuples(result);
        if (tag == null) return false;
        const tag_slice = std.mem.span(tag);
        return tag_slice.len > 0 and !std.mem.eql(u8, tag_slice, "0");
    }

    pub fn getTraceByShareCode(
        self: *Self,
        allocator: std.mem.Allocator,
        share_code: []const u8,
        now_unix: i64,
    ) !?TraceShareRow {
        const q = try self.buildQuery(
            "SELECT share_code, user_id, run_id, events_json::text, " ++
                "created_at_unix, expires_at_unix " ++
                "FROM {schema}.trace_shares " ++
                "WHERE share_code = $1 AND NOT revoked AND expires_at_unix > $2::bigint",
        );
        defer self.allocator.free(q);
        const code_z = try self.allocator.dupeZ(u8, share_code);
        defer self.allocator.free(code_z);
        var now_buf: [32]u8 = undefined;
        const now_s = try std.fmt.bufPrintZ(&now_buf, "{d}", .{now_unix});
        const params = [_]?[*:0]const u8{ code_z.ptr, now_s.ptr };
        const lengths = [_]c_int{ @intCast(share_code.len), @intCast(now_s.len) };
        const result = try self.execParams(q, &params, &lengths);
        defer c.PQclear(result);
        if (c.PQntuples(result) == 0) return null;

        const code_out = try dupeResultValue(allocator, result, 0, 0);
        errdefer allocator.free(code_out);
        const uid_str = try dupeResultValue(allocator, result, 0, 1);
        defer allocator.free(uid_str);
        const run_out = try dupeResultValue(allocator, result, 0, 2);
        errdefer allocator.free(run_out);
        const events_out = try dupeResultValue(allocator, result, 0, 3);
        errdefer allocator.free(events_out);
        const created_str = try dupeResultValue(allocator, result, 0, 4);
        defer allocator.free(created_str);
        const expires_str = try dupeResultValue(allocator, result, 0, 5);
        defer allocator.free(expires_str);

        return .{
            .share_code = code_out,
            .user_id = std.fmt.parseInt(i64, uid_str, 10) catch 0,
            .run_id = run_out,
            .events_json = events_out,
            .created_at_unix = std.fmt.parseInt(i64, created_str, 10) catch 0,
            .expires_at_unix = std.fmt.parseInt(i64, expires_str, 10) catch 0,
        };
    }

    pub fn countLiveTraceSharesForUser(self: *Self, user_id: i64, now_unix: i64) !usize {
        var user_buf: [32]u8 = undefined;
        const user_s = try std.fmt.bufPrintZ(&user_buf, "{d}", .{user_id});
        var now_buf: [32]u8 = undefined;
        const now_s = try std.fmt.bufPrintZ(&now_buf, "{d}", .{now_unix});

        const q = try self.buildQuery(
            "SELECT COUNT(*) FROM {schema}.trace_shares " ++
                "WHERE user_id = $1::bigint AND NOT revoked AND expires_at_unix > $2::bigint",
        );
        defer self.allocator.free(q);
        const params = [_]?[*:0]const u8{ user_s.ptr, now_s.ptr };
        const lengths = [_]c_int{ @intCast(user_s.len), @intCast(now_s.len) };
        const result = try self.execParams(q, &params, &lengths);
        defer c.PQclear(result);
        if (c.PQntuples(result) == 0) return 0;
        const count_str = try dupeResultValue(self.allocator, result, 0, 0);
        defer self.allocator.free(count_str);
        return std.fmt.parseInt(usize, count_str, 10) catch 0;
    }

    // Helper used by both single-row and list paths. Reads the 11-column
    // row layout used by the auth'd SELECTs.
    fn buildArtifactRow(
        allocator: std.mem.Allocator,
        result: *c.PGresult,
        row: c_int,
        user_id: i64,
    ) !ArtifactRow {
        const aid = try dupeResultValue(allocator, result, row, 0);
        errdefer allocator.free(aid);
        const sid_raw = try dupeResultValue(allocator, result, row, 1);
        defer allocator.free(sid_raw);
        const sid_owned: ?[]u8 = if (sid_raw.len == 0) null else try allocator.dupe(u8, sid_raw);
        errdefer if (sid_owned) |s| allocator.free(s);
        const title = try dupeResultValue(allocator, result, row, 2);
        errdefer allocator.free(title);
        const kind = try dupeResultValue(allocator, result, row, 3);
        errdefer allocator.free(kind);
        const created_str = try dupeResultValue(allocator, result, row, 4);
        defer allocator.free(created_str);
        const updated_str = try dupeResultValue(allocator, result, row, 5);
        defer allocator.free(updated_str);
        const ver_str = try dupeResultValue(allocator, result, row, 6);
        defer allocator.free(ver_str);
        const is_shared_str = try dupeResultValue(allocator, result, row, 7);
        defer allocator.free(is_shared_str);
        const share_code_raw = try dupeResultValue(allocator, result, row, 8);
        defer allocator.free(share_code_raw);
        const share_code_owned: ?[]u8 = if (share_code_raw.len == 0) null else try allocator.dupe(u8, share_code_raw);
        errdefer if (share_code_owned) |s| allocator.free(s);
        const expires_raw = try dupeResultValue(allocator, result, row, 9);
        defer allocator.free(expires_raw);
        const meta_out = try dupeResultValue(allocator, result, row, 10);
        errdefer allocator.free(meta_out);

        return .{
            .id = aid,
            .user_id = user_id,
            .session_id = sid_owned,
            .title = title,
            .kind = kind,
            .created_at_unix = std.fmt.parseInt(i64, created_str, 10) catch 0,
            .updated_at_unix = std.fmt.parseInt(i64, updated_str, 10) catch 0,
            .current_version = std.fmt.parseInt(u64, ver_str, 10) catch 1,
            .is_shared = std.mem.eql(u8, is_shared_str, "t") or std.mem.eql(u8, is_shared_str, "true"),
            .share_code = share_code_owned,
            .share_expires_at_unix = if (expires_raw.len == 0) null else (std.fmt.parseInt(i64, expires_raw, 10) catch null),
            .metadata_jsonb = meta_out,
        };
    }
};

// === Postgres UTF-8 write guard (2026-05-21) ===
//
// Postgres rejects any bind parameter that is not valid UTF-8 with
// `ERROR: invalid byte sequence for encoding "UTF8"`. A single stray
// byte — e.g. a bare CP1252 0x94 left behind when a multi-byte UTF-8
// sequence is sliced mid-character — fails the entire statement.
//
// When that statement runs during tenant runtime init (the markdown ->
// Postgres memory sync, upsertMemory with $5 = content), the failure
// propagates all the way out as a hard "tenant runtime init failed" and
// the agent cannot reply at all. Observed 2026-05-21: a memory markdown
// file held a bare 0x94 byte (an em-dash that lost its `e2 80` lead).
//
// This guard validates every bind parameter and, only when one is
// invalid, substitutes each malformed byte with U+FFFD. Valid input —
// the overwhelmingly common case (ASCII ids, well-formed UTF-8 text) —
// takes a zero-allocation fast path. A bad byte now degrades a single
// character instead of bricking the runtime.

/// Copy `input` with every invalid UTF-8 byte replaced by U+FFFD.
/// The result is always valid UTF-8 and NUL-terminated.
fn sanitizeUtf8AllocZ(allocator: std.mem.Allocator, input: []const u8) ![:0]u8 {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    errdefer out.deinit(allocator);
    var i: usize = 0;
    while (i < input.len) {
        const seq_len = std.unicode.utf8ByteSequenceLength(input[i]) catch {
            // Invalid leading byte (continuation byte or illegal range).
            try out.appendSlice(allocator, "\u{FFFD}");
            i += 1;
            continue;
        };
        if (i + seq_len > input.len) {
            // Truncated trailing sequence — not enough bytes remain.
            try out.appendSlice(allocator, "\u{FFFD}");
            i += 1;
            continue;
        }
        if (std.unicode.utf8Decode(input[i .. i + seq_len])) |_| {
            try out.appendSlice(allocator, input[i .. i + seq_len]);
            i += seq_len;
        } else |_| {
            // Valid leading byte but malformed continuation/overlong.
            try out.appendSlice(allocator, "\u{FFFD}");
            i += 1;
        }
    }
    return out.toOwnedSliceSentinel(allocator, 0);
}

/// Result of sanitizeParamsForUtf8. On the fast path (every parameter
/// already valid UTF-8) `params`/`lengths` alias the caller's slices and
/// no memory is owned. On the slow path they point at sanitized copies
/// owned here. Either way the caller MUST call deinit().
const SanitizedParams = struct {
    params: []const ?[*:0]const u8,
    lengths: []const c_int,
    allocator: std.mem.Allocator,
    // Populated only when at least one parameter needed sanitizing.
    owned_params: ?[]?[*:0]const u8 = null,
    owned_lengths: ?[]c_int = null,
    owned_bufs: std.ArrayListUnmanaged([:0]u8) = .empty,

    fn deinit(self: *SanitizedParams) void {
        for (self.owned_bufs.items) |buf| self.allocator.free(buf);
        self.owned_bufs.deinit(self.allocator);
        if (self.owned_params) |p| self.allocator.free(p);
        if (self.owned_lengths) |l| self.allocator.free(l);
    }
};

/// Validate every bind parameter; substitute U+FFFD for any invalid
/// UTF-8. Allocates only when a parameter is actually malformed.
fn sanitizeParamsForUtf8(
    allocator: std.mem.Allocator,
    params: []const ?[*:0]const u8,
    lengths: []const c_int,
) !SanitizedParams {
    var result = SanitizedParams{
        .params = params,
        .lengths = lengths,
        .allocator = allocator,
    };
    errdefer result.deinit();
    for (params, 0..) |param_opt, idx| {
        const param = param_opt orelse continue;
        const len: usize = @intCast(lengths[idx]);
        if (std.unicode.utf8ValidateSlice(param[0..len])) continue;
        if (result.owned_params == null) {
            result.owned_params = try allocator.dupe(?[*:0]const u8, params);
            result.owned_lengths = try allocator.dupe(c_int, lengths);
            result.params = result.owned_params.?;
            result.lengths = result.owned_lengths.?;
        }
        const clean = try sanitizeUtf8AllocZ(allocator, param[0..len]);
        try result.owned_bufs.append(allocator, clean);
        result.owned_params.?[idx] = clean.ptr;
        result.owned_lengths.?[idx] = @intCast(clean.len);
        // Gate on !builtin.is_test to keep canonical CI output clean —
        // same convention as the exec failure logs in this file.
        if (!builtin.is_test) log.warn(
            "postgres write: replaced invalid UTF-8 in bind parameter ${d} ({d} bytes -> {d})",
            .{ idx + 1, len, clean.len },
        );
    }
    return result;
}

test "sanitizeUtf8AllocZ: valid input passes through unchanged" {
    const a = std.testing.allocator;
    const valid = "hello — world ☕ 日本語";
    const out = try sanitizeUtf8AllocZ(a, valid);
    defer a.free(out);
    try std.testing.expectEqualStrings(valid, out);
}

test "sanitizeUtf8AllocZ: bare CP1252 0x94 byte becomes U+FFFD" {
    const a = std.testing.allocator;
    // The exact incident: a markdown memory line with a stray 0x94 byte
    // (an em-dash that lost its `e2 80` lead) bricked tenant runtime init.
    const corrupt = "deep work.\n  \n\x94 keep shipping.";
    const out = try sanitizeUtf8AllocZ(a, corrupt);
    defer a.free(out);
    try std.testing.expect(std.unicode.utf8ValidateSlice(out));
    try std.testing.expectEqualStrings("deep work.\n  \n\u{FFFD} keep shipping.", out);
}

test "sanitizeUtf8AllocZ: truncated trailing multi-byte sequence" {
    const a = std.testing.allocator;
    // "—" is e2 80 94; drop the trailing byte -> dangling lead.
    const corrupt = "tail\xe2\x80";
    const out = try sanitizeUtf8AllocZ(a, corrupt);
    defer a.free(out);
    try std.testing.expect(std.unicode.utf8ValidateSlice(out));
}

test "sanitizeParamsForUtf8: all-valid input takes zero-allocation fast path" {
    const a = std.testing.allocator;
    const p0: [*:0]const u8 = "abc";
    const p1: [*:0]const u8 = "valid — utf8";
    const params = [_]?[*:0]const u8{ p0, p1 };
    const lengths = [_]c_int{ 3, @intCast(std.mem.span(p1).len) };
    var safe = try sanitizeParamsForUtf8(a, &params, &lengths);
    defer safe.deinit();
    try std.testing.expect(safe.owned_params == null);
    try std.testing.expectEqual(@as(usize, 2), safe.params.len);
}

test "sanitizeParamsForUtf8: invalid parameter is sanitized, valid one untouched" {
    const a = std.testing.allocator;
    const good: [*:0]const u8 = "id-123";
    const bad: [*:0]const u8 = "bad\x94byte";
    const params = [_]?[*:0]const u8{ good, bad };
    const lengths = [_]c_int{ 6, 8 };
    var safe = try sanitizeParamsForUtf8(a, &params, &lengths);
    defer safe.deinit();
    try std.testing.expect(safe.owned_params != null);
    // Valid parameter is left aliasing the caller's pointer.
    try std.testing.expectEqual(good, safe.params[0].?);
    // Invalid parameter is replaced with a sanitized, valid-UTF-8 copy.
    try std.testing.expect(safe.params[1].? != bad);
    try std.testing.expect(std.unicode.utf8ValidateSlice(std.mem.span(safe.params[1].?)));
}

fn dupeResultValue(allocator: std.mem.Allocator, result: *c.PGresult, row: c_int, col: c_int) ![]u8 {
    if (c.PQgetisnull(result, row, col) != 0) return allocator.dupe(u8, "");
    const len_raw = c.PQgetlength(result, row, col);
    if (len_raw <= 0) return allocator.dupe(u8, "");
    const len: usize = @intCast(len_raw);
    const val = c.PQgetvalue(result, row, col);
    const src: [*]align(1) const u8 = @ptrCast(val);
    const out = try allocator.alloc(u8, len);
    @memcpy(out, src[0..len]);
    return out;
}

/// Package 2a Task 3 (the miner) — shared row-collection loop for
/// listRecentToolTraces / listRecentToolTracesAllUsers. Both queries
/// project the SAME 3-column shape (run_id, events::text,
/// EXTRACT(EPOCH FROM created_at)::bigint), so one collector avoids
/// duplicating the PQntuples/dupeResultValue/parseInt loop twice.
/// Caller owns the returned slice and each row.
fn collectToolTraceDigestRows(
    allocator: std.mem.Allocator,
    result: *c.PGresult,
) ![]trace_mining.ToolTraceDigestRow {
    const n: usize = @intCast(c.PQntuples(result));
    var out: std.ArrayListUnmanaged(trace_mining.ToolTraceDigestRow) = .empty;
    errdefer {
        for (out.items) |r| r.deinit(allocator);
        out.deinit(allocator);
    }
    try out.ensureTotalCapacity(allocator, n);
    for (0..n) |i| {
        const ri: c_int = @intCast(i);
        const run_id = try dupeResultValue(allocator, result, ri, 0);
        errdefer allocator.free(run_id);
        const events_json = try dupeResultValue(allocator, result, ri, 1);
        errdefer allocator.free(events_json);
        const created_at_raw = try dupeResultValue(allocator, result, ri, 2);
        defer allocator.free(created_at_raw);
        const created_at_unix = std.fmt.parseInt(i64, created_at_raw, 10) catch 0;

        try out.append(allocator, .{
            .run_id = run_id,
            .events_json = events_json,
            .created_at_unix = created_at_unix,
        });
    }
    return out.toOwnedSlice(allocator);
}

/// Row budget for both fleet queries: the FLEET_MAX_TOOLS cap plus ONE
/// probe row. Fetching cap+1 lets fleetMiningStats detect "there was
/// more" (rows > cap → FleetStats.truncated) without a second COUNT
/// query; the probe row itself is never collected or returned. Pinned
/// to the pure module's constant via comptimePrint (the
/// MIN_PATTERN_COUNT precedent) so SQL and types cannot silently
/// drift.
const FLEET_SQL_LIMIT = std.fmt.comptimePrint("{d}", .{trace_mining.FLEET_MAX_TOOLS + 1});

/// SQL-side per-tool fluency census for the bounded fleet endpoint
/// (Manager.fleetMiningStats). Aggregates over jsonb `events` array
/// elements; the SELECT list projects ONLY tool NAME + aggregate counts
/// — never run_id, user_id, label, or arguments (learning contract
/// inv. 5). `success_rate` is derived app-side from uses+successes
/// (matching the pure analyzer's exact f64 arithmetic); p50 is
/// percentile_cont(0.5) over non-negative numeric durations, rounded,
/// COALESCE'd to 0 when a tool logged no usable duration. The
/// malformed-events guard (CASE ... '[]') mirrors the analyzer degrading
/// a bad row to "no events" rather than erroring the whole aggregation.
/// LIMIT (round-2 bound fix): tool names are arbitrary JSON strings, so
/// GROUP BY tool alone is only bounded by corpus cardinality; keep the
/// top FLEET_MAX_TOOLS rows of the deterministic ordering (+1 probe row,
/// see FLEET_SQL_LIMIT).
const FLEET_TOOL_STATS_SQL =
    "SELECT elem->>'tool' AS tool, " ++
    "count(*) AS uses, " ++
    "sum(CASE WHEN jsonb_typeof(elem->'success')='boolean' AND (elem->>'success')='true' THEN 1 ELSE 0 END) AS successes, " ++
    "COALESCE(round(percentile_cont(0.5) WITHIN GROUP (ORDER BY (elem->>'duration_ms')::double precision) " ++
    "FILTER (WHERE jsonb_typeof(elem->'duration_ms')='number' AND (elem->>'duration_ms')::double precision >= 0))::bigint, 0) AS p50 " ++
    "FROM {schema}.tool_traces t " ++
    "CROSS JOIN LATERAL jsonb_array_elements(CASE WHEN jsonb_typeof(t.events)='array' THEN t.events ELSE '[]'::jsonb END) AS elem " ++
    "WHERE t.created_at > NOW() - ($1 || ' days')::interval " ++
    "AND elem->>'kind'='tool_call' AND jsonb_typeof(elem->'tool')='string' " ++
    "GROUP BY elem->>'tool' " ++
    "ORDER BY count(*) DESC, elem->>'tool' ASC " ++
    "LIMIT " ++ FLEET_SQL_LIMIT;

/// SQL-side per-tool failure-count for the bounded fleet endpoint.
/// Groups tool_call failures (success=false) by TOOL alone — no label
/// grouping (inv. 5) — and surfaces only tools that failed at least
/// MIN_PATTERN_COUNT times (the HAVING gate, pinned to the analyzer's
/// constant via comptimePrint so the SQL and the pure module cannot
/// silently drift). LIMIT: same top-FLEET_MAX_TOOLS bound (+1 probe
/// row) as the census query — see FLEET_SQL_LIMIT.
const FLEET_FAILURE_SQL =
    "SELECT elem->>'tool' AS tool, count(*) AS failures " ++
    "FROM {schema}.tool_traces t " ++
    "CROSS JOIN LATERAL jsonb_array_elements(CASE WHEN jsonb_typeof(t.events)='array' THEN t.events ELSE '[]'::jsonb END) AS elem " ++
    "WHERE t.created_at > NOW() - ($1 || ' days')::interval " ++
    "AND elem->>'kind'='tool_call' AND jsonb_typeof(elem->'tool')='string' " ++
    "AND jsonb_typeof(elem->'success')='boolean' AND (elem->>'success')='false' " ++
    "GROUP BY elem->>'tool' " ++
    "HAVING count(*) >= " ++ std.fmt.comptimePrint("{d}", .{trace_mining.MIN_PATTERN_COUNT}) ++ " " ++
    "ORDER BY count(*) DESC, elem->>'tool' ASC " ++
    "LIMIT " ++ FLEET_SQL_LIMIT;

/// Parse a small non-negative count column (bigint text) into usize;
/// NULL/empty/unparseable → 0 (defensive — the fleet aggregates are
/// counts, never identifiers). Frees the intermediate copy.
fn parseFleetCountCol(allocator: std.mem.Allocator, result: *c.PGresult, row: c_int, col: c_int) !usize {
    const raw = try dupeResultValue(allocator, result, row, col);
    defer allocator.free(raw);
    return std.fmt.parseInt(usize, raw, 10) catch 0;
}

/// Parse a bigint text column into u64; NULL/empty/unparseable → 0.
fn parseFleetU64Col(allocator: std.mem.Allocator, result: *c.PGresult, row: c_int, col: c_int) !u64 {
    const raw = try dupeResultValue(allocator, result, row, col);
    defer allocator.free(raw);
    return std.fmt.parseInt(u64, raw, 10) catch 0;
}

/// Collect FLEET_TOOL_STATS_SQL rows (tool, uses, successes, p50) into
/// owned ToolStat values, deriving success_rate app-side. Collects at
/// most `max_rows` rows — the query fetches one probe row past the
/// FLEET_MAX_TOOLS cap purely so the caller can detect truncation, and
/// that probe must never surface. Caller owns the returned slice and
/// each row's `.tool`.
fn collectFleetToolStats(
    allocator: std.mem.Allocator,
    result: *c.PGresult,
    max_rows: usize,
) ![]trace_mining.ToolStat {
    const n: usize = @min(@as(usize, @intCast(c.PQntuples(result))), max_rows);
    var out: std.ArrayListUnmanaged(trace_mining.ToolStat) = .empty;
    errdefer {
        for (out.items) |s| s.deinit(allocator);
        out.deinit(allocator);
    }
    try out.ensureTotalCapacity(allocator, n);
    for (0..n) |i| {
        const ri: c_int = @intCast(i);
        const tool = try dupeResultValue(allocator, result, ri, 0);
        errdefer allocator.free(tool);
        const uses = try parseFleetCountCol(allocator, result, ri, 1);
        const successes = try parseFleetCountCol(allocator, result, ri, 2);
        const p50 = try parseFleetU64Col(allocator, result, ri, 3);
        const success_rate: f64 = if (uses == 0)
            0.0
        else
            @as(f64, @floatFromInt(successes)) / @as(f64, @floatFromInt(uses));
        try out.append(allocator, .{
            .tool = tool,
            .uses = uses,
            .success_rate = success_rate,
            .p50_duration_ms = p50,
        });
    }
    return out.toOwnedSlice(allocator);
}

/// Collect FLEET_FAILURE_SQL rows (tool, count) into owned
/// FleetFailurePattern values. Collects at most `max_rows` rows (the
/// cap+1 probe row is truncation-detection only — see
/// collectFleetToolStats). Caller owns the returned slice and each
/// row's `.tool`.
fn collectFleetFailurePatterns(
    allocator: std.mem.Allocator,
    result: *c.PGresult,
    max_rows: usize,
) ![]trace_mining.FleetFailurePattern {
    const n: usize = @min(@as(usize, @intCast(c.PQntuples(result))), max_rows);
    var out: std.ArrayListUnmanaged(trace_mining.FleetFailurePattern) = .empty;
    errdefer {
        for (out.items) |p| p.deinit(allocator);
        out.deinit(allocator);
    }
    try out.ensureTotalCapacity(allocator, n);
    for (0..n) |i| {
        const ri: c_int = @intCast(i);
        const tool = try dupeResultValue(allocator, result, ri, 0);
        errdefer allocator.free(tool);
        const count = try parseFleetCountCol(allocator, result, ri, 1);
        try out.append(allocator, .{ .tool = tool, .count = count });
    }
    return out.toOwnedSlice(allocator);
}

/// Parse a nullable `EXTRACT(EPOCH FROM ...)::bigint` column into ?i64.
/// Returns null when the SQL value is NULL (S7 extension device registry).
fn parseNullableEpochCol(allocator: std.mem.Allocator, result: *c.PGresult, row: c_int, col: c_int) !?i64 {
    if (c.PQgetisnull(result, row, col) == 1) return null;
    const raw = try dupeResultValue(allocator, result, row, col);
    defer allocator.free(raw);
    if (raw.len == 0) return null;
    return std.fmt.parseInt(i64, raw, 10) catch return error.InvalidTimestamp;
}

fn dupeNullableResultValue(allocator: std.mem.Allocator, result: *c.PGresult, row: c_int, col: c_int) !?[]u8 {
    if (c.PQgetisnull(result, row, col) != 0) return null;
    return try dupeResultValue(allocator, result, row, col);
}

test "dupeResultValue byte-copy path tolerates misaligned source pointers" {
    const allocator = std.testing.allocator;
    const src_buf = [_]u8{ 9, 11, 13, 15, 17 };
    const misaligned_src: [*]align(1) const u8 = @ptrCast(&src_buf[1]);
    const out = try allocator.alloc(u8, 3);
    defer allocator.free(out);
    @memcpy(out, misaligned_src[0..3]);
    try std.testing.expectEqualSlices(u8, &[_]u8{ 11, 13, 15 }, out);
}

test "BRAIN_USER_KEY_FILTER mirrors memory_root.isBrainVisibleKey" {
    // V1.5.1 brain-hygiene cross-check.
    //
    // SQL filter and Zig predicate must agree on every representative key.
    // Drift breaks /brain/* hygiene silently — the SQL filter would let
    // some classes through while the Zig predicate would have hidden them
    // (or vice versa). This test pins the two definitions together.
    //
    // Each entry: (key, expect_visible). expect_visible=false means
    //   - Zig: isBrainVisibleKey(key) returns false
    //   - SQL: BRAIN_USER_KEY_FILTER would exclude this row
    // Both branches must agree per-entry.

    const cases = [_]struct { key: []const u8, expect_visible: bool }{
        // ── User-authored / synthesis (visible) ────────────────────────
        .{ .key = "user_lang", .expect_visible = true },
        .{ .key = "favorite_snack", .expect_visible = true },
        .{ .key = "compose:0123456789abcdef", .expect_visible = true },
        .{ .key = "anything_without_known_prefix", .expect_visible = true },

        // ── Audit (hidden) ─────────────────────────────────────────────
        .{ .key = "autosave_user_1714521600", .expect_visible = false },
        .{ .key = "autosave_assistant_1714521600", .expect_visible = false },
        .{ .key = "session_checkpoint_1714521600", .expect_visible = false },
        .{ .key = "audit_shell/1777419406559181000", .expect_visible = false },

        // ── Continuity (hidden) ────────────────────────────────────────
        .{ .key = "summary_latest/agent:zaki-bot:user:1:thread:main", .expect_visible = false },
        .{ .key = "session_summary/agent:zaki-bot:user:1:thread:main/1714521600", .expect_visible = false },
        .{ .key = "timeline_summary/agent:zaki-bot:user:1:thread:main/1714521600", .expect_visible = false },
        // V1.14.12 (Memory audit Finding 1 fix, 2026-05-19) — durable_fact/*
        // is now brain-VISIBLE. Session-end extraction writes user-authored
        // facts here; previously hidden as "continuity" but actually carries
        // user content. Edit/archive protection still holds via
        // isSystemManagedMemoryKey, independent of brain visibility.
        .{ .key = "durable_fact/1714521600/0", .expect_visible = true },
        .{ .key = "compaction_summary/foo", .expect_visible = false },
        .{ .key = "summary_fallback/foo", .expect_visible = false },
        .{ .key = "compaction_dropped/foo", .expect_visible = false },
        .{ .key = "agent_plan/current/agent:zaki-bot:user:1:thread:main", .expect_visible = false },
        .{ .key = "context_anchor_current", .expect_visible = false },

        // ── Index (hidden) ─────────────────────────────────────────────
        .{ .key = "timeline_index/current", .expect_visible = false },

        // ── Internal (hidden) ──────────────────────────────────────────
        .{ .key = "__tombstone__/some_user_key", .expect_visible = false },
        .{ .key = "__bootstrap.prompt.AGENTS.md", .expect_visible = false },
        .{ .key = "last_hygiene_at", .expect_visible = false },
    };

    // Behavioral check: simulateSqlFilter mirrors the actual SQL semantics
    // by walking the same source-of-truth arrays. If isBrainVisibleKey and
    // simulateSqlFilter ever disagree, drift between Zig and SQL has
    // appeared. Both must derive from BRAIN_HIDDEN_PREFIXES + EXACT_KEYS.
    const simulateSqlFilter = struct {
        fn run(key: []const u8) bool {
            for (memory_root.BRAIN_HIDDEN_PREFIXES) |prefix| {
                if (std.mem.startsWith(u8, key, prefix)) return false;
            }
            for (memory_root.BRAIN_HIDDEN_EXACT_KEYS) |exact| {
                if (std.mem.eql(u8, key, exact)) return false;
            }
            return true;
        }
    }.run;

    for (cases) |tc| {
        const zig_visible = memory_root.isBrainVisibleKey(tc.key);
        const sim_visible = simulateSqlFilter(tc.key);
        try std.testing.expectEqual(tc.expect_visible, zig_visible);
        try std.testing.expectEqual(zig_visible, sim_visible);
    }

    // Structural check on the comptime-derived SQL constant: confirm every
    // prefix from BRAIN_HIDDEN_PREFIXES landed in the regex alternation,
    // and every exact key from BRAIN_HIDDEN_EXACT_KEYS landed in the NOT IN
    // clause. Catches the case where someone breaks the comptime
    // generator so the constant no longer reflects the source arrays.
    const filter = BRAIN_USER_KEY_FILTER;
    try std.testing.expect(std.mem.startsWith(u8, filter, "key !~ '^("));
    try std.testing.expect(std.mem.endsWith(u8, filter, ")"));
    for (memory_root.BRAIN_HIDDEN_PREFIXES) |prefix| {
        // Each prefix must appear in the regex alternation. For the only
        // prefix containing a regex meta-char (`__bootstrap.prompt.`),
        // verify the escaped form is present.
        if (std.mem.indexOf(u8, prefix, ".") != null) {
            // Regex-escape dots manually for the assertion (must match
            // what the comptime generator does).
            var escaped: [256]u8 = undefined;
            var w: usize = 0;
            for (prefix) |ch| {
                if (ch == '.') {
                    escaped[w] = '\\';
                    w += 1;
                    escaped[w] = '.';
                    w += 1;
                } else {
                    escaped[w] = ch;
                    w += 1;
                }
            }
            try std.testing.expect(std.mem.indexOf(u8, filter, escaped[0..w]) != null);
        } else {
            try std.testing.expect(std.mem.indexOf(u8, filter, prefix) != null);
        }
    }
    for (memory_root.BRAIN_HIDDEN_EXACT_KEYS) |exact| {
        try std.testing.expect(std.mem.indexOf(u8, filter, exact) != null);
    }
}

test "V1.6 schema migration applies cleanly + memory_entities round-trips" {
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;
    const test_url = (env_rebrand.getEnvOwnedWithRebrand(allocator, "NULLALIS_POSTGRES_TEST_URL", "NULLCLAW_POSTGRES_TEST_URL") catch return error.SkipZigTest) orelse return error.SkipZigTest;
    defer allocator.free(test_url);

    var schema_buf: [96]u8 = undefined;
    const schema = try std.fmt.bufPrint(&schema_buf, "zaki_bot_test_{d}", .{std.time.microTimestamp()});
    const cfg = config_types.StateConfig{
        .backend = "postgres",
        .postgres = .{
            .connection_string = test_url,
            .schema = schema,
        },
    };

    var mgr = try ManagerImpl.init(allocator, cfg);
    defer mgr.deinit();
    {
        const schema_q = try pg_helpers.quoteIdentifier(allocator, mgr.schemaRaw());
        defer allocator.free(schema_q);
        const drop_q = try std.fmt.allocPrint(allocator, "DROP SCHEMA IF EXISTS {s} CASCADE", .{schema_q});
        defer allocator.free(drop_q);
        const result = try mgr.exec(drop_q);
        c.PQclear(result);
    }
    // First migrate — fresh schema
    try mgr.migrate();

    // Second migrate — must be idempotent (re-running on populated DB)
    try mgr.migrate();

    // ── Verify all V1.6 columns exist on memories ─────────────────────
    const expected_columns = [_][]const u8{
        // V1.6 atomic-fact extraction
        "subject",     "predicate",        "object_key",        "link_type",
        "attribution", "attributed_to",
        // V1.6 Graphiti six-field bi-temporal
           "valid_at",          "invalid_at",
        "expired_at",  "reference_time",   "episodes",
        // V1.6 retrieval + supersession
                 "lemmatized",
        "is_latest",   "parent_memory_id",
        // V1.6 source attribution (M4)
        "source_session_id", "source_snippet",
    };

    for (expected_columns) |col| {
        const q = try std.fmt.allocPrint(
            allocator,
            "SELECT column_name FROM information_schema.columns " ++
                "WHERE table_schema = '{s}' AND table_name = 'memories' " ++
                "AND column_name = '{s}'",
            .{ schema, col },
        );
        defer allocator.free(q);
        const result = try mgr.exec(q);
        defer c.PQclear(result);
        if (c.PQntuples(result) != 1) {
            std.debug.print("V1.6 column missing: {s}\n", .{col});
            return error.MissingColumn;
        }
    }

    // ── Verify memory_entities table exists + round-trips a row ───────
    try mgr.provisionUser(2, "/tmp/nullalis-zaki-bot-test-user-2/workspace");

    const insert_q = try std.fmt.allocPrint(
        allocator,
        "INSERT INTO {s}.memory_entities (id, user_id, name, name_lower, entity_type) " ++
            "VALUES ('ent-1', 2, 'Alex', 'alex', 'PROPER')",
        .{schema},
    );
    defer allocator.free(insert_q);
    const ins_result = try mgr.exec(insert_q);
    c.PQclear(ins_result);

    const select_q = try std.fmt.allocPrint(
        allocator,
        "SELECT id, name, name_lower, entity_type FROM {s}.memory_entities WHERE user_id = 2",
        .{schema},
    );
    defer allocator.free(select_q);
    const sel_result = try mgr.exec(select_q);
    defer c.PQclear(sel_result);
    try std.testing.expectEqual(@as(c_int, 1), c.PQntuples(sel_result));

    const id = try dupeResultValue(allocator, sel_result, 0, 0);
    defer allocator.free(id);
    const name = try dupeResultValue(allocator, sel_result, 0, 1);
    defer allocator.free(name);
    const name_lower = try dupeResultValue(allocator, sel_result, 0, 2);
    defer allocator.free(name_lower);

    try std.testing.expectEqualStrings("ent-1", id);
    try std.testing.expectEqualStrings("Alex", name);
    try std.testing.expectEqualStrings("alex", name_lower);

    // ── Verify the partial indexes exist ───────────────────────────────
    const index_q = try std.fmt.allocPrint(
        allocator,
        "SELECT indexname FROM pg_indexes WHERE schemaname = '{s}' " ++
            "AND tablename IN ('memories', 'memory_entities', 'memory_edges') " ++
            "ORDER BY indexname",
        .{schema},
    );
    defer allocator.free(index_q);
    const idx_result = try mgr.exec(index_q);
    defer c.PQclear(idx_result);

    const expected_indexes = [_][]const u8{
        "idx_edges_source",
        "idx_edges_target",
        "idx_edges_triple",
        "idx_edges_validity",
        "idx_entities_user",
        "idx_entities_vec",
        "idx_memories_is_latest",
        "idx_memories_lemmatized",
        "idx_memories_metadata_subject",
        "idx_memories_object_key",
        "idx_memories_parent",
        "idx_memories_subject",
    };

    var found_indexes: std.StringHashMapUnmanaged(void) = .{};
    defer found_indexes.deinit(allocator);
    const tuples = c.PQntuples(idx_result);
    var i: c_int = 0;
    while (i < tuples) : (i += 1) {
        const idx_name = try dupeResultValue(allocator, idx_result, i, 0);
        try found_indexes.put(allocator, idx_name, {});
    }
    defer {
        var it = found_indexes.keyIterator();
        while (it.next()) |k| allocator.free(k.*);
    }

    for (expected_indexes) |idx_name| {
        if (!found_indexes.contains(idx_name)) {
            std.debug.print("V1.6 index missing: {s}\n", .{idx_name});
            return error.MissingIndex;
        }
    }
}

test "Wave 2 — insertTurnUsage persists http + daemon rows; ON CONFLICT idempotent; usage_rt-independent" {
    // Metering completeness keystone. Proves the durable per-turn ledger:
    //   (1) migration 0004 applies cleanly on a fresh schema,
    //   (2) insertTurnUsage writes a row with the right entry_kind / origin /
    //       tokens / cost / cost_available, reconciled_at NULL,
    //   (3) ON CONFLICT (user_id, turn_key) DO NOTHING is idempotent — a
    //       retried turn never double-inserts (the BFF then reconciles once),
    //   (4) the write is identical whether or not the session had a usage_rt:
    //       the agent calls insertTurnUsage unconditionally, so we exercise
    //       both an http row (usage_rt-backed, settled live) and a daemon row
    //       (usage_rt == null, reconcilable) and assert BOTH land.
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;
    const test_url = (env_rebrand.getEnvOwnedWithRebrand(allocator, "NULLALIS_POSTGRES_TEST_URL", "NULLCLAW_POSTGRES_TEST_URL") catch return error.SkipZigTest) orelse return error.SkipZigTest;
    defer allocator.free(test_url);

    var schema_buf: [96]u8 = undefined;
    const schema = try std.fmt.bufPrint(&schema_buf, "zaki_bot_test_{d}_turnusage", .{std.time.microTimestamp()});
    const cfg = config_types.StateConfig{
        .backend = "postgres",
        .postgres = .{ .connection_string = test_url, .schema = schema },
    };

    var mgr = try ManagerImpl.init(allocator, cfg);
    defer mgr.deinit();
    {
        const schema_q = try pg_helpers.quoteIdentifier(allocator, mgr.schemaRaw());
        defer allocator.free(schema_q);
        const drop_q = try std.fmt.allocPrint(allocator, "DROP SCHEMA IF EXISTS {s} CASCADE", .{schema_q});
        defer allocator.free(drop_q);
        const result = try mgr.exec(drop_q);
        c.PQclear(result);
    }
    // Fresh migrate then re-migrate — 0004 must be idempotent on both.
    try mgr.migrate();
    try mgr.migrate();

    // FK target: users(user_id) must exist before we can insert turn_usage.
    try mgr.provisionUser(7, "/tmp/nullalis-zaki-bot-test-user-7/workspace");

    // (2) daemon row — the metering-hole case (usage_rt == null upstream).
    try mgr.insertTurnUsage(.{
        .user_id = 7,
        .session_key = "agent:zaki-bot:user:7:thread:cron:nightly",
        .turn_key = "r-100-1",
        .entry_kind = "daemon",
        .turn_origin = "scheduler",
        .model = "moonshotai/kimi-k2",
        .input_tokens = 1200,
        .output_tokens = 350,
        .cost_usd = 0.0042,
        .cost_available = true,
    });

    // (4) http row — the live-settled case. Same call shape; usage_rt only
    // affects the in-memory done frame, never this durable write.
    try mgr.insertTurnUsage(.{
        .user_id = 7,
        .session_key = "agent:zaki-bot:user:7:thread:main",
        .turn_key = "r-200-1",
        .entry_kind = "http",
        .turn_origin = "user",
        .model = "anthropic/claude-sonnet-4",
        .input_tokens = 80,
        .output_tokens = 40,
        .cost_usd = 0.0,
        .cost_available = false, // unpriced → BFF settles tokens, not $0
    });

    // Read the daemon row back and assert every field.
    {
        const q = try std.fmt.allocPrint(
            allocator,
            "SELECT session_key, entry_kind, turn_origin, model, input_tokens, " ++
                "output_tokens, cost_usd, cost_available, reconciled_at " ++
                "FROM {s}.turn_usage WHERE user_id = 7 AND turn_key = 'r-100-1'",
            .{schema},
        );
        defer allocator.free(q);
        const result = try mgr.exec(q);
        defer c.PQclear(result);
        try std.testing.expectEqual(@as(c_int, 1), c.PQntuples(result));

        const session_key = try dupeResultValue(allocator, result, 0, 0);
        defer allocator.free(session_key);
        const entry_kind = try dupeResultValue(allocator, result, 0, 1);
        defer allocator.free(entry_kind);
        const origin = try dupeResultValue(allocator, result, 0, 2);
        defer allocator.free(origin);
        const model = try dupeResultValue(allocator, result, 0, 3);
        defer allocator.free(model);
        const input_tokens = try dupeResultValue(allocator, result, 0, 4);
        defer allocator.free(input_tokens);
        const output_tokens = try dupeResultValue(allocator, result, 0, 5);
        defer allocator.free(output_tokens);
        const cost_available = try dupeResultValue(allocator, result, 0, 7);
        defer allocator.free(cost_available);

        try std.testing.expectEqualStrings("agent:zaki-bot:user:7:thread:cron:nightly", session_key);
        try std.testing.expectEqualStrings("daemon", entry_kind);
        try std.testing.expectEqualStrings("scheduler", origin);
        try std.testing.expectEqualStrings("moonshotai/kimi-k2", model);
        try std.testing.expectEqualStrings("1200", input_tokens);
        try std.testing.expectEqualStrings("350", output_tokens);
        try std.testing.expectEqualStrings("t", cost_available);
        // reconciled_at must start NULL (the BFF sweep claims it later).
        try std.testing.expect(c.PQgetisnull(result, 0, 8) == 1);
    }

    // http row landed too, with model + cost_available distinct from daemon.
    {
        const q = try std.fmt.allocPrint(
            allocator,
            "SELECT entry_kind, cost_available FROM {s}.turn_usage " ++
                "WHERE user_id = 7 AND turn_key = 'r-200-1'",
            .{schema},
        );
        defer allocator.free(q);
        const result = try mgr.exec(q);
        defer c.PQclear(result);
        try std.testing.expectEqual(@as(c_int, 1), c.PQntuples(result));
        const entry_kind = try dupeResultValue(allocator, result, 0, 0);
        defer allocator.free(entry_kind);
        const cost_available = try dupeResultValue(allocator, result, 0, 1);
        defer allocator.free(cost_available);
        try std.testing.expectEqualStrings("http", entry_kind);
        try std.testing.expectEqualStrings("f", cost_available);
    }

    // (3) Idempotency: re-insert the daemon turn_key with DIFFERENT values.
    // ON CONFLICT DO NOTHING must keep exactly one row carrying the ORIGINAL
    // values — a retried turn never duplicates and never overwrites.
    try mgr.insertTurnUsage(.{
        .user_id = 7,
        .session_key = "agent:zaki-bot:user:7:thread:cron:nightly",
        .turn_key = "r-100-1",
        .entry_kind = "daemon",
        .turn_origin = "scheduler",
        .model = "moonshotai/kimi-k2",
        .input_tokens = 999999, // would be wrong if it overwrote
        .output_tokens = 999999,
        .cost_usd = 9.99,
        .cost_available = true,
    });
    {
        const q = try std.fmt.allocPrint(
            allocator,
            "SELECT count(*)::int, max(input_tokens)::bigint FROM {s}.turn_usage " ++
                "WHERE user_id = 7 AND turn_key = 'r-100-1'",
            .{schema},
        );
        defer allocator.free(q);
        const result = try mgr.exec(q);
        defer c.PQclear(result);
        const count = try dupeResultValue(allocator, result, 0, 0);
        defer allocator.free(count);
        const max_input = try dupeResultValue(allocator, result, 0, 1);
        defer allocator.free(max_input);
        try std.testing.expectEqualStrings("1", count); // still exactly one row
        try std.testing.expectEqualStrings("1200", max_input); // original preserved
    }

    // Total rows for the user: the daemon + the http row = 2.
    {
        const q = try std.fmt.allocPrint(
            allocator,
            "SELECT count(*)::int FROM {s}.turn_usage WHERE user_id = 7",
            .{schema},
        );
        defer allocator.free(q);
        const result = try mgr.exec(q);
        defer c.PQclear(result);
        const count = try dupeResultValue(allocator, result, 0, 0);
        defer allocator.free(count);
        try std.testing.expectEqualStrings("2", count);
    }

    // Sweep-index sanity: the partial index for the BFF reconciliation sweep
    // exists on the fresh schema.
    {
        const q = try std.fmt.allocPrint(
            allocator,
            "SELECT count(*)::int FROM pg_indexes WHERE schemaname = '{s}' " ++
                "AND indexname = 'idx_turn_usage_sweep'",
            .{schema},
        );
        defer allocator.free(q);
        const result = try mgr.exec(q);
        defer c.PQclear(result);
        const count = try dupeResultValue(allocator, result, 0, 0);
        defer allocator.free(count);
        try std.testing.expectEqualStrings("1", count);
    }

    // Cleanup the throwaway schema.
    {
        const schema_q = try pg_helpers.quoteIdentifier(allocator, mgr.schemaRaw());
        defer allocator.free(schema_q);
        const drop_q = try std.fmt.allocPrint(allocator, "DROP SCHEMA IF EXISTS {s} CASCADE", .{schema_q});
        defer allocator.free(drop_q);
        const result = try mgr.exec(drop_q);
        c.PQclear(result);
    }
}

test "Wave 2 — turn_usage FK CASCADE deletes a user's usage rows on user delete (GDPR purge parity)" {
    // The turn_usage FK to {schema}.users(user_id) ON DELETE CASCADE must
    // make a user's metering rows vanish when the user is purged — same
    // guarantee every other tenant-scoped table relies on. A future schema
    // edit that drops CASCADE would orphan billing rows past account deletion.
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;
    const test_url = (env_rebrand.getEnvOwnedWithRebrand(allocator, "NULLALIS_POSTGRES_TEST_URL", "NULLCLAW_POSTGRES_TEST_URL") catch return error.SkipZigTest) orelse return error.SkipZigTest;
    defer allocator.free(test_url);

    var schema_buf: [96]u8 = undefined;
    const schema = try std.fmt.bufPrint(&schema_buf, "zaki_bot_test_{d}_tucascade", .{std.time.microTimestamp()});
    const cfg = config_types.StateConfig{
        .backend = "postgres",
        .postgres = .{ .connection_string = test_url, .schema = schema },
    };
    var mgr = try ManagerImpl.init(allocator, cfg);
    defer mgr.deinit();
    {
        const schema_q = try pg_helpers.quoteIdentifier(allocator, mgr.schemaRaw());
        defer allocator.free(schema_q);
        const drop_q = try std.fmt.allocPrint(allocator, "DROP SCHEMA IF EXISTS {s} CASCADE", .{schema_q});
        defer allocator.free(drop_q);
        const result = try mgr.exec(drop_q);
        c.PQclear(result);
    }
    try mgr.migrate();
    try mgr.provisionUser(11, "/tmp/nullalis-zaki-bot-test-user-11/workspace");
    try mgr.insertTurnUsage(.{
        .user_id = 11,
        .session_key = "agent:zaki-bot:user:11:thread:main",
        .turn_key = "r-1-1",
        .entry_kind = "daemon",
        .turn_origin = "heartbeat",
        .model = "moonshotai/kimi-k2",
        .input_tokens = 10,
        .output_tokens = 5,
        .cost_usd = 0.0001,
        .cost_available = true,
    });

    // Delete the user row → CASCADE should remove the turn_usage row.
    {
        const del_q = try std.fmt.allocPrint(allocator, "DELETE FROM {s}.users WHERE user_id = 11", .{schema});
        defer allocator.free(del_q);
        const result = try mgr.exec(del_q);
        c.PQclear(result);
    }
    {
        const q = try std.fmt.allocPrint(allocator, "SELECT count(*)::int FROM {s}.turn_usage WHERE user_id = 11", .{schema});
        defer allocator.free(q);
        const result = try mgr.exec(q);
        defer c.PQclear(result);
        const count = try dupeResultValue(allocator, result, 0, 0);
        defer allocator.free(count);
        try std.testing.expectEqualStrings("0", count);
    }
    {
        const schema_q = try pg_helpers.quoteIdentifier(allocator, mgr.schemaRaw());
        defer allocator.free(schema_q);
        const drop_q = try std.fmt.allocPrint(allocator, "DROP SCHEMA IF EXISTS {s} CASCADE", .{schema_q});
        defer allocator.free(drop_q);
        const result = try mgr.exec(drop_q);
        c.PQclear(result);
    }
}

// P0-4 (2026-06-12, Wave A) — static contract for migration 0005. No
// postgres required: pure SQL-string assertions so it runs in every build.
// Guards the acceptance invariant "NO expires_at / NO TTL anywhere" plus the
// FK + status-CHECK shape the durable-approvals logic relies on.
test "P0-4 — migration 0005 has pending_approvals, FK, status CHECK, and NO TTL" {
    var saw: bool = false;
    for (migrations.MIGRATIONS) |m| {
        if (m.version == 5 and std.mem.eql(u8, m.name, "0005_pending_approvals")) {
            saw = true;
            try std.testing.expect(std.mem.indexOf(u8, m.sql, "CREATE TABLE IF NOT EXISTS {schema}.pending_approvals") != null);
            // FK to the parent users row (FK-safe via ensureUserRow).
            try std.testing.expect(std.mem.indexOf(u8, m.sql, "REFERENCES {schema}.users(user_id) ON DELETE CASCADE") != null);
            // Status ledger drives idempotent replay.
            try std.testing.expect(std.mem.indexOf(u8, m.sql, "CHECK (status IN ('pending', 'approved', 'denied'))") != null);
            // ACCEPTANCE: no TTL / no expiry column or sweep anywhere.
            try std.testing.expect(std.mem.indexOf(u8, m.sql, "expires_at") == null);
            try std.testing.expect(std.mem.indexOf(u8, m.sql, "TTL") == null);
        }
    }
    try std.testing.expect(saw);
}

test "P0-4 — durable approvals: persist→rehydrate→resolve→idempotent-replay; FK-safe; no TTL" {
    // The durable-approvals keystone. Proves migration 0005 + the four
    // Manager methods together deliver the acceptance contract:
    //   (1) migration 0005 applies cleanly on a fresh schema (idempotent on
    //       re-migrate),
    //   (2) upsertPendingApproval persists the snapshot FK-safely (it funnels
    //       through ensureUserRow, so the parent users row self-heals),
    //   (3) loadOpenPendingApproval rehydrates the open row after a simulated
    //       restart — exposing the SAME card data,
    //   (4) resolvePendingApproval settles status + resolved_at; once resolved
    //       the open-row read returns null (no double-resume),
    //   (5) pendingApprovalStatus is the idempotent-replay ledger: a repeat
    //       resolve is a no-op and the original status is what replays,
    //   (6) ON CONFLICT (approval_id) DO NOTHING makes a duplicate persist of
    //       the same id a no-op (the FIRST snapshot wins).
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;
    const test_url = (env_rebrand.getEnvOwnedWithRebrand(allocator, "NULLALIS_POSTGRES_TEST_URL", "NULLCLAW_POSTGRES_TEST_URL") catch return error.SkipZigTest) orelse return error.SkipZigTest;
    defer allocator.free(test_url);

    var schema_buf: [96]u8 = undefined;
    const schema = try std.fmt.bufPrint(&schema_buf, "zaki_bot_test_{d}_pendappr", .{std.time.microTimestamp()});
    const cfg = config_types.StateConfig{
        .backend = "postgres",
        .postgres = .{ .connection_string = test_url, .schema = schema },
    };
    var mgr = try ManagerImpl.init(allocator, cfg);
    defer mgr.deinit();
    {
        const schema_q = try pg_helpers.quoteIdentifier(allocator, mgr.schemaRaw());
        defer allocator.free(schema_q);
        const drop_q = try std.fmt.allocPrint(allocator, "DROP SCHEMA IF EXISTS {s} CASCADE", .{schema_q});
        defer allocator.free(drop_q);
        const result = try mgr.exec(drop_q);
        c.PQclear(result);
    }
    // (1) Fresh migrate then re-migrate — 0005 must be idempotent on both.
    try mgr.migrate();
    try mgr.migrate();

    const sk = "agent:zaki-bot:user:42:thread:main";

    // (2) Persist WITHOUT a prior provisionUser call — upsertPendingApproval
    // must self-heal the parent users row via ensureUserRow (FK-safe). The
    // FK target public.zaki_users(42) is seeded by the test harness; with no
    // identity table present (pure-fixture DBs) it proceeds in compat mode.
    try mgr.upsertPendingApproval(.{
        .approval_id = "apr-1",
        .session_key = sk,
        .user_id = 42,
        .tool_name = "shell",
        .tool_call_id = "tc-1",
        .arguments_json = "{\"cmd\":\"ls -la\"}",
        .reason = "supervised_mutating_requires_approval",
        .risk_level = "high",
    });

    // (3) Simulated restart: rehydrate the open row for the session. Same
    // card data must come back.
    {
        var row = (try mgr.loadOpenPendingApproval(allocator, sk)) orelse {
            try std.testing.expect(false);
            unreachable;
        };
        defer row.deinit(allocator);
        try std.testing.expectEqualStrings("apr-1", row.approval_id);
        try std.testing.expectEqualStrings("shell", row.tool_name);
        try std.testing.expectEqualStrings("tc-1", row.tool_call_id.?);
        try std.testing.expectEqualStrings("{\"cmd\":\"ls -la\"}", row.arguments_json);
        try std.testing.expectEqualStrings("supervised_mutating_requires_approval", row.reason);
        try std.testing.expectEqualStrings("high", row.risk_level);
    }

    // (6) Duplicate persist of the SAME approval_id is a no-op (first wins).
    // A different tool_name on the conflicting insert must NOT overwrite.
    try mgr.upsertPendingApproval(.{
        .approval_id = "apr-1",
        .session_key = sk,
        .user_id = 42,
        .tool_name = "DIFFERENT_should_not_win",
        .tool_call_id = null,
        .arguments_json = "{}",
        .reason = "x",
        .risk_level = "low",
    });
    {
        var row = (try mgr.loadOpenPendingApproval(allocator, sk)).?;
        defer row.deinit(allocator);
        try std.testing.expectEqualStrings("shell", row.tool_name); // unchanged
    }

    // (5) Pre-resolve ledger status is 'pending'.
    {
        const st = (try mgr.pendingApprovalStatus(allocator, "apr-1")).?;
        defer allocator.free(st);
        try std.testing.expectEqualStrings("pending", st);
    }

    // (4) Resolve = approve. Status settles, resolved_at stamped.
    try mgr.resolvePendingApproval("apr-1", true, "user");
    {
        const st = (try mgr.pendingApprovalStatus(allocator, "apr-1")).?;
        defer allocator.free(st);
        try std.testing.expectEqualStrings("approved", st);
    }
    // Once resolved, the open-row read returns null (no double-resume).
    try std.testing.expect((try mgr.loadOpenPendingApproval(allocator, sk)) == null);
    // resolved_at must be set.
    {
        const q = try std.fmt.allocPrint(allocator, "SELECT (resolved_at IS NOT NULL)::int, resolved_by FROM {s}.pending_approvals WHERE approval_id = 'apr-1'", .{schema});
        defer allocator.free(q);
        const result = try mgr.exec(q);
        defer c.PQclear(result);
        const resolved_set = try dupeResultValue(allocator, result, 0, 0);
        defer allocator.free(resolved_set);
        try std.testing.expectEqualStrings("1", resolved_set);
        const by = try dupeResultValue(allocator, result, 0, 1);
        defer allocator.free(by);
        try std.testing.expectEqualStrings("user", by);
    }

    // (5) Idempotent replay: a SECOND resolve (even a contradictory deny) is
    // a no-op — the original 'approved' status is preserved, so the gateway
    // replays the original outcome with 200 instead of 409.
    try mgr.resolvePendingApproval("apr-1", false, "user");
    {
        const st = (try mgr.pendingApprovalStatus(allocator, "apr-1")).?;
        defer allocator.free(st);
        try std.testing.expectEqualStrings("approved", st); // NOT 'denied'
    }

    // Unknown id → null status (gateway treats as "not previously resolved").
    try std.testing.expect((try mgr.pendingApprovalStatus(allocator, "apr-nope")) == null);

    {
        const schema_q = try pg_helpers.quoteIdentifier(allocator, mgr.schemaRaw());
        defer allocator.free(schema_q);
        const drop_q = try std.fmt.allocPrint(allocator, "DROP SCHEMA IF EXISTS {s} CASCADE", .{schema_q});
        defer allocator.free(drop_q);
        const result = try mgr.exec(drop_q);
        c.PQclear(result);
    }
}

test "subagent_results upsert is idempotent and loads pending" {
    // Subagent Pass Phase 1 keystone (PG). Proves migration 0007 +
    // the three Manager methods deliver the contract:
    //   (1) upsertSubagentResult persists FK-safely (funnels through ensureUserRow),
    //   (2) ON CONFLICT (result_id) DO NOTHING makes a duplicate persist a no-op,
    //   (3) loadPendingSubagentResults returns the pending row,
    //   (4) markSubagentResultDelivered flips status; subsequent load returns 0 rows.
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;
    const test_url = (env_rebrand.getEnvOwnedWithRebrand(allocator, "NULLALIS_POSTGRES_TEST_URL", "NULLCLAW_POSTGRES_TEST_URL") catch return error.SkipZigTest) orelse return error.SkipZigTest;
    defer allocator.free(test_url);

    var schema_buf: [96]u8 = undefined;
    const schema = try std.fmt.bufPrint(&schema_buf, "zaki_bot_test_{d}_subares", .{std.time.microTimestamp()});
    const cfg = config_types.StateConfig{
        .backend = "postgres",
        .postgres = .{ .connection_string = test_url, .schema = schema },
    };
    var mgr = try ManagerImpl.init(allocator, cfg);
    defer mgr.deinit();
    {
        const schema_q = try pg_helpers.quoteIdentifier(allocator, mgr.schemaRaw());
        defer allocator.free(schema_q);
        const drop_q = try std.fmt.allocPrint(allocator, "DROP SCHEMA IF EXISTS {s} CASCADE", .{schema_q});
        defer allocator.free(drop_q);
        const result = try mgr.exec(drop_q);
        c.PQclear(result);
    }
    // Migrate: 0007 must apply cleanly (idempotent on re-migrate).
    try mgr.migrate();
    try mgr.migrate();

    const input = SubagentResultInput{
        .result_id = "subagent:7",
        .user_id = 42,
        .session_key = "agent:zaki-bot:user:42:main",
        .task_id = 7,
        .result_json = "{\"status\":\"completed\",\"text\":\"done\"}",
    };

    // (1) Persist WITHOUT a prior provisionUser call — must self-heal via ensureUserRow.
    try mgr.upsertSubagentResult(input);

    // (2) Duplicate persist is a no-op (ON CONFLICT DO NOTHING).
    try mgr.upsertSubagentResult(input);

    // (3) Load pending: exactly one row with the right task_id.
    const rows = try mgr.loadPendingSubagentResults(allocator, 42);
    defer {
        for (rows) |r| r.deinit(allocator);
        allocator.free(rows);
    }
    try std.testing.expectEqual(@as(usize, 1), rows.len);
    try std.testing.expectEqual(@as(i64, 7), rows[0].task_id);
    try std.testing.expectEqualStrings("subagent:7", rows[0].result_id);
    try std.testing.expectEqualStrings("agent:zaki-bot:user:42:main", rows[0].session_key);

    // (4) Mark delivered → subsequent load returns 0 rows.
    try mgr.markSubagentResultDelivered("subagent:7");
    const rows2 = try mgr.loadPendingSubagentResults(allocator, 42);
    defer allocator.free(rows2);
    try std.testing.expectEqual(@as(usize, 0), rows2.len);

    {
        const schema_q = try pg_helpers.quoteIdentifier(allocator, mgr.schemaRaw());
        defer allocator.free(schema_q);
        const drop_q = try std.fmt.allocPrint(allocator, "DROP SCHEMA IF EXISTS {s} CASCADE", .{schema_q});
        defer allocator.free(drop_q);
        const result = try mgr.exec(drop_q);
        c.PQclear(result);
    }
}

test "S1b getSubagentResultText recovers durable answer text regardless of delivered status" {
    // Subagent Pass S1b keystone (PG). Proves the durable recovery path that
    // makes task_get's promise true:
    //   (1) getSubagentResultText parses subagent_results.result_json and
    //       returns the SubagentResult .text by (user_id, task_id);
    //   (2) it returns the SAME text AFTER markSubagentResultDelivered — the
    //       durable row survives delivery (mark-delivered is an UPDATE, not a
    //       DELETE), which is exactly what lets a follow-up turn recover a
    //       prior batch's output instead of re-spawning;
    //   (3) a miss (wrong task_id / wrong user_id) returns null, not an error.
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;
    const test_url = (env_rebrand.getEnvOwnedWithRebrand(allocator, "NULLALIS_POSTGRES_TEST_URL", "NULLCLAW_POSTGRES_TEST_URL") catch return error.SkipZigTest) orelse return error.SkipZigTest;
    defer allocator.free(test_url);

    var schema_buf: [96]u8 = undefined;
    const schema = try std.fmt.bufPrint(&schema_buf, "zaki_bot_test_{d}_subrec", .{std.time.microTimestamp()});
    const cfg = config_types.StateConfig{
        .backend = "postgres",
        .postgres = .{ .connection_string = test_url, .schema = schema },
    };
    var mgr = try ManagerImpl.init(allocator, cfg);
    defer mgr.deinit();
    {
        const schema_q = try pg_helpers.quoteIdentifier(allocator, mgr.schemaRaw());
        defer allocator.free(schema_q);
        const drop_q = try std.fmt.allocPrint(allocator, "DROP SCHEMA IF EXISTS {s} CASCADE", .{schema_q});
        defer allocator.free(drop_q);
        const result = try mgr.exec(drop_q);
        c.PQclear(result);
    }
    try mgr.migrate();

    // Persist a full SubagentResult JSON (as completeTask does) for task 7.
    const input = SubagentResultInput{
        .result_id = "subagent:7",
        .user_id = 42,
        .session_key = "agent:zaki-bot:user:42:main",
        .task_id = 7,
        .result_json = "{\"status\":\"completed\",\"text\":\"the treaty was signed in 1648\"}",
    };
    try mgr.upsertSubagentResult(input);

    // (1) Recover the answer text by (user_id, task_id) while still pending.
    const before = try mgr.getSubagentResultText(allocator, 42, 7);
    try std.testing.expect(before != null);
    defer if (before) |b| allocator.free(b);
    try std.testing.expectEqualStrings("the treaty was signed in 1648", before.?);

    // (2) Deliver, then recover AGAIN — the durable text must survive delivery.
    try mgr.markSubagentResultDelivered("subagent:7");
    // Sanity: it is no longer in the pending set (mirrors the delivered flip).
    const pending = try mgr.loadPendingSubagentResults(allocator, 42);
    defer allocator.free(pending);
    try std.testing.expectEqual(@as(usize, 0), pending.len);
    // But getSubagentResultText (status-agnostic) still returns the answer.
    const after = try mgr.getSubagentResultText(allocator, 42, 7);
    try std.testing.expect(after != null);
    defer if (after) |a| allocator.free(a);
    try std.testing.expectEqualStrings("the treaty was signed in 1648", after.?);

    // (3) Misses resolve to null (wrong task_id and wrong user_id), not error.
    try std.testing.expect((try mgr.getSubagentResultText(allocator, 42, 999)) == null);
    try std.testing.expect((try mgr.getSubagentResultText(allocator, 999, 7)) == null);

    {
        const schema_q = try pg_helpers.quoteIdentifier(allocator, mgr.schemaRaw());
        defer allocator.free(schema_q);
        const drop_q = try std.fmt.allocPrint(allocator, "DROP SCHEMA IF EXISTS {s} CASCADE", .{schema_q});
        defer allocator.free(drop_q);
        const result = try mgr.exec(drop_q);
        c.PQclear(result);
    }
}

