    const events_json = "[{\"kind\":\"tool_call\",\"tool\":\"web_search\",\"success\":true,\"duration_ms\":420}]";
    try mgr.insertToolTraceEvents(42, "r-1-1", events_json);
    try mgr.insertToolTraceEvents(42, "r-2-1", events_json);
