    try mgr.insertToolTraceEvents(7, "r-1-1", events_json);
    try mgr.insertToolTraceEvents(7, "r-2-1", events_json);

    // Backdate r-1-1's created_at to 30 days ago (outside a 7-day window).
    {
        const q = try std.fmt.allocPrint(
