/// Test helper: seed one tool_traces row carrying a single tool_call
/// event (with a per-tenant secret label) for the fleet-aggregation
/// tests. `mgr` is `anytype` so this compiles only when referenced (PG
/// builds).
fn seedFleetToolCall(
    mgr: anytype,
    allocator: std.mem.Allocator,
    user_id: i64,
    run_id: []const u8,
    tool: []const u8,
    success: bool,
    duration_ms: i64,
    label: []const u8,
) !void {
    const events = try std.fmt.allocPrint(
        allocator,
        "[{{\"kind\":\"tool_call\",\"tool\":\"{s}\",\"success\":{s},\"duration_ms\":{d},\"label\":\"{s}\"}}]",
        .{ tool, if (success) "true" else "false", duration_ms, label },
    );
    defer allocator.free(events);
    try mgr.insertToolTraceEvents(user_id, run_id, events);
}

fn findFleetStat(stats: []const trace_mining.ToolStat, tool: []const u8) ?trace_mining.ToolStat {
    for (stats) |s| {
        if (std.mem.eql(u8, s.tool, tool)) return s;
    }
    return null;
}

test "tool_traces: fleetMiningStats aggregates SQL-side across users — shapes only, failure gate, p50 median (bounded-materialization fix)" {
    // TDD keystone for the HIGH-severity unbounded-materialization fix.
    // Seeds tool_traces for TWO tenants with distinct secret labels and
    // varied durations/success, then calls the BOUNDED fleetMiningStats
    // path and asserts: (a) correct aggregated shapes across BOTH users,
    // (b) neither tenant's label/sentinel bleeds into any returned field
    // (FleetStats has no run_id/label field at all — inv. 5 by
    // construction), (c) failure_patterns include only tools that failed
    // >= MIN_PATTERN_COUNT (3) times, and p50 is the true median of a
    // known set ({10,20,30,40,50} -> 30).
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;
    const test_url = (env_rebrand.getEnvOwnedWithRebrand(allocator, "NULLALIS_POSTGRES_TEST_URL", "NULLCLAW_POSTGRES_TEST_URL") catch return error.SkipZigTest) orelse return error.SkipZigTest;
    defer allocator.free(test_url);

    var schema_buf: [96]u8 = undefined;
    const schema = try std.fmt.bufPrint(&schema_buf, "zaki_bot_test_{d}_fleetagg", .{std.time.microTimestamp()});
    const cfg = config_types.StateConfig{
        .backend = "postgres",
        .postgres = .{ .connection_string = test_url, .schema = schema },
    };
    var mgr = try ManagerImpl.init(allocator, cfg);
    defer mgr.deinit();
    try mgr.migrate();
    // Drop the throwaway schema on teardown even if an assertion below
    // returns early (the gateway D11 fixture idiom).
    defer mgr.dropSchemaForTests() catch {};

    const A: i64 = 987101;
    const B: i64 = 987102;
    const SENTINEL_A = "AGG_TENANT_A_SECRET_QUUX";
    const SENTINEL_B = "AGG_TENANT_B_SECRET_THUD";

    // alpha_tool — cross-user, all success; durations combine to
    // {10,20,30,40,50} => uses 5, success_rate 1.0, p50 30.
    try seedFleetToolCall(&mgr, allocator, A, "a-alpha-1", "alpha_tool", true, 10, SENTINEL_A);
    try seedFleetToolCall(&mgr, allocator, A, "a-alpha-2", "alpha_tool", true, 30, SENTINEL_A);
    try seedFleetToolCall(&mgr, allocator, A, "a-alpha-3", "alpha_tool", true, 50, SENTINEL_A);
    try seedFleetToolCall(&mgr, allocator, B, "b-alpha-1", "alpha_tool", true, 20, SENTINEL_B);
    try seedFleetToolCall(&mgr, allocator, B, "b-alpha-2", "alpha_tool", true, 40, SENTINEL_B);

    // beta_tool — cross-user failures (2 from A + 1 from B = 3, at the
    // gate) plus 1 success from A => uses 4, success_rate 0.25.
    try seedFleetToolCall(&mgr, allocator, A, "a-beta-1", "beta_tool", false, 100, SENTINEL_A);
    try seedFleetToolCall(&mgr, allocator, A, "a-beta-2", "beta_tool", false, 100, SENTINEL_A);
    try seedFleetToolCall(&mgr, allocator, A, "a-beta-3", "beta_tool", true, 100, SENTINEL_A);
    try seedFleetToolCall(&mgr, allocator, B, "b-beta-1", "beta_tool", false, 100, SENTINEL_B);

    // gamma_tool — only 2 failures (below the gate) => present in
    // tool_stats but NOT in failure_patterns.
    try seedFleetToolCall(&mgr, allocator, A, "a-gamma-1", "gamma_tool", false, 5, SENTINEL_A);
    try seedFleetToolCall(&mgr, allocator, A, "a-gamma-2", "gamma_tool", false, 5, SENTINEL_A);

    var stats = try mgr.fleetMiningStats(allocator, 7);
    defer stats.deinit(allocator);

    // ── (a) aggregated tool_stats across BOTH users.
    try std.testing.expectEqual(@as(usize, 3), stats.tool_stats.len);

    const alpha = findFleetStat(stats.tool_stats, "alpha_tool") orelse return error.MissingAlpha;
    try std.testing.expectEqual(@as(usize, 5), alpha.uses); // 3 from A + 2 from B
    try std.testing.expectApproxEqAbs(@as(f64, 1.0), alpha.success_rate, 0.0001);
    try std.testing.expectEqual(@as(u64, 30), alpha.p50_duration_ms); // median {10,20,30,40,50}

    const beta = findFleetStat(stats.tool_stats, "beta_tool") orelse return error.MissingBeta;
    try std.testing.expectEqual(@as(usize, 4), beta.uses);
    try std.testing.expectApproxEqAbs(@as(f64, 0.25), beta.success_rate, 0.0001);

    const gamma = findFleetStat(stats.tool_stats, "gamma_tool") orelse return error.MissingGamma;
    try std.testing.expectEqual(@as(usize, 2), gamma.uses);
    try std.testing.expectApproxEqAbs(@as(f64, 0.0), gamma.success_rate, 0.0001);

    // ── (c) failure_patterns: only beta_tool clears the >= 3 gate.
    try std.testing.expectEqual(@as(usize, 1), stats.failure_patterns.len);
    try std.testing.expectEqualStrings("beta_tool", stats.failure_patterns[0].tool);
    try std.testing.expectEqual(@as(usize, 3), stats.failure_patterns[0].count); // 2 from A + 1 from B

    // ── (b) NEITHER tenant's secret label appears in ANY returned field.
    for (stats.tool_stats) |s| {
        try std.testing.expect(std.mem.indexOf(u8, s.tool, SENTINEL_A) == null);
        try std.testing.expect(std.mem.indexOf(u8, s.tool, SENTINEL_B) == null);
    }
    for (stats.failure_patterns) |p| {
        try std.testing.expect(std.mem.indexOf(u8, p.tool, SENTINEL_A) == null);
        try std.testing.expect(std.mem.indexOf(u8, p.tool, SENTINEL_B) == null);
    }

    // ── (d) 3 distinct tools is far under FLEET_MAX_TOOLS: nothing was
    // cut, and the report says so.
    try std.testing.expect(!stats.truncated);
}

test "tool_traces: fleetMiningStats is HARD-bounded — top-FLEET_MAX_TOOLS per list, truncated honesty bit (round-2 fix)" {
    // Operator-found round-2 defect (post-#155): the "bounded"
    // aggregation still returned EVERY distinct tool — no LIMIT on
    // either fleet query — and tool names in trace events are arbitrary
    // JSON strings, so distinct-tool cardinality (and with it the
    // response body and the app-side row collection) grows with the
    // corpus. O(distinct tools) was not a real bound. The fix caps both
    // lists at the top FLEET_MAX_TOOLS rows of their deterministic
    // ordering (count DESC, tool ASC) and reports the cut via
    // FleetStats.truncated.
    //
    // Seeds FLEET_MAX_TOOLS+6 distinct tools (one high-use success tool
    // + cap+5 failing tools that all clear MIN_PATTERN_COUNT) and pins:
    // exact cap lengths on BOTH lists, truncated=true, the top-by-count
    // row surviving, and the ordering TAIL being what got cut.
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;
    const test_url = (env_rebrand.getEnvOwnedWithRebrand(allocator, "NULLALIS_POSTGRES_TEST_URL", "NULLCLAW_POSTGRES_TEST_URL") catch return error.SkipZigTest) orelse return error.SkipZigTest;
    defer allocator.free(test_url);

    var schema_buf: [96]u8 = undefined;
    const schema = try std.fmt.bufPrint(&schema_buf, "zaki_bot_test_{d}_fleetcap", .{std.time.microTimestamp()});
    const cfg = config_types.StateConfig{
        .backend = "postgres",
        .postgres = .{ .connection_string = test_url, .schema = schema },
    };
    var mgr = try ManagerImpl.init(allocator, cfg);
    defer mgr.deinit();
    try mgr.migrate();
    defer mgr.dropSchemaForTests() catch {};

    const cap = trace_mining.FLEET_MAX_TOOLS;

    // hot_tool — 5 successes (highest uses in the corpus): the cap must
    // keep the TOP of the ordering, so this row has to survive.
    try mgr.insertToolTraceEvents(987201, "cap-hot-1", "[" ++
        ("{\"kind\":\"tool_call\",\"tool\":\"hot_tool\",\"success\":true,\"duration_ms\":1}," ** 4) ++
        "{\"kind\":\"tool_call\",\"tool\":\"hot_tool\",\"success\":true,\"duration_ms\":1}]");

    // cap+5 distinct failing tools (cap_tool_000 .. cap_tool_104 for
    // cap=100, zero-padded so tool-ASC order == numeric order). One
    // event per tool per run, three failed runs across two tenants →
    // every cap_tool_* has uses=3 and failures=3 (exactly
    // MIN_PATTERN_COUNT, so ALL of them clear the failure gate).
    var events_buf: std.ArrayListUnmanaged(u8) = .empty;
    defer events_buf.deinit(allocator);
    try events_buf.append(allocator, '[');
    var ti: usize = 0;
    while (ti < cap + 5) : (ti += 1) {
        if (ti > 0) try events_buf.append(allocator, ',');
        try events_buf.writer(allocator).print(
            "{{\"kind\":\"tool_call\",\"tool\":\"cap_tool_{d:0>3}\",\"success\":false,\"duration_ms\":10}}",
            .{ti},
        );
    }
    try events_buf.append(allocator, ']');
    try mgr.insertToolTraceEvents(987201, "cap-run-1", events_buf.items);
    try mgr.insertToolTraceEvents(987202, "cap-run-2", events_buf.items);
    try mgr.insertToolTraceEvents(987201, "cap-run-3", events_buf.items);

    var stats = try mgr.fleetMiningStats(allocator, 7);
    defer stats.deinit(allocator);

    // Hard cap on BOTH lists + the honesty bit.
    try std.testing.expectEqual(cap, stats.tool_stats.len);
    try std.testing.expectEqual(cap, stats.failure_patterns.len);
    try std.testing.expect(stats.truncated);

    // The cut respects the deterministic ordering. tool_stats is
    // uses DESC, tool ASC: hot_tool (uses=5) leads, and the kept
    // cap_tool_* rows are the ALPHABETIC HEAD of the tie group — the
    // highest-indexed name is exactly what the cap dropped.
    try std.testing.expectEqualStrings("hot_tool", stats.tool_stats[0].tool);
    try std.testing.expectEqual(@as(usize, 5), stats.tool_stats[0].uses);
    try std.testing.expect(findFleetStat(stats.tool_stats, "cap_tool_000") != null);
    try std.testing.expect(findFleetStat(stats.tool_stats, "cap_tool_104") == null);

    // failure_patterns (all count=3 → pure tool-ASC): keeps
    // cap_tool_000 first; the beyond-cap tail never appears.
    try std.testing.expectEqualStrings("cap_tool_000", stats.failure_patterns[0].tool);
    for (stats.failure_patterns) |p| {
        try std.testing.expectEqual(@as(usize, 3), p.count);
        try std.testing.expect(!std.mem.eql(u8, p.tool, "cap_tool_104"));
    }
}

test "P1-5 — messages persist+reload tool_calls/reasoning (with AND without); old rows unchanged" {
    // P1-5 acceptance keystone (PG): a reloaded transcript carries tool_calls
    // + reasoning for a turn that had them, AND a turn without them loads
    // exactly as before (flat text, NULL extras). Also proves strict backward
    // compatibility: the legacy `saveSessionMessage` (no extras) writes a row
    // that reads back with null tool_calls/reasoning — identical to a
    // pre-migration-0006 row.
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;
    const test_url = (env_rebrand.getEnvOwnedWithRebrand(allocator, "NULLALIS_POSTGRES_TEST_URL", "NULLCLAW_POSTGRES_TEST_URL") catch return error.SkipZigTest) orelse return error.SkipZigTest;
    defer allocator.free(test_url);

    var schema_buf: [96]u8 = undefined;
    const schema = try std.fmt.bufPrint(&schema_buf, "zaki_bot_test_{d}_p1_5fidelity", .{std.time.microTimestamp()});
    const cfg = config_types.StateConfig{
        .backend = "postgres",
        .postgres = .{ .connection_string = test_url, .schema = schema },
    };
    var mgr = try ManagerImpl.init(allocator, cfg);
    defer mgr.deinit();
    {
        const schema_q = try pg_helpers.quoteIdentifier(allocator, mgr.schemaRaw());
        defer allocator.free(schema_q);
        const drop_q = try std.fmt.allocPrint(allocator, "DROP SCHEMA IF EXISTS {s} CASCADE", .{schema_q});
        defer allocator.free(drop_q);
        const result = try mgr.exec(drop_q);
        c.PQclear(result);
    }
    defer {
        if (pg_helpers.quoteIdentifier(allocator, mgr.schemaRaw())) |schema_q| {
            defer allocator.free(schema_q);
            if (std.fmt.allocPrint(allocator, "DROP SCHEMA IF EXISTS {s} CASCADE", .{schema_q})) |drop_q| {
                defer allocator.free(drop_q);
                if (mgr.exec(drop_q)) |result| {
                    c.PQclear(result);
                } else |_| {}
            } else |_| {}
        } else |_| {}
    }
    try mgr.migrate();

    const uid: i64 = 77;
    const sid = "agent:zaki-bot:user:77:thread:main";
    const tc_json = "[{\"id\":\"call_1\",\"name\":\"shell\",\"arguments\":\"{\\\"cmd\\\":\\\"ls\\\"}\"}]";
    const reasoning = "the user asked to list files, so I will run ls";

    // (a) A user row — no extras (the common case). Then an assistant turn
    // WITH tool_calls + reasoning. Then an assistant turn WITHOUT (flat text).
    try mgr.saveSessionMessage(uid, sid, "user", "list the files");
    try mgr.saveSessionMessageRich(uid, sid, "assistant", "running ls", tc_json, reasoning);
    try mgr.saveSessionMessage(uid, sid, "assistant", "here are your files"); // legacy path → NULL extras

    const entries = try mgr.loadSessionMessages(allocator, uid, sid);
    defer memory_root.freeMessages(allocator, entries);
    try std.testing.expectEqual(@as(usize, 3), entries.len);

    // Row 0: user — flat, no extras.
    try std.testing.expectEqualStrings("user", entries[0].role);
    try std.testing.expectEqualStrings("list the files", entries[0].content);
    try std.testing.expect(entries[0].tool_calls_json == null);
    try std.testing.expect(entries[0].reasoning == null);

    // Row 1: assistant WITH tool_calls + reasoning — round-trips verbatim.
    try std.testing.expectEqualStrings("assistant", entries[1].role);
    try std.testing.expectEqualStrings("running ls", entries[1].content);
    try std.testing.expect(entries[1].tool_calls_json != null);
    try std.testing.expect(entries[1].reasoning != null);
    try std.testing.expectEqualStrings(reasoning, entries[1].reasoning.?);
    // tool_calls is a JSONB column → PG may normalize whitespace; assert the
    // structural payload survived (id/name/arguments all present) rather than
    // a byte-for-byte match.
    try std.testing.expect(std.mem.indexOf(u8, entries[1].tool_calls_json.?, "call_1") != null);
    try std.testing.expect(std.mem.indexOf(u8, entries[1].tool_calls_json.?, "shell") != null);
    try std.testing.expect(std.mem.indexOf(u8, entries[1].tool_calls_json.?, "ls") != null);

    // Row 2: assistant WITHOUT extras — loads exactly as a pre-0006 flat row.
    try std.testing.expectEqualStrings("assistant", entries[2].role);
    try std.testing.expectEqualStrings("here are your files", entries[2].content);
    try std.testing.expect(entries[2].tool_calls_json == null);
    try std.testing.expect(entries[2].reasoning == null);

    // (b) Backward-compat at the SQL level: an OLD pod's INSERT names only
    // (id, session_id, user_id, role, source, content) and never references
    // the new columns — simulate it directly to prove the new columns are
    // invisible to old code and default NULL. The new loadSessionMessages
    // reads it back with null extras.
    {
        try mgr.ensureSession(uid, sid);
        const q = try mgr.buildQuery(
            "INSERT INTO {schema}.messages (id, session_id, user_id, role, source, content) " ++
                "VALUES (encode(gen_random_bytes(16),'hex'), " ++
                "(SELECT id FROM {schema}.sessions WHERE session_key = $2 AND user_id = $1), $1, 'user', 'app', $3)",
        );
        defer allocator.free(q);
        var user_buf: [32]u8 = undefined;
        const user_s = try std.fmt.bufPrintZ(&user_buf, "{d}", .{uid});
        const sid_z = try allocator.dupeZ(u8, sid);
        defer allocator.free(sid_z);
        const content_z = try allocator.dupeZ(u8, "old-pod write");
        defer allocator.free(content_z);
        const params = [_]?[*:0]const u8{ user_s.ptr, sid_z, content_z };
        const lengths = [_]c_int{ @intCast(user_s.len), @intCast(sid.len), @intCast("old-pod write".len) };
        const r = try mgr.execParams(q, &params, &lengths);
        c.PQclear(r);
    }
    const entries2 = try mgr.loadSessionMessages(allocator, uid, sid);
    defer memory_root.freeMessages(allocator, entries2);
    try std.testing.expectEqual(@as(usize, 4), entries2.len);
    // The old-pod row is last (created_at ASC, id ASC after the prior three);
    // find it by content and assert null extras.
    var saw_old_pod = false;
    for (entries2) |e| {
        if (std.mem.eql(u8, e.content, "old-pod write")) {
            saw_old_pod = true;
            try std.testing.expect(e.tool_calls_json == null);
            try std.testing.expect(e.reasoning == null);
        }
    }
    try std.testing.expect(saw_old_pod);
}

// D62 (2026-05-25) — wire migrations.run() from zaki_state.migrate.
//
// Static contract test: verifies `migrations.MIGRATIONS` is non-empty,
// contains the artifacts entry, and that the SQL embedded for 0002 is
// idempotent (CREATE TABLE IF NOT EXISTS) so it's safe to apply during
// the dual-path window where the legacy inline loop also creates the
// same tables. No postgres required — pure compile-time / SQL-string
// assertions, so it runs in every build (including non-postgres).
test "D62 — migrations framework is wired with idempotent 0002 entry" {
    // The MIGRATIONS array must have the artifacts entry registered.
    var saw_artifacts = false;
    for (migrations.MIGRATIONS) |m| {
        if (m.version == 2 and std.mem.eql(u8, m.name, "0002_artifacts")) {
            saw_artifacts = true;
            // Dual-path idempotency: 0002's CREATE TABLE statements must
            // use IF NOT EXISTS so the migration is safe to re-apply
            // against a DB where the legacy inline loop in
            // `zaki_state.zig::migrate` already created the same tables.
            // After the inline block is deleted (D62 follow-up), this
            // guard can be dropped and the migration becomes a true diff.
            try std.testing.expect(std.mem.indexOf(u8, m.sql, "CREATE TABLE IF NOT EXISTS {schema}.artifacts") != null);
            try std.testing.expect(std.mem.indexOf(u8, m.sql, "CREATE TABLE IF NOT EXISTS {schema}.artifact_versions") != null);
            // Indexes also guarded with IF NOT EXISTS.
            try std.testing.expect(std.mem.indexOf(u8, m.sql, "CREATE INDEX IF NOT EXISTS idx_artifacts_user_updated") != null);
            try std.testing.expect(std.mem.indexOf(u8, m.sql, "CREATE INDEX IF NOT EXISTS idx_artifacts_share_code") != null);
            try std.testing.expect(std.mem.indexOf(u8, m.sql, "CREATE INDEX IF NOT EXISTS idx_artifact_versions_artifact_version") != null);
        }
    }
    try std.testing.expect(saw_artifacts);
}

test "D62 — migrate() populates schema_migrations with every registered version" {
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;
    const test_url = (env_rebrand.getEnvOwnedWithRebrand(allocator, "NULLALIS_POSTGRES_TEST_URL", "NULLCLAW_POSTGRES_TEST_URL") catch return error.SkipZigTest) orelse return error.SkipZigTest;
    defer allocator.free(test_url);

    var schema_buf: [96]u8 = undefined;
    const schema = try std.fmt.bufPrint(&schema_buf, "zaki_bot_test_{d}_d62", .{std.time.microTimestamp()});
    const cfg = config_types.StateConfig{
        .backend = "postgres",
        .postgres = .{
            .connection_string = test_url,
            .schema = schema,
        },
    };

    var mgr = try ManagerImpl.init(allocator, cfg);
    defer mgr.deinit();

    // Fresh schema — drop anything left over from a previous test run.
    {
        const schema_q = try pg_helpers.quoteIdentifier(allocator, mgr.schemaRaw());
        defer allocator.free(schema_q);
        const drop_q = try std.fmt.allocPrint(allocator, "DROP SCHEMA IF EXISTS {s} CASCADE", .{schema_q});
        defer allocator.free(drop_q);
        const result = try mgr.exec(drop_q);
        c.PQclear(result);
    }

    // First migrate — runs both the legacy inline loop AND migrations.run().
    try mgr.migrate();
    // Second migrate — must be idempotent. migrations.run() sees every
    // registered version already applied and short-circuits.
    try mgr.migrate();

    // Assert schema_migrations contains a row for every registered version.
    const list_q = try std.fmt.allocPrint(
        allocator,
        "SELECT version, name FROM {s}.schema_migrations ORDER BY version ASC",
        .{schema},
    );
    defer allocator.free(list_q);
    const result = try mgr.exec(list_q);
    defer c.PQclear(result);

    const got_rows: usize = @intCast(c.PQntuples(result));
    try std.testing.expect(got_rows >= migrations.MIGRATIONS.len);

    // Every registered version must appear (set inclusion — the legacy
    // bootstrap may also insert duplicates that ON CONFLICT DO NOTHING).
    for (migrations.MIGRATIONS) |m| {
        var found = false;
        for (0..got_rows) |i| {
            const row_idx: c_int = @intCast(i);
            const ver_text = try dupeResultValue(allocator, result, row_idx, 0);
            defer allocator.free(ver_text);
            const ver = try std.fmt.parseInt(u32, ver_text, 10);
            if (ver == m.version) {
                found = true;
                break;
            }
        }
        if (!found) {
            std.debug.print("D62: registered migration version {d} ({s}) missing from schema_migrations\n", .{ m.version, m.name });
            return error.MigrationNotRecorded;
        }
    }
}

test "P1-10 — full migration set applied TWICE is a clean no-op (schema fingerprint stable)" {
    // P1-10 acceptance keystone (rollout/rollback safety): applying the full
    // migration set TWICE against a fresh pgvector PG must leave the schema
    // BYTE-IDENTICAL after the second apply — i.e. every forward migration is
    // idempotent, so a re-apply (rolling update re-runs migrate() on every pod
    // boot; an interrupted-then-retried migrate; a pod restart) is a pure
    // no-op and never errors. We assert this by snapshotting a full schema
    // fingerprint (tables + every column with its nullability/type + every
    // index) after migrate #1, running migrate() again, re-snapshotting, and
    // asserting the two fingerprints are equal. A non-idempotent statement
    // would either (a) error on the second apply — caught because migrate()
    // returns the error — or (b) mutate the schema (e.g. duplicate index) —
    // caught by the fingerprint diff.
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;
    const test_url = (env_rebrand.getEnvOwnedWithRebrand(allocator, "NULLALIS_POSTGRES_TEST_URL", "NULLCLAW_POSTGRES_TEST_URL") catch return error.SkipZigTest) orelse return error.SkipZigTest;
    defer allocator.free(test_url);

    var schema_buf: [96]u8 = undefined;
    const schema = try std.fmt.bufPrint(&schema_buf, "zaki_bot_test_{d}_p1_10idem", .{std.time.microTimestamp()});
    const cfg = config_types.StateConfig{
        .backend = "postgres",
        .postgres = .{ .connection_string = test_url, .schema = schema },
    };
    var mgr = try ManagerImpl.init(allocator, cfg);
    defer mgr.deinit();

    // Fresh schema.
    {
        const schema_q = try pg_helpers.quoteIdentifier(allocator, mgr.schemaRaw());
        defer allocator.free(schema_q);
        const drop_q = try std.fmt.allocPrint(allocator, "DROP SCHEMA IF EXISTS {s} CASCADE", .{schema_q});
        defer allocator.free(drop_q);
        const result = try mgr.exec(drop_q);
        c.PQclear(result);
    }
    defer {
        if (pg_helpers.quoteIdentifier(allocator, mgr.schemaRaw())) |schema_q| {
            defer allocator.free(schema_q);
            if (std.fmt.allocPrint(allocator, "DROP SCHEMA IF EXISTS {s} CASCADE", .{schema_q})) |drop_q| {
                defer allocator.free(drop_q);
                if (mgr.exec(drop_q)) |result| {
                    c.PQclear(result);
                } else |_| {}
            } else |_| {}
        } else |_| {}
    }

    // A full-schema fingerprint: every column (table, name, nullability,
    // data type, ordinal) PLUS every index (name + definition), ordered
    // deterministically. Captured as one concatenated string so the whole
    // schema can be compared with a single equality assertion.
    const fingerprint = struct {
        fn snapshot(a: std.mem.Allocator, m: *ManagerImpl, sch: []const u8) ![]u8 {
            var out: std.ArrayListUnmanaged(u8) = .empty;
            errdefer out.deinit(a);

            // Columns.
            {
                const q = try std.fmt.allocPrint(
                    a,
                    "SELECT table_name, ordinal_position, column_name, is_nullable, data_type " ++
                        "FROM information_schema.columns WHERE table_schema = '{s}' " ++
                        "ORDER BY table_name, ordinal_position",
                    .{sch},
                );
                defer a.free(q);
                const r = try m.exec(q);
                defer c.PQclear(r);
                const rows: usize = @intCast(c.PQntuples(r));
                for (0..rows) |i| {
                    const ri: c_int = @intCast(i);
                    for (0..5) |col| {
                        const v = try dupeResultValue(a, r, ri, @intCast(col));
                        defer a.free(v);
                        try out.appendSlice(a, v);
                        try out.append(a, '|');
                    }
                    try out.append(a, '\n');
                }
            }
            try out.appendSlice(a, "==INDEXES==\n");
            // Indexes (name + full definition — catches a duplicate index or a
            // changed predicate that a name-only check would miss).
            {
                const q = try std.fmt.allocPrint(
                    a,
                    "SELECT indexname, indexdef FROM pg_indexes WHERE schemaname = '{s}' " ++
                        "ORDER BY indexname",
                    .{sch},
                );
                defer a.free(q);
                const r = try m.exec(q);
                defer c.PQclear(r);
                const rows: usize = @intCast(c.PQntuples(r));
                for (0..rows) |i| {
                    const ri: c_int = @intCast(i);
                    const name = try dupeResultValue(a, r, ri, 0);
                    defer a.free(name);
                    const def = try dupeResultValue(a, r, ri, 1);
                    defer a.free(def);
                    try out.appendSlice(a, name);
                    try out.append(a, '|');
                    try out.appendSlice(a, def);
                    try out.append(a, '\n');
                }
            }
            return out.toOwnedSlice(a);
        }
    };

    // Migrate #1 (fresh).
    try mgr.migrate();
    const fp1 = try fingerprint.snapshot(allocator, &mgr, schema);
    defer allocator.free(fp1);

    // Migrate #2 — must not error and must not mutate the schema.
    try mgr.migrate();
    const fp2 = try fingerprint.snapshot(allocator, &mgr, schema);
    defer allocator.free(fp2);

    if (!std.mem.eql(u8, fp1, fp2)) {
        std.debug.print(
            "P1-10: schema fingerprint changed on second migrate apply (NOT idempotent)\n--- after apply #1 ---\n{s}\n--- after apply #2 ---\n{s}\n",
            .{ fp1, fp2 },
        );
        return error.MigrationNotIdempotent;
    }

    // Sanity: the fingerprint actually captured the durable tables this task
    // touches (guards against an empty/degenerate snapshot silently passing).
    try std.testing.expect(std.mem.indexOf(u8, fp1, "pending_approvals") != null);
    try std.testing.expect(std.mem.indexOf(u8, fp1, "turn_usage") != null);
    // The 0006 transcript-fidelity columns must be present after migrate.
    try std.testing.expect(std.mem.indexOf(u8, fp1, "messages|") != null);
    try std.testing.expect(std.mem.indexOf(u8, fp1, "tool_calls") != null);
    try std.testing.expect(std.mem.indexOf(u8, fp1, "reasoning") != null);

    // Every registered version recorded exactly once (no duplicate inserts on
    // re-apply — the framework's version tracking short-circuits).
    {
        const q = try std.fmt.allocPrint(
            allocator,
            "SELECT version, COUNT(*) FROM {s}.schema_migrations GROUP BY version HAVING COUNT(*) > 1",
            .{schema},
        );
        defer allocator.free(q);
        const r = try mgr.exec(q);
        defer c.PQclear(r);
        try std.testing.expectEqual(@as(c_int, 0), c.PQntuples(r));
    }
}

test "v1.14.23 WARN-3 — artifact_versions has exactly ONE index after fresh migrate (no _artifact_ver duplicate)" {
    // Pre-fix, the inline-loop path in zaki_state.migrate() created
    // `idx_artifact_versions_artifact_ver` while migrations.run() created
    // `idx_artifact_versions_artifact_version` from the 0002_artifacts.sql
    // file. Both `IF NOT EXISTS` succeeded → two indexes on the same
    // (artifact_id, version DESC) columns → storage bloat + double-write
    // cost on every artifact_versions write.
    //
    // Post-fix: the inline path uses the canonical `_artifact_version`
    // name, matching the migration file. A fresh DB ends up with exactly
    // ONE index whose name starts with `idx_artifact_versions`. This test
    // asserts that.
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;
    const test_url = (env_rebrand.getEnvOwnedWithRebrand(allocator, "NULLALIS_POSTGRES_TEST_URL", "NULLCLAW_POSTGRES_TEST_URL") catch return error.SkipZigTest) orelse return error.SkipZigTest;
    defer allocator.free(test_url);

    var schema_buf: [96]u8 = undefined;
    const schema = try std.fmt.bufPrint(&schema_buf, "zaki_bot_test_{d}_warn3", .{std.time.microTimestamp()});
    const cfg = config_types.StateConfig{
        .backend = "postgres",
        .postgres = .{
            .connection_string = test_url,
            .schema = schema,
        },
    };

    var mgr = try ManagerImpl.init(allocator, cfg);
    defer mgr.deinit();

    // Drop schema if it exists so the migrate path runs end-to-end.
    {
        const schema_q = try pg_helpers.quoteIdentifier(allocator, mgr.schemaRaw());
        defer allocator.free(schema_q);
        const drop_q = try std.fmt.allocPrint(allocator, "DROP SCHEMA IF EXISTS {s} CASCADE", .{schema_q});
        defer allocator.free(drop_q);
        const result = try mgr.exec(drop_q);
        c.PQclear(result);
    }

    try mgr.migrate();

    // pg_indexes.schemaname is matched as a string literal, not an identifier;
    // we want only indexes in the just-created test schema so a parallel
    // test's `_artifact_ver` (if any survives a prior bad run) doesn't bleed in.
    const count_q = try std.fmt.allocPrint(
        allocator,
        "SELECT count(*)::int FROM pg_indexes WHERE schemaname = '{s}' AND indexname LIKE 'idx_artifact_versions%'",
        .{schema},
    );
    defer allocator.free(count_q);
    const result = try mgr.exec(count_q);
    defer c.PQclear(result);

    try std.testing.expectEqual(@as(c_int, 1), c.PQntuples(result));
    const count_text = try dupeResultValue(allocator, result, 0, 0);
    defer allocator.free(count_text);
    const count = try std.fmt.parseInt(u32, count_text, 10);
    if (count != 1) {
        std.debug.print(
            "WARN-3 fix regressed: expected exactly 1 index matching 'idx_artifact_versions%', got {d}\n",
            .{count},
        );

        // Surface which indexes are present so a future debugger can see
        // the divergence directly.
        const names_q = try std.fmt.allocPrint(
            allocator,
            "SELECT indexname FROM pg_indexes WHERE schemaname = '{s}' AND indexname LIKE 'idx_artifact_versions%' ORDER BY indexname",
            .{schema},
        );
        defer allocator.free(names_q);
        const names_res = try mgr.exec(names_q);
        defer c.PQclear(names_res);
        const n_names: usize = @intCast(c.PQntuples(names_res));
        for (0..n_names) |i| {
            const nm = try dupeResultValue(allocator, names_res, @intCast(i), 0);
            defer allocator.free(nm);
            std.debug.print("  - {s}\n", .{nm});
        }
        return error.DuplicateArtifactIndex;
    }

    // Belt-and-suspenders: the surviving index must be the canonical
    // `_artifact_version` name. The legacy `_artifact_ver` name must NOT
    // be present.
    const canonical_q = try std.fmt.allocPrint(
        allocator,
        "SELECT count(*)::int FROM pg_indexes WHERE schemaname = '{s}' AND indexname = 'idx_artifact_versions_artifact_version'",
        .{schema},
    );
    defer allocator.free(canonical_q);
    const canonical_res = try mgr.exec(canonical_q);
    defer c.PQclear(canonical_res);
    const canonical_text = try dupeResultValue(allocator, canonical_res, 0, 0);
    defer allocator.free(canonical_text);
    try std.testing.expectEqualStrings("1", canonical_text);
}

test "V1.5.1 brain hygiene PG roundtrip — listMemoriesBrainVisible + listMemoriesTimeline filter agent bookkeeping" {
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;
    const test_url = (env_rebrand.getEnvOwnedWithRebrand(allocator, "NULLALIS_POSTGRES_TEST_URL", "NULLCLAW_POSTGRES_TEST_URL") catch return error.SkipZigTest) orelse return error.SkipZigTest;
    defer allocator.free(test_url);

    var schema_buf: [96]u8 = undefined;
    const schema = try std.fmt.bufPrint(&schema_buf, "zaki_bot_test_{d}", .{std.time.microTimestamp()});
    const cfg = config_types.StateConfig{
        .backend = "postgres",
        .postgres = .{
            .connection_string = test_url,
            .schema = schema,
        },
    };

    var mgr = try ManagerImpl.init(allocator, cfg);
    defer mgr.deinit();
    {
        const schema_q = try pg_helpers.quoteIdentifier(allocator, mgr.schemaRaw());
        defer allocator.free(schema_q);
        const drop_q = try std.fmt.allocPrint(allocator, "DROP SCHEMA IF EXISTS {s} CASCADE", .{schema_q});
        defer allocator.free(drop_q);
        const result = try mgr.exec(drop_q);
        c.PQclear(result);
    }
    try mgr.migrate();
    try mgr.provisionUser(2, "/tmp/nullalis-zaki-bot-test-user-2/workspace");

    const user_id: i64 = 2;

    // ── Seed: 4 visible (user-authored) + 6 hidden (one of each class) ─
    try mgr.upsertMemory(user_id, "user_lang", "Prefers Zig", .core, null);
    try mgr.upsertMemory(user_id, "favorite_snack", "olives", .core, null);
    try mgr.upsertMemory(user_id, "compose:0123456789abcdef", "synth", .core, null);
    try mgr.upsertMemory(user_id, "morning_routine", "wake at 6", .daily, null);
    // hidden — audit family
    try mgr.upsertMemory(user_id, "session_checkpoint_1714521600", "type=session_checkpoint reason=shutdown", .daily, null);
    try mgr.upsertMemory(user_id, "audit_shell/1777419406559181000", "type=shell_audit cwd=/foo", .daily, null);
    // hidden — continuity family
    try mgr.upsertMemory(user_id, "summary_latest/agent:zaki-bot:user:7:thread:main", "type=summary_latest origin_channel=zaki_app", .daily, null);
    try mgr.upsertMemory(user_id, "timeline_summary/agent:zaki-bot:user:7:thread:main/1714521600", "type=timeline_summary", .daily, null);
    // hidden — internal family
    try mgr.upsertMemory(user_id, "context_anchor_current", "type=context_anchor", .core, null);
    try mgr.upsertMemory(user_id, "last_hygiene_at", "1714521600", .core, null);

    // ── /brain/graph path: listMemoriesBrainVisible ────────────────────
    const brain = try mgr.listMemoriesBrainVisible(allocator, user_id);
    defer memory_root.freeEntries(allocator, brain);
    try std.testing.expectEqual(@as(usize, 4), brain.len);
    var seen_user_lang = false;
    var seen_compose = false;
    for (brain) |entry| {
        // Cross-check: the predicate must agree with the SQL filter for
        // every returned key.
        try std.testing.expect(memory_root.isBrainVisibleKey(entry.key));
        if (std.mem.eql(u8, entry.key, "user_lang")) seen_user_lang = true;
        if (std.mem.eql(u8, entry.key, "compose:0123456789abcdef")) seen_compose = true;
        // Negative: no hidden-prefix key must appear in the result set.
        try std.testing.expect(!std.mem.startsWith(u8, entry.key, "session_checkpoint_"));
        try std.testing.expect(!std.mem.startsWith(u8, entry.key, "audit_shell/"));
        try std.testing.expect(!std.mem.startsWith(u8, entry.key, "summary_latest/"));
        try std.testing.expect(!std.mem.startsWith(u8, entry.key, "timeline_summary/"));
        try std.testing.expect(!std.mem.eql(u8, entry.key, "context_anchor_current"));
        try std.testing.expect(!std.mem.eql(u8, entry.key, "last_hygiene_at"));
    }
    try std.testing.expect(seen_user_lang);
    try std.testing.expect(seen_compose);

    // ── /brain/timeline path: listMemoriesTimeline (filter baked-in) ───
    const timeline = try mgr.listMemoriesTimeline(allocator, user_id, null, null, 100, null, null);
    defer memory_root.freeEntries(allocator, timeline);
    try std.testing.expectEqual(@as(usize, 4), timeline.len);
    for (timeline) |entry| {
        try std.testing.expect(memory_root.isBrainVisibleKey(entry.key));
    }

    // ── Sanity: agent-facing listMemories STILL sees everything ────────
    // The agent retrieval pipeline depends on continuity artifacts; the
    // hygiene filter MUST NOT leak into the agent path.
    const agent_facing = try mgr.listMemories(allocator, user_id, null, null);
    defer memory_root.freeEntries(allocator, agent_facing);
    try std.testing.expectEqual(@as(usize, 10), agent_facing.len);
}

fn categoryToMemoryType(category: memory_root.MemoryCategory) []const u8 {
    return switch (category) {
        .core => "core",
        .daily => "daily",
        .conversation => "conversation",
        .custom => |name| name,
    };
}

fn memoryTypeToCategory(allocator: std.mem.Allocator, mem_type: []const u8) !memory_root.MemoryCategory {
    if (std.mem.eql(u8, mem_type, "core")) return .core;
    if (std.mem.eql(u8, mem_type, "daily")) return .daily;
    if (std.mem.eql(u8, mem_type, "conversation")) return .conversation;
    return .{ .custom = try allocator.dupe(u8, mem_type) };
}

// ── P3 round-trip: custom: memory types survive the DB string column ──
//
// The durable `memory_type` is stored as a string and read back. P3 routes
// extracted facts to `MemoryCategory{ .custom = "preference"|"decision"|
// "open_loop"|"person" }`. This test pins the CRITICAL invariant flagged in
// the P3 spec: a custom category written via `categoryToMemoryType` (the
// write side) must read back IDENTICALLY via `memoryTypeToCategory` (the
// read side) — NOT crash, NOT collapse to `.core`. Both helpers handle
// arbitrary strings (write passes through; read maps unknown → `.custom`),
// so the round-trip is the identity for any string that is not a builtin
// category name.
test "P3 round-trip: memoryTypeToCategory(categoryToMemoryType(custom)) == custom" {
    const allocator = std.testing.allocator;
    const customs = [_][]const u8{ "preference", "decision", "open_loop", "person" };
    for (customs) |name| {
        const want = memory_root.MemoryCategory{ .custom = name };
        // write side: custom string passes straight through to the column.
        const mem_type = categoryToMemoryType(want);
        try std.testing.expectEqualStrings(name, mem_type);
        // read side: unknown string must come back as .custom (NOT .core).
        const got = try memoryTypeToCategory(allocator, mem_type);
        defer if (got == .custom) allocator.free(got.custom);
        try std.testing.expect(got == .custom);
        try std.testing.expect(want.eql(got));
        try std.testing.expectEqualStrings(name, got.custom);
    }
    // Builtins must NOT regress to .custom.
    const builtins = [_]memory_root.MemoryCategory{ .core, .daily, .conversation };
    const builtin_names = [_][]const u8{ "core", "daily", "conversation" };
    for (builtins, builtin_names) |cat, name| {
        try std.testing.expectEqualStrings(name, categoryToMemoryType(cat));
        const rt = try memoryTypeToCategory(allocator, categoryToMemoryType(cat));
        defer if (rt == .custom) allocator.free(rt.custom);
        try std.testing.expect(cat.eql(rt));
    }
}

fn computeContentHash(allocator: std.mem.Allocator, content: []const u8) ![]u8 {
    var digest: [32]u8 = undefined;
    std.crypto.hash.sha2.Sha256.hash(content, &digest, .{});
    const out = try allocator.alloc(u8, digest.len * 2);
    _ = security_secrets.hexEncode(&digest, out);
    return out;
}

fn decodeMemoryEntry(allocator: std.mem.Allocator, result: *c.PGresult, row: c_int) !memory_root.MemoryEntry {
    const mem_type = try dupeResultValue(allocator, result, row, 3);
    defer allocator.free(mem_type);
    const session_text = try dupeResultValue(allocator, result, row, 5);
    errdefer allocator.free(session_text);

    const sid: ?[]u8 = if (session_text.len == 0) blk: {
        allocator.free(session_text);
        break :blk null;
    } else session_text;

    // S8.1 — populate `lane` from session_id when present (matches the
    // sqlite engine wiring at `memory/engines/sqlite.zig`). Borrowed
    // string-literal pointer; no alloc/free coupling. Without this, all
    // postgres-backed retrievals would land at `lane = "unknown"` and
    // the same-lane ranking heuristic in the agent layer would no-op
    // for production deployments. Post-S8.1 review fix (M-LANE).
    const lane: []const u8 = if (sid) |s| memory_root.laneFromSessionId(s) else "unknown";

    // V1.5 day-2 — column 6 is `valid_to` (BIGINT, nullable). PG returns
    // empty string when NULL via dupeResultValue; treat empty + parse-
    // failure as null to keep the read path forgiving. V1.5 always-null
    // path means most rows hit the empty branch.
    const valid_to_text = try dupeResultValue(allocator, result, row, 6);
    defer allocator.free(valid_to_text);
    const valid_to: ?i64 = if (valid_to_text.len == 0)
        null
    else
        std.fmt.parseInt(i64, valid_to_text, 10) catch null;

    return .{
        .id = try dupeResultValue(allocator, result, row, 0),
        .key = try dupeResultValue(allocator, result, row, 1),
        .content = try dupeResultValue(allocator, result, row, 2),
        .category = try memoryTypeToCategory(allocator, mem_type),
        .timestamp = try dupeResultValue(allocator, result, row, 4),
        .session_id = sid,
        .score = null,
        .lane = lane,
        .valid_to = valid_to,
    };
}

fn decodeMemoryRows(allocator: std.mem.Allocator, result: *c.PGresult, has_score: bool) ![]memory_root.MemoryEntry {
    const rows: usize = @intCast(c.PQntuples(result));
    const out = try allocator.alloc(memory_root.MemoryEntry, rows);
    var initialized: usize = 0;
    errdefer {
        for (out[0..initialized]) |*entry| entry.deinit(allocator);
        allocator.free(out);
    }

    for (0..rows) |i| {
        const row: c_int = @intCast(i);
        out[i] = try decodeMemoryEntry(allocator, result, row);
        if (has_score) {
            // V1.5 day-2 — score column shifted from 6 → 7 because
            // valid_to now occupies column 6 in recall queries. Both
            // recall query branches in `recallMemories` SELECT in this
            // order: id, key, content, memory_type, ts_text, session_id,
            // valid_to, score.
            const score_text = try dupeResultValue(allocator, result, row, 7);
            defer allocator.free(score_text);
            out[i].score = std.fmt.parseFloat(f64, score_text) catch null;
        }
        initialized += 1;
    }
    return out;
}

fn jsonString(allocator: std.mem.Allocator, value: []const u8) ![]u8 {
    var out: std.ArrayList(u8) = .empty;
    errdefer out.deinit(allocator);
    try out.append(allocator, '"');
    for (value) |ch| {
        switch (ch) {
            '\\' => try out.appendSlice(allocator, "\\\\"),
            '"' => try out.appendSlice(allocator, "\\\""),
            '\n' => try out.appendSlice(allocator, "\\n"),
            '\r' => try out.appendSlice(allocator, "\\r"),
            '\t' => try out.appendSlice(allocator, "\\t"),
            else => try out.append(allocator, ch),
        }
    }
    try out.append(allocator, '"');
    return out.toOwnedSlice(allocator);
}

fn canIgnoreMigrateError(template: []const u8, raw_err: [*c]const u8) bool {
    const err_text = std.mem.span(raw_err);
    if (std.mem.startsWith(u8, template, "CREATE SCHEMA IF NOT EXISTS")) {
        return std.mem.indexOf(u8, err_text, "pg_namespace_nspname_index") != null or
            std.mem.indexOf(u8, err_text, "already exists") != null;
    }
    if (std.mem.startsWith(u8, template, "CREATE EXTENSION IF NOT EXISTS")) {
        return std.mem.indexOf(u8, err_text, "already exists") != null or
            std.mem.indexOf(u8, err_text, "pg_extension_name_index") != null or
            std.mem.indexOf(u8, err_text, "duplicate key value violates unique constraint") != null;
    }
    if (std.mem.startsWith(u8, template, "CREATE INDEX IF NOT EXISTS")) {
        return std.mem.indexOf(u8, err_text, "already exists") != null or
            std.mem.indexOf(u8, err_text, "pg_class_relname_nsp_index") != null;
    }
    if (std.mem.startsWith(u8, template, "CREATE UNIQUE INDEX IF NOT EXISTS")) {
        return std.mem.indexOf(u8, err_text, "already exists") != null or
            std.mem.indexOf(u8, err_text, "pg_class_relname_nsp_index") != null;
    }
    if (std.mem.startsWith(u8, template, "CREATE TABLE IF NOT EXISTS")) {
        return std.mem.indexOf(u8, err_text, "already exists") != null or
            std.mem.indexOf(u8, err_text, "pg_type_typname_nsp_index") != null or
            std.mem.indexOf(u8, err_text, "pg_class_relname_nsp_index") != null or
            std.mem.indexOf(u8, err_text, "duplicate key value violates unique constraint") != null;
    }
    if (std.mem.startsWith(u8, template, "ALTER TABLE") and std.mem.indexOf(u8, template, "ADD CONSTRAINT users_user_id_fkey") != null) {
        return std.mem.indexOf(u8, err_text, "already exists") != null or
            std.mem.indexOf(u8, err_text, "duplicate_object") != null or
            std.mem.indexOf(u8, err_text, "permission denied for table zaki_users") != null or
            std.mem.indexOf(u8, err_text, "relation \"zaki_users\" does not exist") != null or
            std.mem.indexOf(u8, err_text, "relation \"public.zaki_users\" does not exist") != null;
    }
    if (std.mem.startsWith(u8, template, "ALTER TABLE") and std.mem.indexOf(u8, template, "DROP CONSTRAINT IF EXISTS") != null) {
        return std.mem.indexOf(u8, err_text, "does not exist") != null;
    }
    if (std.mem.startsWith(u8, template, "ALTER TABLE") and std.mem.indexOf(u8, template, "ADD PRIMARY KEY (user_id, id)") != null) {
        return std.mem.indexOf(u8, err_text, "multiple primary keys for table") != null or
            std.mem.indexOf(u8, err_text, "already exists") != null;
    }
    return false;
}

fn loadMasterKey(allocator: std.mem.Allocator, env_name: []const u8) !?[security_secrets.KEY_LEN]u8 {
    const raw = std.process.getEnvVarOwned(allocator, env_name) catch |err| switch (err) {
        error.EnvironmentVariableNotFound => return null,
        else => return err,
    };
    defer allocator.free(raw);
    var digest: [security_secrets.KEY_LEN]u8 = undefined;
    std.crypto.hash.sha2.Sha256.hash(raw, &digest, .{});
    return digest;
}

