fn initPostgresTestManagerWithPool(allocator: std.mem.Allocator, pool_max: u32, lock_timeout_ms: u32) !ManagerImpl {
    const test_url = (env_rebrand.getEnvOwnedWithRebrand(allocator, "NULLALIS_POSTGRES_TEST_URL", "NULLCLAW_POSTGRES_TEST_URL") catch return error.SkipZigTest) orelse return error.SkipZigTest;
    defer allocator.free(test_url);

    var schema_buf: [96]u8 = undefined;
    const schema = try std.fmt.bufPrint(&schema_buf, "zaki_bot_test_{d}", .{std.time.microTimestamp()});
    const cfg = config_types.StateConfig{
        .backend = "postgres",
        .postgres = .{
            .connection_string = test_url,
            .schema = schema,
            .pool_max = pool_max,
            .lock_timeout_ms = lock_timeout_ms,
        },
    };

    var mgr = try ManagerImpl.init(allocator, cfg);
    {
        const schema_q = try pg_helpers.quoteIdentifier(allocator, mgr.schemaRaw());
        defer allocator.free(schema_q);
        const drop_q = try std.fmt.allocPrint(allocator, "DROP SCHEMA IF EXISTS {s} CASCADE", .{schema_q});
        defer allocator.free(drop_q);
        const result = try mgr.exec(drop_q);
        c.PQclear(result);
    }
    try mgr.migrate();
    return mgr;
}

// ─────────────────────────────────────────────────────────────────────
// C0 (memory-phase-0.5) — phase05Backfill postgres-gated integration.
//
// Pure-logic decision tests live in agent/extraction_persist.zig
// (backfillMemoryType / backfillEntityTypeFromPredicate). These exercise the
// actual UPDATE/DELETE/supersede SQL + the two SAFETY contracts:
//   - dry_run (the tool default) writes NOTHING, and
//   - a second live run is a clean no-op (idempotence).
// Skipped locally (require NULLALIS_POSTGRES_TEST_URL).
// ─────────────────────────────────────────────────────────────────────

/// Helper: read a memory row's raw memory_type by key (incl. superseded rows;
/// no validity filter). Returns owned string; caller frees.
fn c0ReadMemoryType(allocator: std.mem.Allocator, mgr: *ManagerImpl, user_id: i64, key: []const u8) ![]u8 {
    const schema_q = try pg_helpers.quoteIdentifier(allocator, mgr.schemaRaw());
    defer allocator.free(schema_q);
    const q = try std.fmt.allocPrint(
        allocator,
        "SELECT memory_type FROM {s}.memories WHERE user_id = {d} AND key = '{s}'",
        .{ schema_q, user_id, key },
    );
    defer allocator.free(q);
    const result = try mgr.exec(q);
    defer c.PQclear(result);
    return try dupeResultValue(allocator, result, 0, 0);
}

test "C0 phase05Backfill: dry-run writes NOTHING but reports counts" {
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;
    var mgr = initPostgresTestManagerWithPool(allocator, 2, 500) catch return error.SkipZigTest;
    defer mgr.deinit();
    try mgr.provisionUser(2, "/tmp/nullalis-zaki-bot-test-c0-dry/workspace");

    // A legacy `daily` row whose predicate PREFERS routes to `preference`.
    try mgr.upsertMemoryWithMetadata(
        2,
        "c0_dry_pref",
        "User prefers dark mode",
        .daily,
        "sess-c0",
        \\{"subject":"user","predicate":"PREFERS","object":"dark mode","attributed_to":"user"}
        ,
    );

    const report = try mgr.phase05Backfill(allocator, 2, true); // dry_run=true
    try std.testing.expect(report.dry_run);
    try std.testing.expectEqual(@as(usize, 1), report.users_scanned);
    // Reports the would-be re-type...
    try std.testing.expectEqual(@as(usize, 1), report.rows_retyped);
    // ...but the row's memory_type is UNCHANGED on disk.
    const mt = try c0ReadMemoryType(allocator, &mgr, 2, "c0_dry_pref");
    defer allocator.free(mt);
    try std.testing.expectEqualStrings("daily", mt);
}

test "C0 phase05Backfill: live re-type + idempotent second run" {
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;
    var mgr = initPostgresTestManagerWithPool(allocator, 2, 500) catch return error.SkipZigTest;
    defer mgr.deinit();
    try mgr.provisionUser(2, "/tmp/nullalis-zaki-bot-test-c0-retype/workspace");

    try mgr.upsertMemoryWithMetadata(
        2,
        "c0_pref",
        "User prefers dark mode",
        .daily,
        "sess-c0",
        \\{"subject":"user","predicate":"PREFERS","object":"dark mode","attributed_to":"user"}
        ,
    );
    // A KNOWS row → person; and a no-predicate row that must stay untouched.
    try mgr.upsertMemoryWithMetadata(
        2,
        "c0_person",
        "User knows Alice",
        .daily,
        "sess-c0",
        \\{"subject":"user","predicate":"KNOWS","object":"Alice","attributed_to":"user"}
        ,
    );
    try mgr.upsertMemoryWithMetadata(2, "c0_nopred", "freeform note", .daily, "sess-c0", "{}");

    // Live run #1.
    const r1 = try mgr.phase05Backfill(allocator, 2, false);
    try std.testing.expect(!r1.dry_run);
    try std.testing.expectEqual(@as(usize, 2), r1.rows_retyped);

    const pref_t = try c0ReadMemoryType(allocator, &mgr, 2, "c0_pref");
    defer allocator.free(pref_t);
    try std.testing.expectEqualStrings("preference", pref_t);
    const person_t = try c0ReadMemoryType(allocator, &mgr, 2, "c0_person");
    defer allocator.free(person_t);
    try std.testing.expectEqualStrings("person", person_t);
    const nopred_t = try c0ReadMemoryType(allocator, &mgr, 2, "c0_nopred");
    defer allocator.free(nopred_t);
    try std.testing.expectEqualStrings("daily", nopred_t); // untouched — no predicate

    // Live run #2 — IDEMPOTENT: already-typed rows are no longer candidates.
    const r2 = try mgr.phase05Backfill(allocator, 2, false);
    try std.testing.expectEqual(@as(usize, 0), r2.rows_retyped);
    const pref_t2 = try c0ReadMemoryType(allocator, &mgr, 2, "c0_pref");
    defer allocator.free(pref_t2);
    try std.testing.expectEqualStrings("preference", pref_t2);
}

test "T2b: telos row survives content_hash dedup vs a byte-identical raw dup" {
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;
    var mgr = initPostgresTestManagerWithPool(allocator, 2, 500) catch return error.SkipZigTest;
    defer mgr.deinit();
    try mgr.provisionUser(2, "/tmp/nullalis-zaki-bot-test-t2b/workspace");

    // A raw duplicate and a curated telos row with byte-identical content →
    // identical content_hash. The raw row is inserted first (older) AND sorts
    // first by key, so it is the dedup keeper and the telos row is the "loser" —
    // exactly the shape T2b must protect against.
    const dup_content = "Ship v1 by Q3";
    try mgr.upsertMemoryWithMetadata(2, "durable_fact/aaa_raw_dup", dup_content, .core, "sess-t2b", "{}");
    try mgr.upsertMemoryWithMetadata(2, "durable_fact/telos/goal/x", dup_content, .core, "sess-t2b", "{}");

    const r = try mgr.phase05Backfill(allocator, 2, false);
    // The telos loser is SKIPPED, not collapsed (isTelosKey guard).
    try std.testing.expectEqual(@as(usize, 0), r.exact_dups_collapsed);

    // The curated telos row is still live — never superseded by a stray dup.
    const telos = try mgr.getMemory(allocator, 2, "durable_fact/telos/goal/x");
    try std.testing.expect(telos != null);
    if (telos) |m| m.deinit(allocator);

    // The raw keeper is untouched too — both remain live.
    const raw = try mgr.getMemory(allocator, 2, "durable_fact/aaa_raw_dup");
    try std.testing.expect(raw != null);
    if (raw) |m| m.deinit(allocator);
}

test "C0 phase05Backfill: exact content_hash dedup supersedes (never hard-deletes), idempotent" {
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;
    var mgr = initPostgresTestManagerWithPool(allocator, 2, 500) catch return error.SkipZigTest;
    defer mgr.deinit();
    try mgr.provisionUser(2, "/tmp/nullalis-zaki-bot-test-c0-dedup/workspace");

    // Two rows with byte-identical content → identical content_hash. Distinct
    // keys (the duplicate-write shape C0 repairs). Both start live.
    const dup_content = "User lives in Cairo";
    try mgr.upsertMemoryWithMetadata(2, "c0_dup_old", dup_content, .core, "sess-c0", "{}");
    try mgr.upsertMemoryWithMetadata(2, "c0_dup_new", dup_content, .core, "sess-c0", "{}");

    const r1 = try mgr.phase05Backfill(allocator, 2, false);
    try std.testing.expectEqual(@as(usize, 1), r1.exact_dups_collapsed); // 1 loser

    // The keeper (oldest by created_at) is still live; exactly one of the two
    // remains visible via the validity-filtered getMemory.
    var live_count: usize = 0;
    if (try mgr.getMemory(allocator, 2, "c0_dup_old")) |m| {
        m.deinit(allocator);
        live_count += 1;
    }
    if (try mgr.getMemory(allocator, 2, "c0_dup_new")) |m| {
        m.deinit(allocator);
        live_count += 1;
    }
    try std.testing.expectEqual(@as(usize, 1), live_count);

    // NEVER hard-deleted — both rows still exist in the table (one superseded).
    {
        const schema_q = try pg_helpers.quoteIdentifier(allocator, mgr.schemaRaw());
        defer allocator.free(schema_q);
        const q = try std.fmt.allocPrint(allocator, "SELECT COUNT(*) FROM {s}.memories WHERE user_id = 2 AND content_hash IS NOT NULL", .{schema_q});
        defer allocator.free(q);
        const result = try mgr.exec(q);
        defer c.PQclear(result);
        const cnt = try dupeResultValue(allocator, result, 0, 0);
        defer allocator.free(cnt);
        try std.testing.expectEqualStrings("2", cnt);
    }

    // Idempotent: second run finds no LIVE duplicate group (loser has valid_to).
    const r2 = try mgr.phase05Backfill(allocator, 2, false);
    try std.testing.expectEqual(@as(usize, 0), r2.exact_dups_collapsed);
}

test "C0 phase05Backfill: un-embed deletes continuity embeddings, keeps durable_fact" {
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;
    var mgr = initPostgresTestManagerWithPool(allocator, 2, 500) catch return error.SkipZigTest;
    defer mgr.deinit();
    try mgr.provisionUser(2, "/tmp/nullalis-zaki-bot-test-c0-unembed/workspace");

    const schema_q = try pg_helpers.quoteIdentifier(allocator, mgr.schemaRaw());
    defer allocator.free(schema_q);

    // Stand up a minimal pgvector-shaped embeddings table in the tenant schema
    // (the vector plane creates it at runtime; the test recreates its shape).
    {
        const ddl = try std.fmt.allocPrint(allocator,
            \\CREATE TABLE IF NOT EXISTS {s}.memory_embeddings (
            \\  user_id BIGINT NOT NULL, key TEXT NOT NULL,
            \\  embedding vector(3), updated_at TIMESTAMPTZ NOT NULL DEFAULT now(),
            \\  PRIMARY KEY (user_id, key))
        , .{schema_q});
        defer allocator.free(ddl);
        const r = mgr.exec(ddl) catch return error.SkipZigTest; // skip if no pgvector ext
        c.PQclear(r);
    }
    // Insert continuity rows (must be deleted) + a durable_fact row (must stay).
    {
        const ins = try std.fmt.allocPrint(allocator,
            \\INSERT INTO {s}.memory_embeddings (user_id, key, embedding) VALUES
            \\  (2, 'summary_latest/sess-x/0', '[0,0,0]'),
            \\  (2, 'timeline_summary/sess-x/1', '[0,0,0]'),
            \\  (2, 'session_summary/sess-x/2', '[0,0,0]'),
            \\  (2, 'summary_fallback/sess-x/3', '[0,0,0]'),
            \\  (2, 'durable_fact/1778049787/0', '[0,0,0]')
        , .{schema_q});
        defer allocator.free(ins);
        const r = try mgr.exec(ins);
        c.PQclear(r);
    }

    const r1 = try mgr.phase05Backfill(allocator, 2, false);
    try std.testing.expectEqual(@as(usize, 4), r1.continuity_embeddings_removed);

    // durable_fact survived; continuity gone.
    {
        const q = try std.fmt.allocPrint(allocator, "SELECT COUNT(*) FROM {s}.memory_embeddings WHERE user_id = 2", .{schema_q});
        defer allocator.free(q);
        const result = try mgr.exec(q);
        defer c.PQclear(result);
        const cnt = try dupeResultValue(allocator, result, 0, 0);
        defer allocator.free(cnt);
        try std.testing.expectEqualStrings("1", cnt); // only durable_fact remains
    }

    // Idempotent — nothing left to remove.
    const r2 = try mgr.phase05Backfill(allocator, 2, false);
    try std.testing.expectEqual(@as(usize, 0), r2.continuity_embeddings_removed);
}

test "C0 phase05Backfill: PROPER entity with relationship edge upgrades to PERSON, idempotent + no-clobber" {
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;
    var mgr = initPostgresTestManagerWithPool(allocator, 2, 500) catch return error.SkipZigTest;
    defer mgr.deinit();
    try mgr.provisionUser(2, "/tmp/nullalis-zaki-bot-test-c0-entity/workspace");

    const zero_emb = [_]f32{0.0} ** 1024;

    // (a) Alice: PROPER entity with an incoming KNOWS (relationship) edge →
    //     must upgrade to PERSON.
    const alice_id = try mgr.upsertEntity(allocator, 2, "Alice", "PROPER", &zero_emb);
    defer allocator.free(alice_id);
    try mgr.upsertMemory(2, "m_knows_alice", "User knows Alice", .core, null);
    try mgr.upsertMemoryEdge(2, "m_knows_alice", alice_id, "KNOWS", "extraction_classifier", 1.0);

    // (b) Helix: PROPER entity with an incoming USES (usage, NOT relationship)
    //     edge → must stay PROPER (no guessing ORG/PRODUCT from non-relationship
    //     predicates).
    const helix_id = try mgr.upsertEntity(allocator, 2, "Helix", "PROPER", &zero_emb);
    defer allocator.free(helix_id);
    try mgr.upsertMemory(2, "m_uses_helix", "User uses Helix", .core, null);
    try mgr.upsertMemoryEdge(2, "m_uses_helix", helix_id, "USES", "extraction_classifier", 1.0);

    // (c) Bob: already typed PERSON (no-clobber sanity — never demoted, never
    //     re-counted).
    const bob_id = try mgr.upsertEntity(allocator, 2, "Bob", "PERSON", &zero_emb);
    defer allocator.free(bob_id);
    try mgr.upsertMemory(2, "m_knows_bob", "User knows Bob", .core, null);
    try mgr.upsertMemoryEdge(2, "m_knows_bob", bob_id, "MARRIED_TO", "extraction_classifier", 1.0);

    const readType = struct {
        fn run(a: std.mem.Allocator, m: *ManagerImpl, id: []const u8) ![]u8 {
            const schema_q = try pg_helpers.quoteIdentifier(a, m.schemaRaw());
            defer a.free(schema_q);
            const q = try std.fmt.allocPrint(a, "SELECT entity_type FROM {s}.memory_entities WHERE user_id = 2 AND id = '{s}'", .{ schema_q, id });
            defer a.free(q);
            const result = try m.exec(q);
            defer c.PQclear(result);
            return try dupeResultValue(a, result, 0, 0);
        }
    };

    const r1 = try mgr.phase05Backfill(allocator, 2, false);
    // Only Alice flips (Helix non-relationship, Bob already PERSON).
    try std.testing.expectEqual(@as(usize, 1), r1.entities_retyped);

    const alice_t = try readType.run(allocator, &mgr, alice_id);
    defer allocator.free(alice_t);
    try std.testing.expectEqualStrings("PERSON", alice_t);
    const helix_t = try readType.run(allocator, &mgr, helix_id);
    defer allocator.free(helix_t);
    try std.testing.expectEqualStrings("PROPER", helix_t); // unchanged — no guessing
    const bob_t = try readType.run(allocator, &mgr, bob_id);
    defer allocator.free(bob_t);
    try std.testing.expectEqualStrings("PERSON", bob_t); // unchanged — not demoted

    // Idempotent: Alice is now PERSON, no longer a 'PROPER' candidate.
    const r2 = try mgr.phase05Backfill(allocator, 2, false);
    try std.testing.expectEqual(@as(usize, 0), r2.entities_retyped);
}

test "brain-leak C: phase05Backfill purges scaffold entities + their edges (dry-run safe, idempotent)" {
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;
    var mgr = initPostgresTestManagerWithPool(allocator, 2, 500) catch return error.SkipZigTest;
    defer mgr.deinit();
    try mgr.provisionUser(2, "/tmp/nullalis-zaki-bot-test-c0-scaffold/workspace");

    const zero_emb = [_]f32{0.0} ** 1024;

    // (a) A poisoned scaffold entity — the #48 leak shape: a section title that
    //     got persisted as a brain entity, with an incoming edge.
    const scaffold_id = try mgr.upsertEntity(allocator, 2, "Brain Architecture", "PROPER", &zero_emb);
    defer allocator.free(scaffold_id);
    try mgr.upsertMemory(2, "m_scaffold", "User uses Brain Architecture", .core, null);
    try mgr.upsertMemoryEdge(2, "m_scaffold", scaffold_id, "USES", "extraction_classifier", 1.0);

    // (b) A scaffold entity as an edge SOURCE too (e.g. "Memory Link Types" →
    //     edges) — purge must clear edges on both sides.
    const scaffold2_id = try mgr.upsertEntity(allocator, 2, "Memory Link Types", "PROPER", &zero_emb);
    defer allocator.free(scaffold2_id);
    const real_target = try mgr.upsertEntity(allocator, 2, "edges", "PROPER", &zero_emb);
    defer allocator.free(real_target);
    try mgr.upsertMemoryEdge(2, scaffold2_id, real_target, "RELATED_TO", "extraction_classifier", 1.0);

    // (c) A genuine entity + edge — must survive untouched.
    const helix_id = try mgr.upsertEntity(allocator, 2, "Helix", "PROPER", &zero_emb);
    defer allocator.free(helix_id);
    try mgr.upsertMemory(2, "m_helix", "User uses Helix", .core, null);
    try mgr.upsertMemoryEdge(2, "m_helix", helix_id, "USES", "extraction_classifier", 1.0);

    const countEntities = struct {
        fn run(a: std.mem.Allocator, m: *ManagerImpl) !i64 {
            const schema_q = try pg_helpers.quoteIdentifier(a, m.schemaRaw());
            defer a.free(schema_q);
            const q = try std.fmt.allocPrint(a, "SELECT COUNT(*) FROM {s}.memory_entities WHERE user_id = 2", .{schema_q});
            defer a.free(q);
            const result = try m.exec(q);
            defer c.PQclear(result);
            const s = try dupeResultValue(a, result, 0, 0);
            defer a.free(s);
            return try std.fmt.parseInt(i64, s, 10);
        }
    };
    const entityExists = struct {
        fn run(a: std.mem.Allocator, m: *ManagerImpl, id: []const u8) !bool {
            const schema_q = try pg_helpers.quoteIdentifier(a, m.schemaRaw());
            defer a.free(schema_q);
            const q = try std.fmt.allocPrint(a, "SELECT COUNT(*) FROM {s}.memory_entities WHERE user_id = 2 AND id = '{s}'", .{ schema_q, id });
            defer a.free(q);
            const result = try m.exec(q);
            defer c.PQclear(result);
            const s = try dupeResultValue(a, result, 0, 0);
            defer a.free(s);
            return !std.mem.eql(u8, s, "0");
        }
    };
    const edgesTouchingScaffold = struct {
        fn run(a: std.mem.Allocator, m: *ManagerImpl, sid1: []const u8, sid2: []const u8) !i64 {
            const schema_q = try pg_helpers.quoteIdentifier(a, m.schemaRaw());
            defer a.free(schema_q);
            const q = try std.fmt.allocPrint(
                a,
                "SELECT COUNT(*) FROM {s}.memory_edges WHERE user_id = 2 AND " ++
                    "(source_key IN ('{s}','{s}') OR target_key IN ('{s}','{s}'))",
                .{ schema_q, sid1, sid2, sid1, sid2 },
            );
            defer a.free(q);
            const result = try m.exec(q);
            defer c.PQclear(result);
            const s = try dupeResultValue(a, result, 0, 0);
            defer a.free(s);
            return try std.fmt.parseInt(i64, s, 10);
        }
    };

    const entities_before = try countEntities.run(allocator, &mgr);
    try std.testing.expectEqual(@as(i64, 4), entities_before); // 2 scaffold + edges + Helix

    // ── Dry-run: reports the would-be purge, deletes NOTHING.
    const dry = try mgr.phase05Backfill(allocator, 2, true);
    try std.testing.expect(dry.dry_run);
    try std.testing.expectEqual(@as(usize, 2), dry.scaffold_entities_purged); // Brain Architecture + Memory Link Types
    try std.testing.expect(dry.scaffold_edges_purged >= 2); // both scaffold edges counted
    try std.testing.expectEqual(@as(i64, 4), try countEntities.run(allocator, &mgr)); // untouched on disk
    try std.testing.expect(try entityExists.run(allocator, &mgr, scaffold_id));

    // ── Apply: scaffold entities + their edges deleted; genuine survive.
    const r1 = try mgr.phase05Backfill(allocator, 2, false);
    try std.testing.expect(!r1.dry_run);
    try std.testing.expectEqual(@as(usize, 2), r1.scaffold_entities_purged);
    try std.testing.expect(r1.scaffold_edges_purged >= 2);

    try std.testing.expect(!(try entityExists.run(allocator, &mgr, scaffold_id))); // gone
    try std.testing.expect(!(try entityExists.run(allocator, &mgr, scaffold2_id))); // gone
    try std.testing.expectEqual(@as(i64, 0), try edgesTouchingScaffold.run(allocator, &mgr, scaffold_id, scaffold2_id)); // edges gone

    // Genuine entity + its edge survive (no over-purge).
    try std.testing.expect(try entityExists.run(allocator, &mgr, helix_id));
    {
        const schema_q = try pg_helpers.quoteIdentifier(allocator, mgr.schemaRaw());
        defer allocator.free(schema_q);
        const q = try std.fmt.allocPrint(allocator, "SELECT COUNT(*) FROM {s}.memory_edges WHERE user_id = 2 AND target_key = '{s}'", .{ schema_q, helix_id });
        defer allocator.free(q);
        const result = try mgr.exec(q);
        defer c.PQclear(result);
        const s = try dupeResultValue(allocator, result, 0, 0);
        defer allocator.free(s);
        try std.testing.expectEqualStrings("1", s); // Helix's USES edge intact
    }

    // ── Idempotent: second apply finds nothing left to purge.
    const r2 = try mgr.phase05Backfill(allocator, 2, false);
    try std.testing.expectEqual(@as(usize, 0), r2.scaffold_entities_purged);
    try std.testing.expectEqual(@as(usize, 0), r2.scaffold_edges_purged);
}

test "setMemorySource preserves updated_at for attribution-only enrichment" {
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;

    var mgr = initPostgresTestManagerWithPool(allocator, 2, 500) catch return error.SkipZigTest;
    defer mgr.deinit();
    try mgr.provisionUser(2, "/tmp/nullalis-zaki-bot-test-user-2/workspace");

    const key = "source_no_recency_bump";
    const metadata =
        \\{"subject":"user","predicate":"PREFERS","object":"Helix"}
    ;
    try mgr.upsertMemoryWithMetadata(
        2,
        key,
        "User prefers Helix",
        .core,
        "session-A",
        metadata,
    );

    const schema_q = try pg_helpers.quoteIdentifier(allocator, mgr.schemaRaw());
    defer allocator.free(schema_q);
    const fixed_updated_at: i64 = 1_700_000_000;

    {
        const q = try std.fmt.allocPrint(
            allocator,
            "UPDATE {s}.memories SET updated_at = TO_TIMESTAMP({d}) WHERE user_id = 2 AND key = '{s}'",
            .{ schema_q, fixed_updated_at, key },
        );
        defer allocator.free(q);
        const result = try mgr.exec(q);
        c.PQclear(result);
    }

    try mgr.setMemorySource(2, key, "session-A", "snippet A");

    {
        const q = try std.fmt.allocPrint(
            allocator,
            "SELECT COALESCE((EXTRACT(EPOCH FROM updated_at))::bigint, 0) FROM {s}.memories WHERE user_id = 2 AND key = '{s}'",
            .{ schema_q, key },
        );
        defer allocator.free(q);
        const result = try mgr.exec(q);
        defer c.PQclear(result);
        try std.testing.expectEqual(@as(c_int, 1), c.PQntuples(result));
        const updated_at_text = try dupeResultValue(allocator, result, 0, 0);
        defer allocator.free(updated_at_text);
        const updated_at = try std.fmt.parseInt(i64, updated_at_text, 10);
        try std.testing.expectEqual(fixed_updated_at, updated_at);
    }

    var source = (try mgr.getMemorySource(allocator, 2, key)).?;
    defer source.deinit(allocator);
    try std.testing.expectEqualStrings("session-A", source.session_id.?);
    try std.testing.expectEqualStrings("snippet A", source.snippet.?);
}

// ─────────────────────────────────────────────────────────────────────
// P0-6 (2026-06-11) — ensureUserRow self-heals the parent users row at
// the ensureSession chokepoint, closing the sessions_user_id_fkey /
// memories_user_id_fkey violations seen in GlitchTip (user_ids 72, 75).
//
// Two tests:
//   (1) compat-mode integration (runs in the default suite) — covers
//       acceptance (a) self-heal succeeds and (c) zero regression for an
//       already-provisioned user. public.zaki_users is absent (the suite's
//       standing contract — every other PG test relies on it being absent
//       so provisionUser runs in compatibility mode), so the self-heal
//       INSERT lands on the tenant users PK without an FK probe.
//   (2) live-identity rejection (opt-in via NULLALIS_PG_IDENTITY_TEST=1) —
//       covers acceptance (b). It must create the SHARED public.zaki_users
//       table to make hasExternalIdentity return a definitive false for a
//       bogus id; that mutation would break the other PG test binaries that
//       run in parallel and assume the table is absent, so it is gated off
//       by default (same precedent as NULLALIS_MCP_LIVE_TEST). It restores
//       the prior state on the way out.
// ─────────────────────────────────────────────────────────────────────
test "P0-6 ensureUserRow self-heals missing users row at session write (compat mode)" {
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;

    var mgr = initPostgresTestManagerWithPool(allocator, 2, 500) catch return error.SkipZigTest;
    defer mgr.deinit();

    const schema_q = try pg_helpers.quoteIdentifier(allocator, mgr.schemaRaw());
    defer allocator.free(schema_q);

    const user_id: i64 = 72;

    // ── (a) users row ABSENT → a session write must self-heal it ──────────────
    // No provisionUser call: the parent users row does not exist yet, so a
    // pre-P0-6 write would fault on sessions_user_id_fkey. ensureUserRow at the
    // ensureSession chokepoint must create the parent row first and succeed.
    try mgr.saveSessionMessage(user_id, "agent:zaki-bot:user:72:main", "user", "hello");

    {
        const q = try std.fmt.allocPrint(allocator, "SELECT workspace_path FROM {s}.users WHERE user_id = {d}", .{ schema_q, user_id });
        defer allocator.free(q);
        const result = try mgr.exec(q);
        defer c.PQclear(result);
        try std.testing.expectEqual(@as(c_int, 1), c.PQntuples(result));
        const ws = try dupeResultValue(allocator, result, 0, 0);
        defer allocator.free(ws);
        // Default workspace_path derived the {data_root}/{user_id}/workspace way.
        try std.testing.expectEqualStrings("/data/users/72/workspace", ws);
    }
    {
        const q = try std.fmt.allocPrint(allocator, "SELECT COUNT(*) FROM {s}.messages WHERE user_id = {d}", .{ schema_q, user_id });
        defer allocator.free(q);
        const result = try mgr.exec(q);
        defer c.PQclear(result);
        const cnt = try dupeResultValue(allocator, result, 0, 0);
        defer allocator.free(cnt);
        try std.testing.expectEqualStrings("1", cnt);
    }

    // ── (c) zero regression for an already-provisioned user ──────────────────
    // provisionUser seeds a real workspace_path; the self-heal upsert is
    // ON CONFLICT (user_id) DO NOTHING, so a subsequent session write must NOT
    // overwrite it (the placeholder default never clobbers an existing row).
    try mgr.provisionUser(user_id, "/data/users/72/real-workspace");
    try mgr.saveSessionMessage(user_id, "agent:zaki-bot:user:72:system", "user", "again");
    {
        const q = try std.fmt.allocPrint(allocator, "SELECT workspace_path FROM {s}.users WHERE user_id = {d}", .{ schema_q, user_id });
        defer allocator.free(q);
        const result = try mgr.exec(q);
        defer c.PQclear(result);
        const ws = try dupeResultValue(allocator, result, 0, 0);
        defer allocator.free(ws);
        try std.testing.expectEqualStrings("/data/users/72/real-workspace", ws);
    }
}

test "P0-6 ensureUserRow rejects bogus id with typed identity error (live zaki_users)" {
    if (!build_options.enable_postgres) return error.SkipZigTest;
    // Opt-in: this test creates the SHARED public.zaki_users table, which the
    // other parallel PG test binaries assume is absent. Gated off by default to
    // avoid flaking them; run explicitly with NULLALIS_PG_IDENTITY_TEST=1.
    const gate = std.process.getEnvVarOwned(std.heap.page_allocator, "NULLALIS_PG_IDENTITY_TEST") catch {
        std.debug.print("[p0-6-identity] skipped (set NULLALIS_PG_IDENTITY_TEST=1 to run)\n", .{});
        return error.SkipZigTest;
    };
    defer std.heap.page_allocator.free(gate);

    const allocator = std.testing.allocator;
    const test_url = (env_rebrand.getEnvOwnedWithRebrand(allocator, "NULLALIS_POSTGRES_TEST_URL", "NULLCLAW_POSTGRES_TEST_URL") catch return error.SkipZigTest) orelse return error.SkipZigTest;
    defer allocator.free(test_url);

    var schema_buf: [96]u8 = undefined;
    const schema = try std.fmt.bufPrint(&schema_buf, "zaki_bot_test_{d}", .{std.time.microTimestamp()});
    const cfg = config_types.StateConfig{
        .backend = "postgres",
        .postgres = .{ .connection_string = test_url, .schema = schema },
    };

    var mgr = try ManagerImpl.init(allocator, cfg);
    defer mgr.deinit();

    // Clean tenant schema.
    {
        const schema_q = try pg_helpers.quoteIdentifier(allocator, mgr.schemaRaw());
        defer allocator.free(schema_q);
        const drop_q = try std.fmt.allocPrint(allocator, "DROP SCHEMA IF EXISTS {s} CASCADE", .{schema_q});
        defer allocator.free(drop_q);
        const result = try mgr.exec(drop_q);
        c.PQclear(result);
    }

    // Stand up the secondary FK target BEFORE migrate so users_user_id_fkey
    // actually attaches and a bogus id would genuinely fault on it (proving the
    // identity gate — not luck — is what produces the clean typed error). Seed a
    // valid id; ensure the bogus id is genuinely absent. Restore on the way out.
    const valid_id: i64 = 72;
    const bogus_id: i64 = 999_972;
    {
        const r1 = try mgr.exec("CREATE TABLE IF NOT EXISTS public.zaki_users (id BIGINT PRIMARY KEY)");
        c.PQclear(r1);
        const seed = try std.fmt.allocPrint(allocator, "INSERT INTO public.zaki_users (id) VALUES ({d}) ON CONFLICT (id) DO NOTHING", .{valid_id});
        defer allocator.free(seed);
        const r2 = try mgr.exec(seed);
        c.PQclear(r2);
        const del = try std.fmt.allocPrint(allocator, "DELETE FROM public.zaki_users WHERE id = {d}", .{bogus_id});
        defer allocator.free(del);
        const r3 = try mgr.exec(del);
        c.PQclear(r3);
    }
    defer {
        // Restore: drop the shared FK target we created so the suite's standing
        // "public.zaki_users is absent" contract holds for the next run.
        const r = mgr.exec("DROP TABLE IF EXISTS public.zaki_users CASCADE") catch null;
        if (r) |res| c.PQclear(res);
    }

    try mgr.migrate();

    const schema_q = try pg_helpers.quoteIdentifier(allocator, mgr.schemaRaw());
    defer allocator.free(schema_q);

    // ── (a-control) valid id self-heals even with the FK attached ─────────────
    try mgr.saveSessionMessage(valid_id, "agent:zaki-bot:user:72:main", "user", "hello");
    {
        const q = try std.fmt.allocPrint(allocator, "SELECT COUNT(*) FROM {s}.users WHERE user_id = {d}", .{ schema_q, valid_id });
        defer allocator.free(q);
        const result = try mgr.exec(q);
        defer c.PQclear(result);
        const cnt = try dupeResultValue(allocator, result, 0, 0);
        defer allocator.free(cnt);
        try std.testing.expectEqualStrings("1", cnt);
    }

    // ── (b) bogus id → clean typed identity error, NEVER a raw *_user_id_fkey ──
    const err = mgr.saveSessionMessage(bogus_id, "agent:zaki-bot:user:999972:main", "user", "nope");
    try std.testing.expectError(error.IdentityUserNotFound, err);
    {
        // And nothing leaked into the tenant tables for the bogus id.
        const q = try std.fmt.allocPrint(allocator, "SELECT COUNT(*) FROM {s}.users WHERE user_id = {d}", .{ schema_q, bogus_id });
        defer allocator.free(q);
        const result = try mgr.exec(q);
        defer c.PQclear(result);
        const cnt = try dupeResultValue(allocator, result, 0, 0);
        defer allocator.free(cnt);
        try std.testing.expectEqualStrings("0", cnt);
    }
}

// ─────────────────────────────────────────────────────────────────────
// P1-7 (2026-06-12) — provisionUser is ATOMIC. The 6 provisioning inserts
// (users, user_config, heartbeat, channel_state, onboarding, sessions)
// run inside a single connection-pinned transaction, so a mid-provision
// failure rolls back ALL of them — no half-provisioned state where the
// users row exists but its config/heartbeat/sessions don't (or vice
// versa). Pre-P1-7 each insert was a separate autocommit statement on a
// (potentially different) pooled connection, so a failure on insert N
// left rows 1..N-1 committed.
//
// Induce a deterministic mid-provision failure by DROPPING one of the
// later insert targets (onboarding, the 5th insert) so its INSERT faults.
// Acceptance: the FIRST insert's users row must NOT survive (proving the
// whole batch rolled back), and after restoring the table a clean
// re-provision must land all 6 rows.
// ─────────────────────────────────────────────────────────────────────
test "P1-7 provisionUser is atomic — mid-provision failure leaves no partial rows" {
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;

    var mgr = initPostgresTestManagerWithPool(allocator, 4, 5000) catch return error.SkipZigTest;
    defer mgr.deinit();

    const schema_q = try pg_helpers.quoteIdentifier(allocator, mgr.schemaRaw());
    defer allocator.free(schema_q);

    const user_id: i64 = 4242;

    // Snapshot the onboarding DDL so we can recreate it after the induced
    // failure. Simplest deterministic break: drop the table so the 5th
    // insert (onboarding) faults with `relation does not exist`. The
    // first four inserts (users, user_config, heartbeat, channel_state)
    // and the BEGIN have already run on the pinned txn conn; an atomic
    // provisionUser must ROLLBACK them.
    {
        const drop_q = try std.fmt.allocPrint(allocator, "ALTER TABLE {s}.onboarding RENAME TO onboarding_p1_7_stash", .{schema_q});
        defer allocator.free(drop_q);
        const r = try mgr.exec(drop_q);
        c.PQclear(r);
    }

    // The provision MUST fail (onboarding insert faults).
    const provision_err = mgr.provisionUser(user_id, "/data/users/4242/workspace");
    try std.testing.expectError(error.ExecFailed, provision_err);

    // Restore the table BEFORE the assertions/re-provision below.
    {
        const restore_q = try std.fmt.allocPrint(allocator, "ALTER TABLE {s}.onboarding_p1_7_stash RENAME TO onboarding", .{schema_q});
        defer allocator.free(restore_q);
        const r = try mgr.exec(restore_q);
        c.PQclear(r);
    }

    // ── ATOMICITY ASSERTION — NO partial rows ──
    // The users row from the (committed, pre-P1-7) first insert must be
    // gone: the whole transaction rolled back. Pre-P1-7 this row would
    // survive (separate autocommit insert) → count == 1 → test fails.
    inline for (.{ "users", "user_config", "heartbeat", "channel_state" }) |tbl| {
        const q = try std.fmt.allocPrint(allocator, "SELECT COUNT(*) FROM {s}.{s} WHERE user_id = {d}", .{ schema_q, tbl, user_id });
        defer allocator.free(q);
        const result = try mgr.exec(q);
        defer c.PQclear(result);
        const cnt = try dupeResultValue(allocator, result, 0, 0);
        defer allocator.free(cnt);
        try std.testing.expectEqualStrings("0", cnt);
    }

    // ── RECOVERY — a clean re-provision lands all 6 rows ──
    try mgr.provisionUser(user_id, "/data/users/4242/workspace");
    inline for (.{ "users", "user_config", "heartbeat", "channel_state", "onboarding" }) |tbl| {
        const q = try std.fmt.allocPrint(allocator, "SELECT COUNT(*) FROM {s}.{s} WHERE user_id = {d}", .{ schema_q, tbl, user_id });
        defer allocator.free(q);
        const result = try mgr.exec(q);
        defer c.PQclear(result);
        const cnt = try dupeResultValue(allocator, result, 0, 0);
        defer allocator.free(cnt);
        try std.testing.expectEqualStrings("1", cnt);
    }
    {
        const q = try std.fmt.allocPrint(allocator, "SELECT COUNT(*) FROM {s}.sessions WHERE user_id = {d}", .{ schema_q, user_id });
        defer allocator.free(q);
        const result = try mgr.exec(q);
        defer c.PQclear(result);
        const cnt = try dupeResultValue(allocator, result, 0, 0);
        defer allocator.free(cnt);
        try std.testing.expectEqualStrings("1", cnt);
    }
}

// ─────────────────────────────────────────────────────────────────────
// P1-8 (2026-06-12) — close the FK class on the SESSION-LESS memory write
// lane. upsertMemory / upsertMemoryWithMetadataAndEventType gate
// ensureSession (hence ensureUserRow) behind `if (session_id) |sid|`, and
// the brain_compose gateway handler writes with session_id=null. Pre-P1-8
// a null-session write for a never-provisioned user bypassed ensureUserRow
// entirely and faulted memories_user_id_fkey. P1-8 adds an ensureUserRow
// call on the null-session branch so the parent users row self-heals and
// the memory lands on ANY lane.
// ─────────────────────────────────────────────────────────────────────
test "P1-8 session-less memory write self-heals users row (no memories_user_id_fkey)" {
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;

    var mgr = initPostgresTestManagerWithPool(allocator, 4, 5000) catch return error.SkipZigTest;
    defer mgr.deinit();

    const schema_q = try pg_helpers.quoteIdentifier(allocator, mgr.schemaRaw());
    defer allocator.free(schema_q);

    const user_id: i64 = 8181;

    // NO provisionUser, NO session: this is the brain_compose lane —
    // upsertMemoryWithMetadata(..., session_id = null, ...). Pre-P1-8 this
    // skips ensureSession (so ensureUserRow never runs) and the INSERT
    // faults on memories_user_id_fkey (the parent users row is absent).
    // compat mode: public.zaki_users is absent → hasExternalIdentity
    // returns null → ensureUserRow inserts the row on the tenant PK.
    try mgr.upsertMemoryWithMetadata(
        user_id,
        "compose:p1_8_no_session",
        "a fact composed with no session",
        .core,
        null,
        \\{"synthesized_by":"user"}
        ,
    );

    // The parent users row self-healed.
    {
        const q = try std.fmt.allocPrint(allocator, "SELECT workspace_path FROM {s}.users WHERE user_id = {d}", .{ schema_q, user_id });
        defer allocator.free(q);
        const result = try mgr.exec(q);
        defer c.PQclear(result);
        try std.testing.expectEqual(@as(c_int, 1), c.PQntuples(result));
        const ws = try dupeResultValue(allocator, result, 0, 0);
        defer allocator.free(ws);
        try std.testing.expectEqualStrings("/data/users/8181/workspace", ws);
    }
    // And the memory landed.
    {
        const entry = (try mgr.getMemory(allocator, user_id, "compose:p1_8_no_session")) orelse return error.TestUnexpectedResult;
        defer entry.deinit(allocator);
        try std.testing.expectEqualStrings("a fact composed with no session", entry.content);
    }

    // The simple upsertMemory null-session path is also gated — exercise it
    // for a fresh never-provisioned id to prove the same self-heal.
    const user_id2: i64 = 8282;
    try mgr.upsertMemory(user_id2, "p1_8_simple_no_session", "simple null-session fact", .core, null);
    {
        const q = try std.fmt.allocPrint(allocator, "SELECT COUNT(*) FROM {s}.users WHERE user_id = {d}", .{ schema_q, user_id2 });
        defer allocator.free(q);
        const result = try mgr.exec(q);
        defer c.PQclear(result);
        const cnt = try dupeResultValue(allocator, result, 0, 0);
        defer allocator.free(cnt);
        try std.testing.expectEqualStrings("1", cnt);
    }
}

// ─────────────────────────────────────────────────────────────────────
// P1-8 (2026-06-12) — daemon cron/heartbeat/wake lane gate. The daemon
// (daemon.zig runScheduledJobTurnWithRuntime) calls
// Manager.ensureUserProvisioned BEFORE a scheduled turn, so a turn for a
// never-provisioned user provisions-first instead of writing orphan rows
// that fault *_user_id_fkey. This test exercises that public chokepoint
// directly (the full runtime+scheduler harness needed to drive
// runScheduledJobTurnWithRuntime end to end does not exist in the test
// suite; this covers the exact mechanism the daemon-lane fix relies on):
//   (a) never-provisioned user → users row self-heals.
//   (c) already-provisioned user → no-op, authoritative workspace_path
//       preserved (ON CONFLICT DO NOTHING).
// Acceptance (b) — bogus-id rejection on the live-identity path — is
// covered by the P0-6 live-identity test, since ensureUserProvisioned
// delegates to the same ensureUserRow identity gate.
// ─────────────────────────────────────────────────────────────────────
test "P1-8 daemon lane ensureUserProvisioned self-heals users row (no *_user_id_fkey)" {
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;

    var mgr = initPostgresTestManagerWithPool(allocator, 2, 500) catch return error.SkipZigTest;
    defer mgr.deinit();

    const schema_q = try pg_helpers.quoteIdentifier(allocator, mgr.schemaRaw());
    defer allocator.free(schema_q);

    const user_id: i64 = 5151;

    // ── (a) never-provisioned → self-heal ──
    try mgr.ensureUserProvisioned(user_id);
    {
        const q = try std.fmt.allocPrint(allocator, "SELECT workspace_path FROM {s}.users WHERE user_id = {d}", .{ schema_q, user_id });
        defer allocator.free(q);
        const result = try mgr.exec(q);
        defer c.PQclear(result);
        try std.testing.expectEqual(@as(c_int, 1), c.PQntuples(result));
        const ws = try dupeResultValue(allocator, result, 0, 0);
        defer allocator.free(ws);
        try std.testing.expectEqualStrings("/data/users/5151/workspace", ws);
    }

    // ── (c) already-provisioned → no-op, authoritative path preserved ──
    try mgr.provisionUser(user_id, "/data/users/5151/real-workspace");
    try mgr.ensureUserProvisioned(user_id); // must NOT clobber the real path
    {
        const q = try std.fmt.allocPrint(allocator, "SELECT workspace_path FROM {s}.users WHERE user_id = {d}", .{ schema_q, user_id });
        defer allocator.free(q);
        const result = try mgr.exec(q);
        defer c.PQclear(result);
        const ws = try dupeResultValue(allocator, result, 0, 0);
        defer allocator.free(ws);
        try std.testing.expectEqualStrings("/data/users/5151/real-workspace", ws);
    }

    // And a session write for the provisioned user lands cleanly (the
    // daemon turn's downstream write — no FK fault on the parent row).
    try mgr.saveSessionMessage(user_id, "agent:zaki-bot:user:5151:main", "user", "scheduled turn");
    {
        const q = try std.fmt.allocPrint(allocator, "SELECT COUNT(*) FROM {s}.messages WHERE user_id = {d}", .{ schema_q, user_id });
        defer allocator.free(q);
        const result = try mgr.exec(q);
        defer c.PQclear(result);
        const cnt = try dupeResultValue(allocator, result, 0, 0);
        defer allocator.free(cnt);
        try std.testing.expectEqualStrings("1", cnt);
    }
}

// ─────────────────────────────────────────────────────────────────────
// P1-9 (2026-06-12) — external-identity fail-open cache TTL. The
// `.unavailable` short-circuit in hasExternalIdentity is TTL'd so a
// transient probe failure self-heals instead of permanently disabling
// identity verification. The TTL boundary lives in the pure
// shouldReprobeExternalIdentity helper, unit-tested here (no PG needed).
// ─────────────────────────────────────────────────────────────────────
test "P1-9 external-identity TTL: re-probe boundary" {
    const ttl: i64 = EXTERNAL_IDENTITY_REPROBE_MS;
    const base: i64 = 1_000_000_000_000; // arbitrary wall-clock ms

    // Not latched (.unknown / .available) → always probe.
    try std.testing.expect(shouldReprobeExternalIdentity(false, 0, base, ttl));
    try std.testing.expect(shouldReprobeExternalIdentity(false, base, base, ttl));

    // Latched, BEFORE the window elapses → fail open (no re-probe).
    try std.testing.expect(!shouldReprobeExternalIdentity(true, base, base, ttl)); // 0ms since latch
    try std.testing.expect(!shouldReprobeExternalIdentity(true, base, base + ttl - 1, ttl)); // just inside

    // Latched, AT/AFTER the window → re-probe (self-heal opportunity).
    try std.testing.expect(shouldReprobeExternalIdentity(true, base, base + ttl, ttl)); // exact boundary
    try std.testing.expect(shouldReprobeExternalIdentity(true, base, base + ttl + 1, ttl));
    try std.testing.expect(shouldReprobeExternalIdentity(true, base, base + 10 * ttl, ttl));

    // Test-pin sentinel → NEVER re-probe even far past any window.
    try std.testing.expect(!shouldReprobeExternalIdentity(true, EXTERNAL_IDENTITY_PIN_FOREVER, base, ttl));
    try std.testing.expect(!shouldReprobeExternalIdentity(true, EXTERNAL_IDENTITY_PIN_FOREVER, EXTERNAL_IDENTITY_PIN_FOREVER, ttl));
}

// P1-9 — live-DB self-heal: a single transient probe failure latches
// `.unavailable`, but a re-probe after the TTL window flips the gate back
// to `.available`. Drives the real hasExternalIdentity against pgvector PG:
// stand up public.zaki_users, force the latch via the stash/rename trick,
// rewind the latch timestamp past the TTL to simulate the window elapsing,
// then confirm the next call re-probes and clears the latch.
test "P1-9 hasExternalIdentity self-heals after TTL window (live PG)" {
    if (!build_options.enable_postgres) return error.SkipZigTest;
    // Opt-in: mutates the SHARED public.zaki_users table other parallel PG
    // test binaries assume is absent — same gate/precedent as the P0-6
    // live-identity test. Run with NULLALIS_PG_IDENTITY_TEST=1.
    const gate = std.process.getEnvVarOwned(std.heap.page_allocator, "NULLALIS_PG_IDENTITY_TEST") catch {
        std.debug.print("[p1-9-ttl] skipped (set NULLALIS_PG_IDENTITY_TEST=1 to run)\n", .{});
        return error.SkipZigTest;
    };
    defer std.heap.page_allocator.free(gate);

    const allocator = std.testing.allocator;
    var mgr = initPostgresTestManagerWithPool(allocator, 2, 5000) catch return error.SkipZigTest;
    defer mgr.deinit();

    const valid_id: i64 = 71;
    // Stand up the shared identity table with a valid id seeded. Restore
    // (drop) on the way out so the suite's "table absent" contract holds.
    {
        const r1 = try mgr.exec("CREATE TABLE IF NOT EXISTS public.zaki_users (id BIGINT PRIMARY KEY)");
        c.PQclear(r1);
        const seed = try std.fmt.allocPrint(allocator, "INSERT INTO public.zaki_users (id) VALUES ({d}) ON CONFLICT (id) DO NOTHING", .{valid_id});
        defer allocator.free(seed);
        const r2 = try mgr.exec(seed);
        c.PQclear(r2);
    }
    defer {
        const r = mgr.exec("DROP TABLE IF EXISTS public.zaki_users CASCADE") catch null;
        if (r) |res| c.PQclear(res);
    }

    // Baseline: probe succeeds, gate available, valid id resolves true.
    try std.testing.expectEqual(@as(?bool, true), try mgr.hasExternalIdentity(valid_id));
    try std.testing.expect(mgr.external_identity_status == .available);

    // Induce a transient probe failure by renaming the table away, then
    // probing once → latches `.unavailable` (fail-open returns null).
    {
        const r = try mgr.exec("ALTER TABLE public.zaki_users RENAME TO zaki_users_p1_9_stash");
        c.PQclear(r);
    }
    try std.testing.expectEqual(@as(?bool, null), try mgr.hasExternalIdentity(valid_id));
    try std.testing.expect(mgr.external_identity_status == .unavailable);

    // Restore the table — the "transient" failure is over.
    {
        const r = try mgr.exec("ALTER TABLE public.zaki_users_p1_9_stash RENAME TO zaki_users");
        c.PQclear(r);
    }

    // WITHIN the TTL window the gate stays fail-open (still null) — proves
    // we keep the noisy-log mitigation and don't hammer the probe.
    try std.testing.expectEqual(@as(?bool, null), try mgr.hasExternalIdentity(valid_id));
    try std.testing.expect(mgr.external_identity_status == .unavailable);

    // Simulate the TTL window elapsing by rewinding the latch timestamp
    // past the re-probe horizon. The next call must re-probe → succeed →
    // self-heal back to `.available` and resolve the valid id true.
    mgr.external_identity_unavailable_since_ms -= (EXTERNAL_IDENTITY_REPROBE_MS + 1);
    try std.testing.expectEqual(@as(?bool, true), try mgr.hasExternalIdentity(valid_id));
    try std.testing.expect(mgr.external_identity_status == .available);
}

// ─────────────────────────────────────────────────────────────────────
// V1.14.12 (Memory audit Finding 3 fix, 2026-05-19) — TxnLease tests.
//
// These exercise the connection-pinned transaction primitive that
// replaced the broken `exec("BEGIN") + execParams(...) + exec("COMMIT")`
// pattern in 7 production sites. Each call previously acquired and
// released a pool connection per statement, so multi-statement
// transactions silently split across N connections and ROLLBACK ran
// on a different conn (no-op). TxnLease holds one connection across
// the entire BEGIN→COMMIT/ROLLBACK lifecycle.
// ─────────────────────────────────────────────────────────────────────

test "TxnLease: commit persists writes" {
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;
    var mgr = initPostgresTestManagerWithPool(allocator, 4, 5000) catch return error.SkipZigTest;
    defer mgr.deinit();

    // Finding B fix (coordinator review, 2026-05-21): user 7777 must be
    // provisioned before any memories write — memories.user_id carries an FK
    // to users(user_id) (0001_initial_schema.sql). Without provisionUser,
    // upsertMemory fails with `error.ExecFailed` (FK violation), failing the
    // test. Latent: pg tests skip unless NULLALIS_POSTGRES_TEST_URL is set,
    // so this never ran green against a live DB.
    try mgr.provisionUser(7777, "/tmp/nullalis-zaki-bot-test-user-7777/workspace");
    try mgr.upsertMemory(7777, "txn_commit_baseline", "before", .core, null);

    {
        var txn = try mgr.beginTransaction();
        defer txn.deinit();
        const schema_q = try pg_helpers.quoteIdentifier(allocator, mgr.schemaRaw());
        defer allocator.free(schema_q);
        const q = try std.fmt.allocPrintSentinel(allocator, "UPDATE {s}.memories SET content = $2 WHERE user_id = 7777 AND key = $1", .{schema_q}, 0);
        defer allocator.free(q);
        const key_z = try allocator.dupeZ(u8, "txn_commit_baseline");
        defer allocator.free(key_z);
        const val_z = try allocator.dupeZ(u8, "committed");
        defer allocator.free(val_z);
        const params = [_]?[*:0]const u8{ key_z, val_z };
        const lengths = [_]c_int{ @intCast(@as(usize, "txn_commit_baseline".len)), @intCast(@as(usize, "committed".len)) };
        const r = try txn.execParams(q, &params, &lengths);
        c.PQclear(r);
        try txn.commit();
    }

    const entry = (try mgr.getMemory(allocator, 7777, "txn_commit_baseline")) orelse return error.TestUnexpectedResult;
    defer entry.deinit(allocator);
    try std.testing.expectEqualStrings("committed", entry.content);
}

test "TxnLease: rollback discards writes" {
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;
    var mgr = initPostgresTestManagerWithPool(allocator, 4, 5000) catch return error.SkipZigTest;
    defer mgr.deinit();

    // Finding B fix (coordinator review, 2026-05-21): provision user 7777
    // before the memories write — see "TxnLease: commit persists writes".
    try mgr.provisionUser(7777, "/tmp/nullalis-zaki-bot-test-user-7777/workspace");
    try mgr.upsertMemory(7777, "txn_rollback_baseline", "before", .core, null);

    {
        var txn = try mgr.beginTransaction();
        defer txn.deinit();
        const schema_q = try pg_helpers.quoteIdentifier(allocator, mgr.schemaRaw());
        defer allocator.free(schema_q);
        const q = try std.fmt.allocPrintSentinel(allocator, "UPDATE {s}.memories SET content = $2 WHERE user_id = 7777 AND key = $1", .{schema_q}, 0);
        defer allocator.free(q);
        const key_z = try allocator.dupeZ(u8, "txn_rollback_baseline");
        defer allocator.free(key_z);
        const val_z = try allocator.dupeZ(u8, "should_not_persist");
        defer allocator.free(val_z);
        const params = [_]?[*:0]const u8{ key_z, val_z };
        const lengths = [_]c_int{ @intCast(@as(usize, "txn_rollback_baseline".len)), @intCast(@as(usize, "should_not_persist".len)) };
        const r = try txn.execParams(q, &params, &lengths);
        c.PQclear(r);
        txn.rollback();
        // Explicit rollback — content must remain "before".
    }

    const entry = (try mgr.getMemory(allocator, 7777, "txn_rollback_baseline")) orelse return error.TestUnexpectedResult;
    defer entry.deinit(allocator);
    try std.testing.expectEqualStrings("before", entry.content);
}

test "TxnLease: deinit without commit rolls back (defensive)" {
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;
    var mgr = initPostgresTestManagerWithPool(allocator, 4, 5000) catch return error.SkipZigTest;
    defer mgr.deinit();

    // Finding B fix (coordinator review, 2026-05-21): provision user 7777
    // before the memories write — see "TxnLease: commit persists writes".
    try mgr.provisionUser(7777, "/tmp/nullalis-zaki-bot-test-user-7777/workspace");
    try mgr.upsertMemory(7777, "txn_deinit_baseline", "before", .core, null);

    {
        var txn = try mgr.beginTransaction();
        defer txn.deinit(); // intentional: no explicit commit/rollback
        const schema_q = try pg_helpers.quoteIdentifier(allocator, mgr.schemaRaw());
        defer allocator.free(schema_q);
        const q = try std.fmt.allocPrintSentinel(allocator, "UPDATE {s}.memories SET content = $2 WHERE user_id = 7777 AND key = $1", .{schema_q}, 0);
        defer allocator.free(q);
        const key_z = try allocator.dupeZ(u8, "txn_deinit_baseline");
        defer allocator.free(key_z);
        const val_z = try allocator.dupeZ(u8, "should_not_persist");
        defer allocator.free(val_z);
        const params = [_]?[*:0]const u8{ key_z, val_z };
        const lengths = [_]c_int{ @intCast(@as(usize, "txn_deinit_baseline".len)), @intCast(@as(usize, "should_not_persist".len)) };
        const r = try txn.execParams(q, &params, &lengths);
        c.PQclear(r);
        // Scope ends here; defer txn.deinit() fires → rollback.
    }

    const entry = (try mgr.getMemory(allocator, 7777, "txn_deinit_baseline")) orelse return error.TestUnexpectedResult;
    defer entry.deinit(allocator);
    try std.testing.expectEqualStrings("before", entry.content);
}

test "TxnLease: commit and rollback are idempotent" {
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;
    var mgr = initPostgresTestManagerWithPool(allocator, 4, 5000) catch return error.SkipZigTest;
    defer mgr.deinit();

    var txn = try mgr.beginTransaction();
    try txn.commit();
    // Second commit is a no-op (finalized flag).
    try txn.commit();
    // Rollback after commit is a no-op.
    txn.rollback();
    // deinit after both is a no-op.
    txn.deinit();
}

test "TxnLease: pool-split regression — overlapping txns each see their own state" {
    // Regression test for the pre-fix bug. Pre-fix, the second
    // `beginTransaction` (well, the broken `exec("BEGIN")` pattern)
    // could land on the same connection that the first transaction
    // had not yet returned a COMMIT for — and any subsequent
    // execParams calls from the FIRST flow would land on a DIFFERENT
    // pool conn, silently auto-committing.
    //
    // With TxnLease, each transaction holds its conn exclusively;
    // pool_max=2 ensures two TxnLeases CAN exist concurrently without
    // colliding. We sequentially run two leases, both committing
    // distinct rows, both visible after.
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;
    var mgr = initPostgresTestManagerWithPool(allocator, 2, 5000) catch return error.SkipZigTest;
    defer mgr.deinit();

    // Finding B fix (coordinator review, 2026-05-21): the inline-for below
    // INSERTs rows into {schema}.memories with a literal user_id of 7777.
    // memories.user_id has an FK to users(user_id) — provision 7777 first
    // or both INSERTs fail with `error.ExecFailed` (FK violation).
    try mgr.provisionUser(7777, "/tmp/nullalis-zaki-bot-test-user-7777/workspace");

    var txn_a = try mgr.beginTransaction();
    defer txn_a.deinit();
    var txn_b = try mgr.beginTransaction();
    defer txn_b.deinit();

    // Each txn writes its own row via a direct INSERT.
    const schema_q = try pg_helpers.quoteIdentifier(allocator, mgr.schemaRaw());
    defer allocator.free(schema_q);

    inline for ([_]struct { txn_idx: u8, key: []const u8 }{
        .{ .txn_idx = 0, .key = "txn_split_a" },
        .{ .txn_idx = 1, .key = "txn_split_b" },
    }) |spec| {
        const id_buf = try std.fmt.allocPrint(allocator, "txn_split_id_{s}", .{spec.key});
        defer allocator.free(id_buf);
        const q = try std.fmt.allocPrintSentinel(
            allocator,
            "INSERT INTO {s}.memories (id, user_id, key, content, memory_type) VALUES ($1, 7777, $2, $3, 'core')",
            .{schema_q},
            0,
        );
        defer allocator.free(q);
        const id_z = try allocator.dupeZ(u8, id_buf);
        defer allocator.free(id_z);
        const key_z = try allocator.dupeZ(u8, spec.key);
        defer allocator.free(key_z);
        const val_z = try allocator.dupeZ(u8, "committed");
        defer allocator.free(val_z);
        const params = [_]?[*:0]const u8{ id_z, key_z, val_z };
        const lengths = [_]c_int{ @intCast(@as(usize, id_buf.len)), @intCast(@as(usize, spec.key.len)), @intCast(@as(usize, "committed".len)) };
        const r = if (spec.txn_idx == 0)
            try txn_a.execParams(q, &params, &lengths)
        else
            try txn_b.execParams(q, &params, &lengths);
        c.PQclear(r);
    }

    try txn_a.commit();
    try txn_b.commit();

    const a = (try mgr.getMemory(allocator, 7777, "txn_split_a")) orelse return error.TestUnexpectedResult;
    defer a.deinit(allocator);
    const b = (try mgr.getMemory(allocator, 7777, "txn_split_b")) orelse return error.TestUnexpectedResult;
    defer b.deinit(allocator);
    try std.testing.expectEqualStrings("committed", a.content);
    try std.testing.expectEqualStrings("committed", b.content);
}

test "postgres claimed job one-shot completion preserves run history and disables job in management view" {
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;
    const test_url = (env_rebrand.getEnvOwnedWithRebrand(allocator, "NULLALIS_POSTGRES_TEST_URL", "NULLCLAW_POSTGRES_TEST_URL") catch return error.SkipZigTest) orelse return error.SkipZigTest;
    defer allocator.free(test_url);

    var schema_buf: [96]u8 = undefined;
    const schema = try std.fmt.bufPrint(&schema_buf, "zaki_bot_test_{d}", .{std.time.microTimestamp()});
    const cfg = config_types.StateConfig{
        .backend = "postgres",
        .postgres = .{
            .connection_string = test_url,
            .schema = schema,
        },
    };

    var mgr = try ManagerImpl.init(allocator, cfg);
    defer mgr.deinit();
    {
        const schema_q = try pg_helpers.quoteIdentifier(allocator, mgr.schemaRaw());
        defer allocator.free(schema_q);
        const drop_q = try std.fmt.allocPrint(allocator, "DROP SCHEMA IF EXISTS {s} CASCADE", .{schema_q});
        defer allocator.free(drop_q);
        const result = try mgr.exec(drop_q);
        c.PQclear(result);
    }
    try mgr.migrate();

    try mgr.provisionUser(2, "/tmp/nullalis-zaki-bot-test-user-2/workspace");
    try mgr.replaceJobsJson(2, "agent:zaki-bot:user:2:main", "[{\"id\":\"once-reminder\",\"expression\":\"@once:1m\",\"command\":\"message \\\"hello\\\"\",\"next_run_secs\":1,\"one_shot\":true,\"job_type\":\"agent\",\"session_target\":\"main\",\"prompt\":\"say hello\",\"delivery\":{\"mode\":\"always\",\"channel\":\"telegram\",\"to\":\"chat-2\",\"best_effort\":false}}]");

    const claimed = try mgr.claimDueJobs(allocator, "test-owner", 5, 60, 10);
    defer {
        for (claimed) |*job| job.deinit(allocator);
        allocator.free(claimed);
    }
    try std.testing.expectEqual(@as(usize, 1), claimed.len);
    try std.testing.expectEqual(@as(i64, 2), claimed[0].user_id);
    try std.testing.expect(std.mem.startsWith(u8, claimed[0].id, "user:2:once-reminder"));

    try mgr.completeClaimedJob(2, claimed[0].id, "test-owner", null, null, "ok", "reminder sent", 5, 6);

    const jobs_after = try mgr.getJobsJson(allocator, 2);
    defer allocator.free(jobs_after);
    const parsed_jobs = try std.json.parseFromSlice(std.json.Value, allocator, jobs_after, .{});
    defer parsed_jobs.deinit();
    try std.testing.expect(parsed_jobs.value == .array);
    try std.testing.expectEqual(@as(usize, 1), parsed_jobs.value.array.items.len);
    try std.testing.expectEqualStrings("once-reminder", parsed_jobs.value.array.items[0].object.get("id").?.string);
    try std.testing.expectEqual(false, parsed_jobs.value.array.items[0].object.get("enabled").?.bool);

    const q = try mgr.buildQuery("SELECT COUNT(*) FROM {schema}.job_runs WHERE user_id = $1 AND job_id = $2");
    defer allocator.free(q);
    var user_buf: [32]u8 = undefined;
    const user_z = try std.fmt.bufPrintZ(&user_buf, "{d}", .{2});
    const job_id_z = try allocator.dupeZ(u8, claimed[0].id);
    defer allocator.free(job_id_z);
    const params = [_]?[*:0]const u8{ user_z.ptr, job_id_z };
    const lengths = [_]c_int{ @intCast(user_z.len), @intCast(claimed[0].id.len) };
    const result = try mgr.execParams(q, &params, &lengths);
    defer c.PQclear(result);
    const run_count_text = try dupeResultValue(allocator, result, 0, 0);
    defer allocator.free(run_count_text);
    const run_count = try std.fmt.parseInt(usize, run_count_text, 10);
    try std.testing.expectEqual(@as(usize, 1), run_count);

    const claimed_again = try mgr.claimDueJobs(allocator, "test-owner", 10, 60, 10);
    defer {
        for (claimed_again) |*job| job.deinit(allocator);
        allocator.free(claimed_again);
    }
    try std.testing.expectEqual(@as(usize, 0), claimed_again.len);
}

test "postgres claimed recurring job reschedules and records run" {
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;
    const test_url = (env_rebrand.getEnvOwnedWithRebrand(allocator, "NULLALIS_POSTGRES_TEST_URL", "NULLCLAW_POSTGRES_TEST_URL") catch return error.SkipZigTest) orelse return error.SkipZigTest;
    defer allocator.free(test_url);

    var schema_buf: [96]u8 = undefined;
    const schema = try std.fmt.bufPrint(&schema_buf, "zaki_bot_test_{d}", .{std.time.microTimestamp()});
    const cfg = config_types.StateConfig{
        .backend = "postgres",
        .postgres = .{
            .connection_string = test_url,
            .schema = schema,
        },
    };

    var mgr = try ManagerImpl.init(allocator, cfg);
    defer mgr.deinit();
    {
        const schema_q = try pg_helpers.quoteIdentifier(allocator, mgr.schemaRaw());
        defer allocator.free(schema_q);
        const drop_q = try std.fmt.allocPrint(allocator, "DROP SCHEMA IF EXISTS {s} CASCADE", .{schema_q});
        defer allocator.free(drop_q);
        const result = try mgr.exec(drop_q);
        c.PQclear(result);
    }
    try mgr.migrate();

    try mgr.provisionUser(2, "/tmp/nullalis-zaki-bot-test-user-2/workspace");

    var scheduler = cron_mod.CronScheduler.init(allocator, 1, true);
    defer scheduler.deinit();
    const job = try scheduler.addJob("*/5 * * * *", "echo scheduled");
    const old_id = job.id;
    scheduler.jobs.items[0].id = try allocator.dupe(u8, "recurring-reminder");
    allocator.free(old_id);
    scheduler.jobs.items[0].job_type = .agent;
    scheduler.jobs.items[0].session_target = .main;
    scheduler.jobs.items[0].prompt = try allocator.dupe(u8, "check in");
    scheduler.jobs.items[0].prompt_owned = true;
    scheduler.jobs.items[0].delivery = .{
        .mode = .always,
        .channel = try allocator.dupe(u8, "telegram"),
        .to = try allocator.dupe(u8, "chat-2"),
        .best_effort = true,
    };
    scheduler.jobs.items[0].delivery_channel_owned = true;
    scheduler.jobs.items[0].delivery_to_owned = true;
    scheduler.jobs.items[0].next_run_secs = 10;

    const jobs_json = try cron_mod.saveJobsToSlice(allocator, &scheduler);
    defer allocator.free(jobs_json);
    try mgr.replaceJobsJson(2, "agent:zaki-bot:user:2:main", jobs_json);

    const claimed = try mgr.claimDueJobs(allocator, "test-owner", 10, 60, 10);
    defer {
        for (claimed) |*claimed_job| claimed_job.deinit(allocator);
        allocator.free(claimed);
    }
    try std.testing.expectEqual(@as(usize, 1), claimed.len);

    var runtime_scheduler = cron_mod.CronScheduler.init(allocator, 1, true);
    defer runtime_scheduler.deinit();
    try runtime_scheduler.setExecutionContext("2", "/tmp/nullalis-zaki-bot-test-user-2", "/tmp/nullalis-zaki-bot-test-user-2/workspace");
    try cron_mod.loadJobFromJsonSlice(&runtime_scheduler, claimed[0].raw_job_json);
    // D14 fix: the test exercises job_type=.agent which requires an agent
    // runner; without one, tick() sets last_status="error" and the assertion
    // below (expectEqualStrings("ok", ...)) fails. Wire a stub runner that
    // returns a fixed string — the test's intent is "scheduler reschedules
    // and records run", not "agent execution semantics."
    const StubRunner = struct {
        fn run(_: ?*anyopaque, alloc: std.mem.Allocator, _: *const cron_mod.CronScheduler, _: *const cron_mod.CronJob, _: []const u8) ![]const u8 {
            return alloc.dupe(u8, "ok");
        }
    };
    runtime_scheduler.setAgentRunner(&StubRunner.run, null);
    _ = runtime_scheduler.tick(10, null);
    try std.testing.expectEqual(@as(usize, 1), runtime_scheduler.listJobs().len);
    const updated_json = try cron_mod.jobToJson(allocator, &runtime_scheduler.listJobs()[0]);
    defer allocator.free(updated_json);

    try mgr.completeClaimedJob(2, claimed[0].id, "test-owner", updated_json, runtime_scheduler.listJobs()[0].next_run_secs, runtime_scheduler.listJobs()[0].last_status, runtime_scheduler.listJobs()[0].last_output, 10, 11);

    const jobs_after = try mgr.getJobsJson(allocator, 2);
    defer allocator.free(jobs_after);
    const parsed_jobs = try std.json.parseFromSlice(std.json.Value, allocator, jobs_after, .{});
    defer parsed_jobs.deinit();
    try std.testing.expect(parsed_jobs.value == .array);
    try std.testing.expectEqual(@as(usize, 1), parsed_jobs.value.array.items.len);
    try std.testing.expect(parsed_jobs.value.array.items[0] == .object);
    const stored_job = parsed_jobs.value.array.items[0].object;
    try std.testing.expectEqualStrings("recurring-reminder", stored_job.get("id").?.string);
    try std.testing.expectEqualStrings("ok", stored_job.get("last_status").?.string);

    const future_claim = try mgr.claimDueJobs(allocator, "test-owner", 11, 60, 10);
    defer {
        for (future_claim) |*claimed_job| claimed_job.deinit(allocator);
        allocator.free(future_claim);
    }
    try std.testing.expectEqual(@as(usize, 0), future_claim.len);

    const runs = try mgr.listJobRuns(allocator, 2, "recurring-reminder", 10);
    defer {
        for (runs) |run| {
            allocator.free(@constCast(run.job_id));
            allocator.free(@constCast(run.status));
            if (run.output) |value| allocator.free(@constCast(value));
        }
        allocator.free(runs);
    }
    try std.testing.expectEqual(@as(usize, 1), runs.len);
    try std.testing.expectEqualStrings("recurring-reminder", runs[0].job_id);
    try std.testing.expectEqualStrings("ok", runs[0].status);
    try std.testing.expectEqualStrings("ok", runs[0].output.?);
}

