// ── H6 (boot hardening): DB steady-state readiness ping ──────────────
//
// pingHealth() is a lightweight `SELECT 1` the gateway maintenance thread
// runs periodically to feed health.markComponentOk/Error("db", …) so
// /ready (which aggregates the registry) sheds a pod whose Postgres went
// away AFTER boot. Kept out of /health (liveness) to avoid restart storms.

test "H6: pingHealth succeeds against a live database" {
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;
    var mgr = try initPostgresTestManagerWithPool(allocator, 2, 500);
    defer mgr.deinit();

    try mgr.pingHealth();
}

// ── H4 (boot hardening): migrations serialized by a PG advisory lock ──
//
// migrate() had NO lock; a rolling-update / HPA scale-out can run two
// pods' migrations concurrently (deadlock risk, worse once non-idempotent
// 0002+ ships). The fix holds a transaction-scoped pg_try_advisory_xact_lock
// inside an open BEGIN..COMMIT on a pinned connection (the open txn pins the
// backend through pgBouncer pool_mode=transaction; COMMIT auto-releases it),
// plus a process-global mutex serializing migrate() within a pod.

test "H4: advisory lock is mutually exclusive then re-grantable after unlock" {
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;
    var mgr = try initPostgresTestManagerWithPool(allocator, 4, 500);
    defer mgr.deinit();

    const KEY = ManagerImpl.MIGRATION_ADVISORY_LOCK_KEY;
    // Hold the migration lock on connection A.
    var lease_a = try mgr.acquireConn(0);
    defer mgr.releaseConn(&lease_a, true);
    try std.testing.expect(try mgr.tryAdvisoryLockOnConn(lease_a.conn, KEY));

    // A different session (connection B) must NOT be able to take it.
    var lease_b = try mgr.acquireConn(0);
    defer mgr.releaseConn(&lease_b, true);
    try std.testing.expect(!(try mgr.tryAdvisoryLockOnConn(lease_b.conn, KEY)));

    // Release on A; now B can take it.
    mgr.advisoryUnlockOnConn(lease_a.conn, KEY);
    try std.testing.expect(try mgr.tryAdvisoryLockOnConn(lease_b.conn, KEY));
    mgr.advisoryUnlockOnConn(lease_b.conn, KEY);
}

test "H4: migrate acquires and releases the advisory lock (no lock left held)" {
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;
    // initPostgresTestManagerWithPool already ran migrate() once during init.
    var mgr = try initPostgresTestManagerWithPool(allocator, 4, 500);
    defer mgr.deinit();

    const KEY = ManagerImpl.MIGRATION_ADVISORY_LOCK_KEY;
    // After init's migrate() returned, the advisory lock MUST be free —
    // otherwise a follow-up migrate (or another pod) would block forever.
    // A fresh session taking pg_try_advisory_lock proves migrate() unlocked.
    var probe = try mgr.acquireConn(0);
    defer mgr.releaseConn(&probe, true);
    try std.testing.expect(try mgr.tryAdvisoryLockOnConn(probe.conn, KEY));
    mgr.advisoryUnlockOnConn(probe.conn, KEY);

    // And migrate() is still idempotent under the lock (re-run is clean).
    try mgr.migrate();
    // Lock is free again after the second migrate().
    try std.testing.expect(try mgr.tryAdvisoryLockOnConn(probe.conn, KEY));
    mgr.advisoryUnlockOnConn(probe.conn, KEY);
}

test "pgBouncer-fix: migration xact lock serializes across independent connections" {
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;
    var mgr = try initPostgresTestManagerWithPool(allocator, 4, 2000);
    defer mgr.deinit();

    // The cutover-critical property: two INDEPENDENT connections (two pods) must
    // never both hold the migration lock. This exercises the real production
    // primitive — acquireMigrationXactLock inside an open beginTransaction — NOT
    // the in-process g_migration_mutex (which the same-process concurrent-migrate
    // test below covers separately).
    const KEY = ManagerImpl.MIGRATION_ADVISORY_LOCK_KEY;
    const H = struct {
        // One non-blocking xact-lock attempt on a pinned txn conn (what
        // acquireMigrationXactLock does each retry), returning grant/deny.
        fn tryXact(txn: *ManagerImpl.TxnLease, key: i64) !bool {
            var buf: [96]u8 = undefined;
            const q = try std.fmt.bufPrint(&buf, "SELECT pg_try_advisory_xact_lock({d})", .{key});
            const r = try txn.exec(q);
            defer c.PQclear(r);
            return c.PQntuples(r) >= 1 and c.PQgetvalue(r, 0, 0)[0] == 't';
        }
    };

    // Holder takes the lock the way migrate() does and keeps its txn open.
    var holder = try mgr.beginTransaction();
    defer holder.deinit(); // ROLLBACK releases the xact lock
    try mgr.acquireMigrationXactLock(&holder);

    // A second, independent pinned connection is DENIED the same lock while the
    // holder's txn is open (advisory locks are database-global).
    var contender = try mgr.beginTransaction();
    defer contender.deinit();
    try std.testing.expect(!(try H.tryXact(&contender, KEY)));

    // Once the holder's txn ends, the contender can take it.
    holder.rollback();
    try std.testing.expect(try H.tryXact(&contender, KEY));
}

test "H4: concurrent migrate() from two managers on one schema does not error" {
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;

    // Two managers on the SAME schema racing migrate(). NOTE: both run in THIS
    // process, so g_migration_mutex serializes them BEFORE the advisory lock
    // contends — this validates the in-process mutex + migrate() path (no
    // deadlock / duplicate-DDL). Cross-CONNECTION advisory-lock serialization
    // (the cross-pod property) is proven by the test above and by
    // scripts/pgbouncer-migration-harness. initPostgresTestManagerWithPool makes
    // a unique schema + migrates once; build a second manager on that schema.
    var mgr_a = try initPostgresTestManagerWithPool(allocator, 4, 2000);
    defer mgr_a.deinit();

    const test_url = (env_rebrand.getEnvOwnedWithRebrand(allocator, "NULLALIS_POSTGRES_TEST_URL", "NULLCLAW_POSTGRES_TEST_URL") catch return error.SkipZigTest) orelse return error.SkipZigTest;
    defer allocator.free(test_url);
    const cfg_b = config_types.StateConfig{
        .backend = "postgres",
        .postgres = .{
            .connection_string = test_url,
            .schema = mgr_a.schemaRaw(),
            .pool_max = 4,
            .lock_timeout_ms = 2000,
        },
    };
    var mgr_b = try ManagerImpl.init(allocator, cfg_b);
    defer mgr_b.deinit();

    const Runner = struct {
        fn run(m: *ManagerImpl, out: *?anyerror) void {
            m.migrate() catch |e| {
                out.* = e;
            };
        }
    };

    var err_a: ?anyerror = null;
    var err_b: ?anyerror = null;
    const t_a = try std.Thread.spawn(.{}, Runner.run, .{ &mgr_a, &err_a });
    const t_b = try std.Thread.spawn(.{}, Runner.run, .{ &mgr_b, &err_b });
    t_a.join();
    t_b.join();

    // The advisory lock serializes them; both complete without a deadlock
    // or duplicate-DDL error (the legacy loop is idempotent + now serial).
    if (err_a) |e| {
        std.debug.print("concurrent migrate A failed: {any}\n", .{e});
        return e;
    }
    if (err_b) |e| {
        std.debug.print("concurrent migrate B failed: {any}\n", .{e});
        return e;
    }
}

