test "V1.6 commit 6 setMemoryInvalidation closes out memory + filters from retrieval" {
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;
    const test_url = (env_rebrand.getEnvOwnedWithRebrand(allocator, "NULLALIS_POSTGRES_TEST_URL", "NULLCLAW_POSTGRES_TEST_URL") catch return error.SkipZigTest) orelse return error.SkipZigTest;
    defer allocator.free(test_url);

    var schema_buf: [96]u8 = undefined;
    const schema = try std.fmt.bufPrint(&schema_buf, "zaki_bot_test_{d}", .{std.time.microTimestamp()});
    const cfg = config_types.StateConfig{
        .backend = "postgres",
        .postgres = .{
            .connection_string = test_url,
            .schema = schema,
        },
    };

    var mgr = try ManagerImpl.init(allocator, cfg);
    defer mgr.deinit();
    {
        const schema_q = try pg_helpers.quoteIdentifier(allocator, mgr.schemaRaw());
        defer allocator.free(schema_q);
        const drop_q = try std.fmt.allocPrint(allocator, "DROP SCHEMA IF EXISTS {s} CASCADE", .{schema_q});
        defer allocator.free(drop_q);
        const result = try mgr.exec(drop_q);
        c.PQclear(result);
    }
    try mgr.migrate();
    try mgr.provisionUser(2, "/tmp/nullalis-zaki-bot-test-user-2/workspace");

    // ── Seed: existing extraction-classifier memory ───────────────────
    const old_metadata =
        \\{"subject":"user","predicate":"PREFERS","object_key":"NeoVim","attributed_to":"user","attribution":"extraction_classifier","confidence":1.0,"extracted_at":1000000}
    ;
    try mgr.upsertMemoryWithMetadata(2, "extracted_old_pref", "User prefers NeoVim", .core, null, old_metadata);

    // Sanity: row reachable via getMemory + findRelatedExtractedMemories
    {
        const before = try mgr.getMemory(allocator, 2, "extracted_old_pref");
        try std.testing.expect(before != null);
        before.?.deinit(allocator);
    }
    {
        const related = try mgr.findRelatedExtractedMemories(allocator, 2, "user", 8);
        defer {
            for (related) |e| e.deinit(allocator);
            allocator.free(related);
        }
        try std.testing.expectEqual(@as(usize, 1), related.len);
        try std.testing.expectEqualStrings("extracted_old_pref", related[0].key);
    }

    // ── Close out: new "Helix" fact contradicts old "NeoVim" fact ─────
    const close_out_ts: i64 = std.time.timestamp();
    try mgr.setMemoryInvalidation(2, "extracted_old_pref", close_out_ts, close_out_ts);

    // ── Assertions ───────────────────────────────────────────────────
    // 1. getMemory hides the closed-out row (MEMORIES_VALIDITY_FILTER)
    {
        const after = try mgr.getMemory(allocator, 2, "extracted_old_pref");
        try std.testing.expect(after == null);
    }
    // 2. findRelatedExtractedMemories also hides it
    {
        const related = try mgr.findRelatedExtractedMemories(allocator, 2, "user", 8);
        defer {
            for (related) |e| e.deinit(allocator);
            allocator.free(related);
        }
        try std.testing.expectEqual(@as(usize, 0), related.len);
    }
    // 3. The row IS still in the table — for audit. Direct SQL confirms
    //    valid_to + invalid_at + expired_at populated, is_latest = false.
    {
        const audit_q = try std.fmt.allocPrint(
            allocator,
            "SELECT valid_to, invalid_at, expired_at, is_latest FROM {s}.memories WHERE user_id = 2 AND key = 'extracted_old_pref'",
            .{schema},
        );
        defer allocator.free(audit_q);
        const result = try mgr.exec(audit_q);
        defer c.PQclear(result);
        try std.testing.expectEqual(@as(c_int, 1), c.PQntuples(result));

        const valid_to_str = try dupeResultValue(allocator, result, 0, 0);
        defer allocator.free(valid_to_str);
        const invalid_at_str = try dupeResultValue(allocator, result, 0, 1);
        defer allocator.free(invalid_at_str);
        const expired_at_str = try dupeResultValue(allocator, result, 0, 2);
        defer allocator.free(expired_at_str);
        const is_latest_str = try dupeResultValue(allocator, result, 0, 3);
        defer allocator.free(is_latest_str);

        const valid_to = try std.fmt.parseInt(i64, valid_to_str, 10);
        const invalid_at = try std.fmt.parseInt(i64, invalid_at_str, 10);
        const expired_at = try std.fmt.parseInt(i64, expired_at_str, 10);

        try std.testing.expectEqual(close_out_ts, valid_to);
        try std.testing.expectEqual(close_out_ts, invalid_at);
        try std.testing.expectEqual(close_out_ts, expired_at);
        // postgres BOOLEAN serializes as "f" / "t"
        try std.testing.expectEqualStrings("f", is_latest_str);
    }

    // 4. Idempotent: a second invalidation with the same timestamps is
    //    a no-op (UPDATE re-writes the same values, returns successfully).
    try mgr.setMemoryInvalidation(2, "extracted_old_pref", close_out_ts, close_out_ts);

    // 5. Non-existent key: silent no-op (caller doesn't gate on existence).
    try mgr.setMemoryInvalidation(2, "no_such_key", close_out_ts, close_out_ts);
}

// Package 3 Task 1 (M2) — editMemorySupersede writes a bi-temporal history
// row instead of mutating in place. Proves: (a) the live key keeps stable
// identity and reads back the NEW content; (b) a born-closed history row
// carrying the OLD content is written under key
// `history/<key>/<editor_now>-<nanos>` and is validity-filtered OUT of every
// normal read (getMemory/listMemories); (c) the history row IS retrievable
// via getMemoryAnyValidity + direct count; (d) a `memory_events` row
// `event_type='edit_supersede'` is appended; (e) fix-wave I2: two edits in
// the SAME second keep BOTH snapshots under distinct keys.
test "M2 editMemorySupersede writes born-closed history row and updates live in place" {
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;
    const test_url = (env_rebrand.getEnvOwnedWithRebrand(allocator, "NULLALIS_POSTGRES_TEST_URL", "NULLCLAW_POSTGRES_TEST_URL") catch return error.SkipZigTest) orelse return error.SkipZigTest;
    defer allocator.free(test_url);

    var schema_buf: [96]u8 = undefined;
    const schema = try std.fmt.bufPrint(&schema_buf, "zaki_bot_test_{d}", .{std.time.microTimestamp()});
    const cfg = config_types.StateConfig{
        .backend = "postgres",
        .postgres = .{
            .connection_string = test_url,
            .schema = schema,
        },
    };

    var mgr = try ManagerImpl.init(allocator, cfg);
    defer mgr.deinit();
    {
        const result = try mgr.exec("SET client_min_messages TO WARNING");
        c.PQclear(result);
    }
    {
        const schema_q = try pg_helpers.quoteIdentifier(allocator, mgr.schemaRaw());
        defer allocator.free(schema_q);
        const drop_q = try std.fmt.allocPrint(allocator, "DROP SCHEMA IF EXISTS {s} CASCADE", .{schema_q});
        defer allocator.free(drop_q);
        const result = try mgr.exec(drop_q);
        c.PQclear(result);
    }
    try mgr.migrate();
    try mgr.provisionUser(2, "/tmp/nullalis-zaki-bot-test-user-2/workspace");

    // ── Seed: a live, editable fact holding "oolong". ─────────────────
    try mgr.upsertMemory(2, "fav_tea", "oolong", .core, null);
    {
        const before = try mgr.getMemory(allocator, 2, "fav_tea");
        try std.testing.expect(before != null);
        defer before.?.deinit(allocator);
        try std.testing.expectEqualStrings("oolong", before.?.content);
    }

    // ── Supersede: edit oolong → sencha at editor_now. ────────────────
    // Fix-wave (review I2): editMemorySupersede now RETURNS the history key
    // it actually wrote (null would mean the snapshot INSERT was skipped by
    // ON CONFLICT — callers must not claim archival then). The key shape is
    // `history/<key>/<editor_now>-<nanos>`: seconds in the temporal columns,
    // a nanosecond component in the key for same-second collision-proofing.
    const editor_now: i64 = std.time.timestamp();
    const history_key = (try mgr.editMemorySupersede(allocator, 2, "fav_tea", "sencha", editor_now)) orelse {
        std.debug.print("FAIL: first supersede reported a skipped snapshot\n", .{});
        return error.TestUnexpectedResult;
    };
    defer allocator.free(history_key);
    {
        var prefix_buf: [64]u8 = undefined;
        const expected_prefix = try std.fmt.bufPrint(&prefix_buf, "history/fav_tea/{d}-", .{editor_now});
        try std.testing.expect(std.mem.startsWith(u8, history_key, expected_prefix));
    }

    // ── Assertion 1: the live key keeps its address and reads NEW content.
    {
        const live = try mgr.getMemory(allocator, 2, "fav_tea");
        try std.testing.expect(live != null);
        defer live.?.deinit(allocator);
        try std.testing.expectEqualStrings("sencha", live.?.content);
    }

    // ── Assertion 2: a default-validity listMemories does NOT surface the
    //    history row (its valid_to <= now hides it), and DOES surface the
    //    live key exactly once.
    {
        const rows = try mgr.listMemories(allocator, 2, null, null);
        defer {
            for (rows) |e| e.deinit(allocator);
            allocator.free(rows);
        }
        var saw_live = false;
        for (rows) |e| {
            if (std.mem.eql(u8, e.key, history_key)) {
                std.debug.print("FAIL: history row leaked into listMemories: {s}\n", .{e.key});
                return error.TestUnexpectedResult;
            }
            if (std.mem.eql(u8, e.key, "fav_tea")) saw_live = true;
        }
        try std.testing.expect(saw_live);
    }

    // ── Assertion 3: getMemory (validity-filtered) hides the history row.
    {
        const hidden = try mgr.getMemory(allocator, 2, history_key);
        try std.testing.expect(hidden == null);
    }

    // ── Assertion 4: getMemoryAnyValidity surfaces the history row holding
    //    the OLD content ("oolong").
    {
        const audit = try mgr.getMemoryAnyValidity(allocator, 2, history_key);
        try std.testing.expect(audit != null);
        defer audit.?.deinit(allocator);
        try std.testing.expectEqualStrings("oolong", audit.?.content);
    }

    // ── Assertion 5: direct SQL — the history row exists with valid_to /
    //    invalid_at / expired_at = editor_now and is_latest = FALSE.
    {
        const audit_q = try std.fmt.allocPrint(
            allocator,
            "SELECT content, valid_to, invalid_at, expired_at, is_latest FROM {s}.memories WHERE user_id = 2 AND key = $1",
            .{schema},
        );
        defer allocator.free(audit_q);
        const key_z = try allocator.dupeZ(u8, history_key);
        defer allocator.free(key_z);
        const params = [_]?[*:0]const u8{key_z};
        const lengths = [_]c_int{@intCast(history_key.len)};
        const result = try mgr.execParams(audit_q, &params, &lengths);
        defer c.PQclear(result);
        try std.testing.expectEqual(@as(c_int, 1), c.PQntuples(result));

        const content_str = try dupeResultValue(allocator, result, 0, 0);
        defer allocator.free(content_str);
        const valid_to_str = try dupeResultValue(allocator, result, 0, 1);
        defer allocator.free(valid_to_str);
        const invalid_at_str = try dupeResultValue(allocator, result, 0, 2);
        defer allocator.free(invalid_at_str);
        const expired_at_str = try dupeResultValue(allocator, result, 0, 3);
        defer allocator.free(expired_at_str);
        const is_latest_str = try dupeResultValue(allocator, result, 0, 4);
        defer allocator.free(is_latest_str);

        try std.testing.expectEqualStrings("oolong", content_str);
        try std.testing.expectEqual(editor_now, try std.fmt.parseInt(i64, valid_to_str, 10));
        try std.testing.expectEqual(editor_now, try std.fmt.parseInt(i64, invalid_at_str, 10));
        try std.testing.expectEqual(editor_now, try std.fmt.parseInt(i64, expired_at_str, 10));
        try std.testing.expectEqualStrings("f", is_latest_str);
    }

    // ── Assertion 6: a `memory_events` row event_type='edit_supersede'
    //    exists for this user.
    {
        const ev_q = try std.fmt.allocPrint(
            allocator,
            "SELECT COUNT(*) FROM {s}.memory_events WHERE user_id = 2 AND event_type = 'edit_supersede'",
            .{schema},
        );
        defer allocator.free(ev_q);
        const result = try mgr.exec(ev_q);
        defer c.PQclear(result);
        try std.testing.expectEqual(@as(c_int, 1), c.PQntuples(result));
        const count_str = try dupeResultValue(allocator, result, 0, 0);
        defer allocator.free(count_str);
        try std.testing.expectEqual(@as(i64, 1), try std.fmt.parseInt(i64, count_str, 10));
    }

    // ── Assertion 7 (fix-wave, review I2): a second edit within the SAME
    //    second must NOT silently drop the intermediate snapshot. Reuse the
    //    same editor_now (deterministic same-second collision under the old
    //    `history/<key>/<ts>` shape — the nanosecond component now keeps the
    //    keys distinct). BOTH snapshots exist afterwards, under distinct
    //    history keys, each preserving its superseded content.
    {
        const history_key2 = (try mgr.editMemorySupersede(allocator, 2, "fav_tea", "matcha", editor_now)) orelse {
            std.debug.print("FAIL: same-second second edit dropped its snapshot (ON CONFLICT)\n", .{});
            return error.TestUnexpectedResult;
        };
        defer allocator.free(history_key2);

        // Distinct history keys for the two same-second edits.
        try std.testing.expect(!std.mem.eql(u8, history_key, history_key2));

        // The live key reads the newest content.
        const live = try mgr.getMemory(allocator, 2, "fav_tea");
        try std.testing.expect(live != null);
        defer live.?.deinit(allocator);
        try std.testing.expectEqualStrings("matcha", live.?.content);

        // Exactly TWO born-closed snapshots exist.
        const count_q = try std.fmt.allocPrint(
            allocator,
            "SELECT COUNT(*) FROM {s}.memories WHERE user_id = 2 AND key LIKE 'history/fav_tea/%'",
            .{schema},
        );
        defer allocator.free(count_q);
        const result = try mgr.exec(count_q);
        defer c.PQclear(result);
        const count_str = try dupeResultValue(allocator, result, 0, 0);
        defer allocator.free(count_str);
        try std.testing.expectEqual(@as(i64, 2), try std.fmt.parseInt(i64, count_str, 10));

        // Both old contents are preserved: snapshot 1 = oolong, snapshot 2 =
        // sencha (the intermediate version the old key shape used to drop).
        const audit1 = try mgr.getMemoryAnyValidity(allocator, 2, history_key);
        try std.testing.expect(audit1 != null);
        defer audit1.?.deinit(allocator);
        try std.testing.expectEqualStrings("oolong", audit1.?.content);

        const audit2 = try mgr.getMemoryAnyValidity(allocator, 2, history_key2);
        try std.testing.expect(audit2 != null);
        defer audit2.?.deinit(allocator);
        try std.testing.expectEqualStrings("sencha", audit2.?.content);
    }
}

// Package 3 Task 2 (M3) — archiveInformationScoped is INFORMATION-scoped:
// archiving one key auto-closes every live row with the identical
// content_hash (the M3 leak shape: `durable_fact/behavior/<fnv>` copy +
// `extracted_*` twin), reports the closed copies, and LISTS — without
// closing — a reworded near-duplicate found via the salient-token survey.
test "M3 archiveInformationScoped closes exact-hash copies and reports near-dups" {
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;
    const test_url = (env_rebrand.getEnvOwnedWithRebrand(allocator, "NULLALIS_POSTGRES_TEST_URL", "NULLCLAW_POSTGRES_TEST_URL") catch return error.SkipZigTest) orelse return error.SkipZigTest;
    defer allocator.free(test_url);

    var schema_buf: [96]u8 = undefined;
    const schema = try std.fmt.bufPrint(&schema_buf, "zaki_bot_test_{d}", .{std.time.microTimestamp()});
    const cfg = config_types.StateConfig{
        .backend = "postgres",
        .postgres = .{
            .connection_string = test_url,
            .schema = schema,
        },
    };

    var mgr = try ManagerImpl.init(allocator, cfg);
    defer mgr.deinit();
    {
        const result = try mgr.exec("SET client_min_messages TO WARNING");
        c.PQclear(result);
    }
    try mgr.migrate();
    try mgr.provisionUser(2, "/tmp/nullalis-zaki-bot-test-user-2/workspace");

    // ── Seed the M3 leak shape. ────────────────────────────────────────
    const info = "User prefers thmanyah podcasts on Fridays";
    try mgr.upsertMemory(2, "extracted_m3mgr001", info, .core, null);
    try mgr.upsertMemory(2, "durable_fact/behavior/1111cafe2222beef", info, .core, null);
    const reworded = "User enjoys thmanyah episodes weekly";
    try mgr.upsertMemory(2, "extracted_m3mgrnear", reworded, .core, null);
    try mgr.upsertMemory(2, "extracted_m3mgrunrl", "User lives in Hamburg", .core, null);

    // ── Act: archive ONE key. ──────────────────────────────────────────
    const now_ts: i64 = std.time.timestamp();
    var scope = try mgr.archiveInformationScoped(allocator, 2, "extracted_m3mgr001", now_ts);
    defer scope.deinit(allocator);

    // ── Result shape: primary closed; exactly the behavior twin in
    //    exact_closed; exactly the reworded row in near_dups. ────────────
    try std.testing.expect(scope.primary_closed);
    try std.testing.expectEqual(@as(usize, 1), scope.exact_closed.len);
    try std.testing.expectEqualStrings("durable_fact/behavior/1111cafe2222beef", scope.exact_closed[0]);
    try std.testing.expectEqual(@as(usize, 1), scope.near_dups.len);
    try std.testing.expectEqualStrings("extracted_m3mgrnear", scope.near_dups[0].key);
    try std.testing.expectEqualStrings(reworded, scope.near_dups[0].content);

    // ── BOTH identical-content rows carry valid_to (validity-filtered
    //    out); the near-dup and the unrelated row stay live. ─────────────
    {
        const primary = try mgr.getMemory(allocator, 2, "extracted_m3mgr001");
        try std.testing.expect(primary == null);
        const copy = try mgr.getMemory(allocator, 2, "durable_fact/behavior/1111cafe2222beef");
        try std.testing.expect(copy == null);
        const near = try mgr.getMemory(allocator, 2, "extracted_m3mgrnear");
        try std.testing.expect(near != null);
        defer near.?.deinit(allocator);
        const unrl = try mgr.getMemory(allocator, 2, "extracted_m3mgrunrl");
        try std.testing.expect(unrl != null);
        defer unrl.?.deinit(allocator);
    }
    // Direct SQL: the cascade-closed copy got the full bi-temporal
    // close-out (valid_to/invalid_at/expired_at = now_ts, is_latest=f) —
    // the same column discipline setMemoryInvalidation always applies.
    {
        const audit_q = try std.fmt.allocPrint(
            allocator,
            "SELECT valid_to, invalid_at, expired_at, is_latest FROM {s}.memories WHERE user_id = 2 AND key = 'durable_fact/behavior/1111cafe2222beef'",
            .{schema},
        );
        defer allocator.free(audit_q);
        const result = try mgr.exec(audit_q);
        defer c.PQclear(result);
        try std.testing.expectEqual(@as(c_int, 1), c.PQntuples(result));
        const valid_to_str = try dupeResultValue(allocator, result, 0, 0);
        defer allocator.free(valid_to_str);
        const invalid_at_str = try dupeResultValue(allocator, result, 0, 1);
        defer allocator.free(invalid_at_str);
        const expired_at_str = try dupeResultValue(allocator, result, 0, 2);
        defer allocator.free(expired_at_str);
        const is_latest_str = try dupeResultValue(allocator, result, 0, 3);
        defer allocator.free(is_latest_str);
        try std.testing.expectEqual(now_ts, try std.fmt.parseInt(i64, valid_to_str, 10));
        try std.testing.expectEqual(now_ts, try std.fmt.parseInt(i64, invalid_at_str, 10));
        try std.testing.expectEqual(now_ts, try std.fmt.parseInt(i64, expired_at_str, 10));
        try std.testing.expectEqualStrings("f", is_latest_str);
    }

    // ── Warm-start read paths no longer return EITHER closed row. ───────
    {
        const rows = try mgr.listMemories(allocator, 2, null, null);
        defer {
            for (rows) |e| e.deinit(allocator);
            allocator.free(rows);
        }
        for (rows) |e| {
            try std.testing.expect(!std.mem.eql(u8, e.key, "extracted_m3mgr001"));
            try std.testing.expect(!std.mem.eql(u8, e.key, "durable_fact/behavior/1111cafe2222beef"));
        }
    }
    {
        const rows = try mgr.recallMemories(allocator, 2, "thmanyah", 10, null);
        defer {
            for (rows) |e| e.deinit(allocator);
            allocator.free(rows);
        }
        for (rows) |e| {
            try std.testing.expect(!std.mem.eql(u8, e.key, "extracted_m3mgr001"));
            try std.testing.expect(!std.mem.eql(u8, e.key, "durable_fact/behavior/1111cafe2222beef"));
        }
    }

    // ── Missing key surfaces MemoryKeyNotFound (M2 parity). ─────────────
    try std.testing.expectError(
        error.MemoryKeyNotFound,
        mgr.archiveInformationScoped(allocator, 2, "no_such_key_m3", now_ts),
    );
}

// Package 3 Task 2 (M3, forget flavor) — forgetInformationScoped HARD-deletes
// the named key and its exact-hash KNOWLEDGE copies (rows GONE, not
// validity-closed); near-dups are reported and untouched. Fix-wave (review
// I3): autosave twins are DOWNGRADED to close-out — audit rows are never
// destroyed by the cascade, only removed from live recall.
test "M3 forgetInformationScoped hard-deletes exact-hash copies" {
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;
    const test_url = (env_rebrand.getEnvOwnedWithRebrand(allocator, "NULLALIS_POSTGRES_TEST_URL", "NULLCLAW_POSTGRES_TEST_URL") catch return error.SkipZigTest) orelse return error.SkipZigTest;
    defer allocator.free(test_url);

    var schema_buf: [96]u8 = undefined;
    const schema = try std.fmt.bufPrint(&schema_buf, "zaki_bot_test_{d}", .{std.time.microTimestamp()});
    const cfg = config_types.StateConfig{
        .backend = "postgres",
        .postgres = .{
            .connection_string = test_url,
            .schema = schema,
        },
    };

    var mgr = try ManagerImpl.init(allocator, cfg);
    defer mgr.deinit();
    {
        const result = try mgr.exec("SET client_min_messages TO WARNING");
        c.PQclear(result);
    }
    try mgr.migrate();
    try mgr.provisionUser(2, "/tmp/nullalis-zaki-bot-test-user-2/workspace");

    const info = "User passport number is X99 via wanderlust";
    try mgr.upsertMemory(2, "extracted_m3fmgr01", info, .core, null);
    try mgr.upsertMemory(2, "autosave_user_777001", info, .conversation, null);
    try mgr.upsertMemory(2, "extracted_m3fmgrnr", "User carries a wanderlust visa", .core, null);
    try mgr.upsertMemory(2, "durable_fact/behavior/m3fmgrtwin01", info, .core, null);

    const now_ts: i64 = std.time.timestamp();
    var scope = try mgr.forgetInformationScoped(allocator, 2, "extracted_m3fmgr01", now_ts);
    defer scope.deinit(allocator);

    try std.testing.expect(scope.primary_closed);
    try std.testing.expectEqual(@as(usize, 2), scope.exact_closed.len);
    try std.testing.expectEqualStrings("autosave_user_777001", scope.exact_closed[0]);
    try std.testing.expectEqualStrings("durable_fact/behavior/m3fmgrtwin01", scope.exact_closed[1]);

    // HARD delete reaches the named row and the knowledge-lane copy — both
    // GONE at any validity. The AUTOSAVE twin is downgraded to close-out
    // (fix-wave I3): gone from live reads, preserved at any validity with
    // valid_to set — GDPR recall erasure without destroying the audit row.
    {
        const primary = try mgr.getMemoryAnyValidity(allocator, 2, "extracted_m3fmgr01");
        try std.testing.expect(primary == null);
        const knowledge_copy = try mgr.getMemoryAnyValidity(allocator, 2, "durable_fact/behavior/m3fmgrtwin01");
        try std.testing.expect(knowledge_copy == null);
        const live = try mgr.getMemory(allocator, 2, "autosave_user_777001");
        try std.testing.expect(live == null);
        const audit = (try mgr.getMemoryAnyValidity(allocator, 2, "autosave_user_777001")) orelse return error.TestUnexpectedResult;
        defer audit.deinit(allocator);
        try std.testing.expectEqual(now_ts, audit.valid_to orelse return error.TestUnexpectedResult);
    }
    // The reworded near-dup is reported and untouched.
    try std.testing.expectEqual(@as(usize, 1), scope.near_dups.len);
    try std.testing.expectEqualStrings("extracted_m3fmgrnr", scope.near_dups[0].key);
    {
        const near = try mgr.getMemory(allocator, 2, "extracted_m3fmgrnr");
        try std.testing.expect(near != null);
        defer near.?.deinit(allocator);
    }
}

// Package 3 fix-wave (review I2) — content-length floor on the exact-hash
// cascade. Byte identity on SHORT generic content ("yes", "blue") does not
// prove same-information: two unrelated keys can legitimately hold the same
// short value, and pre-fix the cascade auto-closed (archive) or HARD-deleted
// (forget) the unrelated twin. Twins shorter than 16 bytes are now REPORTED
// in near_dups (visible, user-confirmable) instead of swept — in BOTH modes.
// The primary key the user explicitly named is unaffected by the floor.
test "M3 cascade floor: short identical content is reported, never swept" {
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;
    const test_url = (env_rebrand.getEnvOwnedWithRebrand(allocator, "NULLALIS_POSTGRES_TEST_URL", "NULLCLAW_POSTGRES_TEST_URL") catch return error.SkipZigTest) orelse return error.SkipZigTest;
    defer allocator.free(test_url);

    var schema_buf: [96]u8 = undefined;
    const schema = try std.fmt.bufPrint(&schema_buf, "zaki_bot_test_{d}", .{std.time.microTimestamp()});
    const cfg = config_types.StateConfig{
        .backend = "postgres",
        .postgres = .{
            .connection_string = test_url,
            .schema = schema,
        },
    };

    var mgr = try ManagerImpl.init(allocator, cfg);
    defer mgr.deinit();
    {
        const result = try mgr.exec("SET client_min_messages TO WARNING");
        c.PQclear(result);
    }
    try mgr.migrate();
    try mgr.provisionUser(2, "/tmp/nullalis-zaki-bot-test-user-2/workspace");

    // Three unrelated user keys, identical 4-byte content. ("blue" clears
    // the isLowSignalMemory ingestion gate — unlike "yes"/"ok" — while
    // still sitting far below the 16-byte cascade floor.)
    try mgr.upsertMemory(2, "pref_color_answer", "blue", .core, null);
    try mgr.upsertMemory(2, "confirm_backup_yes", "blue", .core, null);
    try mgr.upsertMemory(2, "reply_style_short", "blue", .core, null);

    const now_ts: i64 = std.time.timestamp();
    // ── Archive mode: primary closed; short twins reported, NOT closed. ──
    var scope = try mgr.archiveInformationScoped(allocator, 2, "pref_color_answer", now_ts);
    defer scope.deinit(allocator);
    try std.testing.expect(scope.primary_closed);
    try std.testing.expectEqual(@as(usize, 0), scope.exact_closed.len);
    try std.testing.expectEqual(@as(usize, 2), scope.near_dups.len);
    try std.testing.expectEqualStrings("confirm_backup_yes", scope.near_dups[0].key);
    try std.testing.expectEqualStrings("reply_style_short", scope.near_dups[1].key);
    {
        const live1 = try mgr.getMemory(allocator, 2, "confirm_backup_yes");
        try std.testing.expect(live1 != null);
        live1.?.deinit(allocator);
        const live2 = try mgr.getMemory(allocator, 2, "reply_style_short");
        try std.testing.expect(live2 != null);
        live2.?.deinit(allocator);
    }

    // ── Forget mode: primary hard-deleted (floor never guards the named
    //    key); the remaining short twin survives LIVE and is reported. ────
    var scope2 = try mgr.forgetInformationScoped(allocator, 2, "confirm_backup_yes", now_ts);
    defer scope2.deinit(allocator);
    try std.testing.expect(scope2.primary_closed);
    try std.testing.expectEqual(@as(usize, 0), scope2.exact_closed.len);
    try std.testing.expectEqual(@as(usize, 1), scope2.near_dups.len);
    try std.testing.expectEqualStrings("reply_style_short", scope2.near_dups[0].key);
    {
        const gone = try mgr.getMemoryAnyValidity(allocator, 2, "confirm_backup_yes");
        try std.testing.expect(gone == null);
        const live = try mgr.getMemory(allocator, 2, "reply_style_short");
        try std.testing.expect(live != null);
        live.?.deinit(allocator);
    }
}

// Package 3 fix-wave (review I3) — the exact-hash cascade obeys the SAME
// protection predicate as direct curation (memory_root.isEditableMemoryEntry,
// the guard behind lookupMemoryLifecycleEntry's `protected` verdict): a
// byte-identical twin under a protected system family (summary_latest/,
// agent_plan/, append-only families, ...) is SKIPPED in both modes — pre-fix
// it was closed (archive) or hard-deleted (forget) even though curating that
// key directly is refused as `protected`. DELIBERATE EXCEPTION: autosave_*
// audit twins stay sweepable — the byte-identical autosave copy IS the M3
// recall leak — but forget DOWNGRADES them to close-out instead of
// hard-delete (audit rows are never destroyed; any-validity reads keep them).
test "M3 cascade protection: system twins skipped; autosave twins closed, never hard-deleted" {
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;
    const test_url = (env_rebrand.getEnvOwnedWithRebrand(allocator, "NULLALIS_POSTGRES_TEST_URL", "NULLCLAW_POSTGRES_TEST_URL") catch return error.SkipZigTest) orelse return error.SkipZigTest;
    defer allocator.free(test_url);

    var schema_buf: [96]u8 = undefined;
    const schema = try std.fmt.bufPrint(&schema_buf, "zaki_bot_test_{d}", .{std.time.microTimestamp()});
    const cfg = config_types.StateConfig{
        .backend = "postgres",
        .postgres = .{
            .connection_string = test_url,
            .schema = schema,
        },
    };

    var mgr = try ManagerImpl.init(allocator, cfg);
    defer mgr.deinit();
    {
        const result = try mgr.exec("SET client_min_messages TO WARNING");
        c.PQclear(result);
    }
    try mgr.migrate();
    try mgr.provisionUser(2, "/tmp/nullalis-zaki-bot-test-user-2/workspace");

    // ── Archive mode. ──────────────────────────────────────────────────
    const info = "User prefers the desert road on weekends";
    try mgr.upsertMemory(2, "extracted_m3prot01", info, .core, null);
    try mgr.upsertMemory(2, "summary_latest/sess-prot1", info, .core, null);
    try mgr.upsertMemory(2, "autosave_user_888001", info, .conversation, null);

    const now_ts: i64 = std.time.timestamp();
    var scope = try mgr.archiveInformationScoped(allocator, 2, "extracted_m3prot01", now_ts);
    defer scope.deinit(allocator);
    try std.testing.expect(scope.primary_closed);
    // ONLY the autosave twin is swept; the protected summary row is
    // skipped by the cascade — and never surfaces in the near-dup report
    // either (it is not a curation candidate: direct curation refuses it).
    try std.testing.expectEqual(@as(usize, 1), scope.exact_closed.len);
    try std.testing.expectEqualStrings("autosave_user_888001", scope.exact_closed[0]);
    for (scope.near_dups) |nd| try std.testing.expect(!std.mem.eql(u8, nd.key, "summary_latest/sess-prot1"));
    {
        const summary = try mgr.getMemory(allocator, 2, "summary_latest/sess-prot1");
        try std.testing.expect(summary != null);
        summary.?.deinit(allocator);
    }
    // The autosave twin is CLOSED (bi-temporal), not destroyed.
    {
        const live = try mgr.getMemory(allocator, 2, "autosave_user_888001");
        try std.testing.expect(live == null);
        const audit = (try mgr.getMemoryAnyValidity(allocator, 2, "autosave_user_888001")) orelse return error.TestUnexpectedResult;
        defer audit.deinit(allocator);
        try std.testing.expectEqual(now_ts, audit.valid_to orelse return error.TestUnexpectedResult);
    }

    // ── Forget mode (fresh content so the named key is live). ───────────
    const info2 = "User plays the oud every Thursday evening";
    try mgr.upsertMemory(2, "extracted_m3prot02", info2, .core, null);
    try mgr.upsertMemory(2, "summary_latest/sess-prot2", info2, .core, null);
    try mgr.upsertMemory(2, "autosave_user_888002", info2, .conversation, null);

    var scope2 = try mgr.forgetInformationScoped(allocator, 2, "extracted_m3prot02", now_ts);
    defer scope2.deinit(allocator);
    try std.testing.expect(scope2.primary_closed);
    try std.testing.expectEqual(@as(usize, 1), scope2.exact_closed.len);
    try std.testing.expectEqualStrings("autosave_user_888002", scope2.exact_closed[0]);
    // The protected summary twin survives forget untouched...
    {
        const summary = try mgr.getMemory(allocator, 2, "summary_latest/sess-prot2");
        try std.testing.expect(summary != null);
        summary.?.deinit(allocator);
    }
    // ...the named key is HARD-deleted (primary semantics unchanged)...
    {
        const gone = try mgr.getMemoryAnyValidity(allocator, 2, "extracted_m3prot02");
        try std.testing.expect(gone == null);
    }
    // ...and the autosave twin is CLOSED, not hard-deleted: gone from live
    // reads, still present at any validity with valid_to set.
    {
        const live = try mgr.getMemory(allocator, 2, "autosave_user_888002");
        try std.testing.expect(live == null);
        const audit = (try mgr.getMemoryAnyValidity(allocator, 2, "autosave_user_888002")) orelse return error.TestUnexpectedResult;
        defer audit.deinit(allocator);
        try std.testing.expectEqual(now_ts, audit.valid_to orelse return error.TestUnexpectedResult);
    }
}

// V1.6 commit 6 — findRelatedExtractedMemories scoping smoke test.
//
// Confirms the candidate fetcher correctly filters by:
//   - subject (only same-subject rows)
//   - attribution = 'extraction_classifier' (excludes agent_tool / compose)
//   - MEMORIES_VALIDITY_FILTER (excludes closed-out rows)
test "V1.6 commit 6 findRelatedExtractedMemories scopes by subject + attribution + validity" {
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;
    const test_url = (env_rebrand.getEnvOwnedWithRebrand(allocator, "NULLALIS_POSTGRES_TEST_URL", "NULLCLAW_POSTGRES_TEST_URL") catch return error.SkipZigTest) orelse return error.SkipZigTest;
    defer allocator.free(test_url);

    var schema_buf: [96]u8 = undefined;
    const schema = try std.fmt.bufPrint(&schema_buf, "zaki_bot_test_{d}", .{std.time.microTimestamp()});
    const cfg = config_types.StateConfig{
        .backend = "postgres",
        .postgres = .{
            .connection_string = test_url,
            .schema = schema,
        },
    };

    var mgr = try ManagerImpl.init(allocator, cfg);
    defer mgr.deinit();
    // Suppress libpq NOTICE-level messages during migrate. See user_99
    // test above for rationale.
    {
        const result = try mgr.exec("SET client_min_messages TO WARNING");
        c.PQclear(result);
    }
    {
        const schema_q = try pg_helpers.quoteIdentifier(allocator, mgr.schemaRaw());
        defer allocator.free(schema_q);
        const drop_q = try std.fmt.allocPrint(allocator, "DROP SCHEMA IF EXISTS {s} CASCADE", .{schema_q});
        defer allocator.free(drop_q);
        const result = try mgr.exec(drop_q);
        c.PQclear(result);
    }
    try mgr.migrate();
    try mgr.provisionUser(2, "/tmp/nullalis-zaki-bot-test-user-2/workspace");

    // Same subject="user", extraction-classifier attribution → MUST be returned
    try mgr.upsertMemoryWithMetadata(2, "ec_user_helix", "User uses Helix", .core, null,
        \\{"subject":"user","predicate":"USES","object_key":"Helix","attributed_to":"user","attribution":"extraction_classifier","confidence":1.0}
    );
    // Same subject="user", DIFFERENT attribution ("agent_tool") → MUST NOT be returned
    try mgr.upsertMemoryWithMetadata(2, "agent_tool_user_other", "User session log", .core, null,
        \\{"subject":"user","predicate":"NOTE","object_key":"x","attributed_to":"user","attribution":"agent_tool","confidence":1.0}
    );
    // DIFFERENT subject="alex", extraction-classifier → MUST NOT be returned
    try mgr.upsertMemoryWithMetadata(2, "ec_alex_birthday", "Alex birthday May 15", .core, null,
        \\{"subject":"alex","predicate":"BIRTHDAY","object_key":"May 15","attributed_to":"user","attribution":"extraction_classifier","confidence":1.0}
    );
    // Same subject="user", extraction-classifier, but CLOSED OUT → MUST NOT be returned
    try mgr.upsertMemoryWithMetadata(2, "ec_user_neovim_closed", "User uses NeoVim", .core, null,
        \\{"subject":"user","predicate":"USES","object_key":"NeoVim","attributed_to":"user","attribution":"extraction_classifier","confidence":1.0}
    );
    const closed_ts: i64 = std.time.timestamp();
    try mgr.setMemoryInvalidation(2, "ec_user_neovim_closed", closed_ts, closed_ts);

    // ── The query MUST return exactly 1 row: ec_user_helix ────────────
    const related = try mgr.findRelatedExtractedMemories(allocator, 2, "user", 16);
    defer {
        for (related) |e| e.deinit(allocator);
        allocator.free(related);
    }
    try std.testing.expectEqual(@as(usize, 1), related.len);
    try std.testing.expectEqualStrings("ec_user_helix", related[0].key);
    try std.testing.expectEqualStrings("User uses Helix", related[0].content);
}

// V1.6 cmt6 × V1.7 integration regression test (W-INT-01).
//
// Scenario: a non-core extraction-classifier row gets closed-out by V1.6
// commit 6's setMemoryInvalidation (e.g. via the contradiction judge). A
// later session re-states a similar fact under the SAME key (escapes the
// content_hash dedup because phrasing differs). Without the resurrect-on-
// upsert CASE-clears in upsertMemoryWithMetadata, the row would update
// content while remaining invisible (valid_to in past, is_latest=false) —
// "zombie" row. Worse: a 2nd cross-session re-statement would trigger
// promoteMemoryToCore on a closed-out row, marking it core forever +
// permanently invisible.
//
// This test asserts: post-resurrect-upsert, the row is visible to
// getMemory + findRelatedExtractedMemories, with valid_to=NULL and
// is_latest=TRUE.
test "V1.6 commit 6 × V1.7 W-INT-01 resurrect-on-upsert clears close-out cols" {
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;
    const test_url = (env_rebrand.getEnvOwnedWithRebrand(allocator, "NULLALIS_POSTGRES_TEST_URL", "NULLCLAW_POSTGRES_TEST_URL") catch return error.SkipZigTest) orelse return error.SkipZigTest;
    defer allocator.free(test_url);

    var schema_buf: [96]u8 = undefined;
    const schema = try std.fmt.bufPrint(&schema_buf, "zaki_bot_test_{d}", .{std.time.microTimestamp()});
    const cfg = config_types.StateConfig{
        .backend = "postgres",
        .postgres = .{
            .connection_string = test_url,
            .schema = schema,
        },
    };

    var mgr = try ManagerImpl.init(allocator, cfg);
    defer mgr.deinit();
    {
        const schema_q = try pg_helpers.quoteIdentifier(allocator, mgr.schemaRaw());
        defer allocator.free(schema_q);
        const drop_q = try std.fmt.allocPrint(allocator, "DROP SCHEMA IF EXISTS {s} CASCADE", .{schema_q});
        defer allocator.free(drop_q);
        const result = try mgr.exec(drop_q);
        c.PQclear(result);
    }
    try mgr.migrate();
    try mgr.provisionUser(2, "/tmp/nullalis-zaki-bot-test-user-2/workspace");

    // ── Step 1: write extraction-classifier row from session A.
    // Use `.daily` (non-core) to exercise the resurrect-on-upsert path —
    // a `.core`-seeded row would hit the core-preserve branch instead,
    // which is the OTHER axis tested in step 6 below.
    //
    // Phase-0.5b note: `.daily` STILL resurrects under the type-based C1 fix
    // (daily is ephemeral — not in DURABLE_MEMORY_TYPES), so this test's
    // behavior is UNCHANGED. The durable types (preference/decision/person/
    // open_loop) now do NOT resurrect — see the dedicated C1 tests
    // "Phase-0.5b C1: durable types do NOT resurrect ...". The universal
    // state-based rule "closed-stays-closed for daily too" is the Phase-1
    // unified-classifier item, intentionally NOT changed here.
    try mgr.upsertMemoryWithMetadata(2, "extracted_resurrect_test", "User prefers NeoVim editor", .daily, "session-A",
        \\{"subject":"user","predicate":"PREFERS","object_key":"NeoVim","attributed_to":"user","attribution":"extraction_classifier","confidence":1.0}
    );

    // ── Step 2: contradiction judge closes it out ─────────────────────
    const close_ts: i64 = std.time.timestamp();
    try mgr.setMemoryInvalidation(2, "extracted_resurrect_test", close_ts, close_ts);
    {
        const hidden = try mgr.getMemory(allocator, 2, "extracted_resurrect_test");
        try std.testing.expect(hidden == null); // confirmed: validity filter hides it
    }

    // ── Step 3: fresh re-statement from session B, SAME key, different content
    try mgr.upsertMemoryWithMetadata(2, "extracted_resurrect_test", "User uses NeoVim as their primary editor", .daily, "session-B",
        \\{"subject":"user","predicate":"USES","object_key":"NeoVim","attributed_to":"user","attribution":"extraction_classifier","confidence":1.0}
    );

    // ── Step 4: row MUST be visible again, with cleared close-out columns
    const resurrected = try mgr.getMemory(allocator, 2, "extracted_resurrect_test");
    try std.testing.expect(resurrected != null);
    var r = resurrected.?;
    defer r.deinit(allocator);
    try std.testing.expectEqualStrings("User uses NeoVim as their primary editor", r.content);
    try std.testing.expect(r.valid_to == null); // CASE-cleared back to NULL

    // Audit columns also reset
    {
        const audit_q = try std.fmt.allocPrint(
            allocator,
            "SELECT valid_to, invalid_at, expired_at, is_latest FROM {s}.memories WHERE user_id = 2 AND key = 'extracted_resurrect_test'",
            .{schema},
        );
        defer allocator.free(audit_q);
        const result = try mgr.exec(audit_q);
        defer c.PQclear(result);
        try std.testing.expectEqual(@as(c_int, 1), c.PQntuples(result));
        // valid_to/invalid_at/expired_at all NULL after resurrect; is_latest = true.
        try std.testing.expectEqual(@as(c_int, 1), c.PQgetisnull(result, 0, 0)); // valid_to NULL
        try std.testing.expectEqual(@as(c_int, 1), c.PQgetisnull(result, 0, 1)); // invalid_at NULL
        try std.testing.expectEqual(@as(c_int, 1), c.PQgetisnull(result, 0, 2)); // expired_at NULL
        const is_latest_str = try dupeResultValue(allocator, result, 0, 3);
        defer allocator.free(is_latest_str);
        try std.testing.expectEqualStrings("t", is_latest_str);
    }

    // ── Step 5: findRelatedExtractedMemories also sees the resurrected row
    const related = try mgr.findRelatedExtractedMemories(allocator, 2, "user", 8);
    defer {
        for (related) |e| e.deinit(allocator);
        allocator.free(related);
    }
    try std.testing.expectEqual(@as(usize, 1), related.len);
    try std.testing.expectEqualStrings("extracted_resurrect_test", related[0].key);

    // ── Step 6: a CORE row that gets closed-out STAYS closed-out across upsert
    // (resurrect is non-core only; explicit demote required for core).
    try mgr.upsertMemory(2, "core_stays_closed", "core fact A", .core, "session-A");
    try mgr.execParamsNoResult(
        "UPDATE {schema}.memories SET memory_type = 'core', session_id = NULL WHERE user_id = $1 AND key = $2",
        &.{ "2", "core_stays_closed" },
        &.{ 1, @as(c_int, @intCast("core_stays_closed".len)) },
    );
    try mgr.setMemoryInvalidation(2, "core_stays_closed", close_ts, close_ts);
    try mgr.upsertMemory(2, "core_stays_closed", "core fact B", .daily, "session-B");
    {
        const closed_core = try mgr.getMemory(allocator, 2, "core_stays_closed");
        try std.testing.expect(closed_core == null); // still hidden — core close-out preserved
    }
}

// ─────────────────────────────────────────────────────────────────────
// Phase-0.5b — durable-type protection (C1/C2/H2/H3/H7) postgres-gated.
//
// A prior patch (P3) routed durable user facts off `memory_type='core'`
// onto `custom:"preference"/"decision"/"person"/"open_loop"`, but the
// protection guards still keyed on the literal `'core'`. These tests pin
// the type-based fixes from `memory_root.{DURABLE,EVERGREEN}_*`:
//   C1 — durable types do NOT resurrect on a benign re-upsert.
//   C2 — a corroborated durable type is NOT promoted (clobbered) to core.
//   H2 — demote reaches the durable types (not just core).
//   H3 — persistent decay exempts the evergreen types (open_loop still decays).
//   H7 — retype/demote only touch LIVE rows (a closed row is skipped).
// Skipped locally (require NULLALIS_POSTGRES_TEST_URL).
// ─────────────────────────────────────────────────────────────────────

/// Helper: read (valid_to_is_null, is_latest) for a key, bypassing the
/// validity filter so superseded rows are visible. Returns booleans.
fn p05bReadCloseOut(mgr: *ManagerImpl, allocator: std.mem.Allocator, user_id: i64, key: []const u8) !struct { valid_to_null: bool, is_latest: bool } {
    const schema_q = try pg_helpers.quoteIdentifier(allocator, mgr.schemaRaw());
    defer allocator.free(schema_q);
    const q = try std.fmt.allocPrint(
        allocator,
        "SELECT valid_to, is_latest FROM {s}.memories WHERE user_id = {d} AND key = '{s}'",
        .{ schema_q, user_id, key },
    );
    defer allocator.free(q);
    const result = try mgr.exec(q);
    defer c.PQclear(result);
    try std.testing.expectEqual(@as(c_int, 1), c.PQntuples(result));
    const valid_to_null = c.PQgetisnull(result, 0, 0) != 0;
    const is_latest_str = try dupeResultValue(allocator, result, 0, 1);
    defer allocator.free(is_latest_str);
    return .{ .valid_to_null = valid_to_null, .is_latest = std.mem.eql(u8, is_latest_str, "t") };
}

// C1 — a superseded DURABLE typed row (preference / open_loop) keeps its
// close-out across a benign re-upsert: valid_to stays NON-NULL, is_latest
// stays FALSE. Contrast the `.daily` resurrect test above (daily DOES revive).
test "Phase-0.5b C1: durable types (preference, open_loop) do NOT resurrect on re-upsert" {
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;
    var mgr = initPostgresTestManagerWithPool(allocator, 2, 500) catch return error.SkipZigTest;
    defer mgr.deinit();
    try mgr.provisionUser(2, "/tmp/nullalis-zaki-bot-test-p05b-c1/workspace");

    const close_ts: i64 = std.time.timestamp();

    // ── preference: seed → supersede → re-upsert → must STAY closed.
    try mgr.upsertMemoryWithMetadata(2, "p05b_pref", "User prefers dark mode", .{ .custom = "preference" }, "sess-A",
        \\{"subject":"user","predicate":"PREFERS","object":"dark mode","attributed_to":"user"}
    );
    try mgr.setMemoryInvalidation(2, "p05b_pref", close_ts, close_ts);
    // Benign re-upsert, same key, fresh content from a new session.
    try mgr.upsertMemoryWithMetadata(2, "p05b_pref", "User prefers a dark theme", .{ .custom = "preference" }, "sess-B",
        \\{"subject":"user","predicate":"PREFERS","object":"dark theme","attributed_to":"user"}
    );
    {
        const co = try p05bReadCloseOut(&mgr, allocator, 2, "p05b_pref");
        try std.testing.expect(!co.valid_to_null); // valid_to stays NON-NULL — NOT resurrected
        try std.testing.expect(!co.is_latest); // is_latest stays FALSE
        // memory_type preserved (anti-demotion): still a preference.
        const t = try c0ReadMemoryType(allocator, &mgr, 2, "p05b_pref");
        defer allocator.free(t);
        try std.testing.expectEqualStrings("preference", t);
        // And it stays hidden from retrieval (closed-out).
        const got = try mgr.getMemory(allocator, 2, "p05b_pref");
        try std.testing.expect(got == null);
    }

    // ── open_loop: durable too — same closed-stays-closed behavior.
    try mgr.upsertMemoryWithMetadata(2, "p05b_loop", "Waiting on the contract review", .{ .custom = "open_loop" }, "sess-A",
        \\{"subject":"user","predicate":"AWAITING","object":"contract review","attributed_to":"user"}
    );
    try mgr.setMemoryInvalidation(2, "p05b_loop", close_ts, close_ts);
    try mgr.upsertMemoryWithMetadata(2, "p05b_loop", "Still waiting on contract review", .{ .custom = "open_loop" }, "sess-B",
        \\{"subject":"user","predicate":"AWAITING","object":"contract review","attributed_to":"user"}
    );
    {
        const co = try p05bReadCloseOut(&mgr, allocator, 2, "p05b_loop");
        try std.testing.expect(!co.valid_to_null); // open_loop is DURABLE → NOT resurrected
        try std.testing.expect(!co.is_latest);
        const t = try c0ReadMemoryType(allocator, &mgr, 2, "p05b_loop");
        defer allocator.free(t);
        try std.testing.expectEqualStrings("open_loop", t);
    }
}

// C2 — a `preference` written from ≥2 distinct sessions (which would trip
// Tier-3 auto-promotion for a generic row) is NOT promoted to core. Its
// memory_type stays `preference` (promotion would erase the type + drop it
// from its <preferences> view).
test "Phase-0.5b C2: corroborated preference is NOT promoted/clobbered to core" {
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;
    var mgr = initPostgresTestManagerWithPool(allocator, 2, 500) catch return error.SkipZigTest;
    defer mgr.deinit();
    try mgr.provisionUser(2, "/tmp/nullalis-zaki-bot-test-p05b-c2/workspace");

    // Two cross-session writes of the SAME preference key → seen_in_session
    // count reaches the promotion trigger. The fix gates promotion on
    // `!isDurableMemoryType`, so a preference is left alone.
    try mgr.upsertMemoryWithMetadata(2, "p05b_promo_pref", "User prefers tabs over spaces", .{ .custom = "preference" }, "sess-A",
        \\{"subject":"user","predicate":"PREFERS","object":"tabs","attributed_to":"user"}
    );
    try mgr.upsertMemoryWithMetadata(2, "p05b_promo_pref", "User prefers tabs not spaces", .{ .custom = "preference" }, "sess-B",
        \\{"subject":"user","predicate":"PREFERS","object":"tabs","attributed_to":"user"}
    );

    const t = try c0ReadMemoryType(allocator, &mgr, 2, "p05b_promo_pref");
    defer allocator.free(t);
    try std.testing.expectEqualStrings("preference", t); // NOT "core"

    // Sanity: the comparison case — a generic `.daily` corroborated row DOES
    // still promote to core (promotion path itself is intact).
    try mgr.upsertMemory(2, "p05b_promo_daily", "some fact", .daily, "sess-A");
    try mgr.upsertMemory(2, "p05b_promo_daily", "some fact restated", .daily, "sess-B");
    const dt = try c0ReadMemoryType(allocator, &mgr, 2, "p05b_promo_daily");
    defer allocator.free(dt);
    try std.testing.expectEqualStrings("core", dt); // generic row still promotes
}

// H2 + H7 — demote reaches the durable types AND only touches LIVE rows.
//   (a) demoting a `preference` updates exactly 1 row (returns true).
//   (b) demote skips a CLOSED durable row (validity guard) → returns false.
test "Phase-0.5b H2/H7: demote reaches durable types, skips closed rows" {
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;
    var mgr = initPostgresTestManagerWithPool(allocator, 2, 500) catch return error.SkipZigTest;
    defer mgr.deinit();
    try mgr.provisionUser(2, "/tmp/nullalis-zaki-bot-test-p05b-h2/workspace");

    // ── (a) H2: demote a LIVE preference → 1 row updated, type becomes daily.
    try mgr.upsertMemoryWithMetadata(2, "p05b_demote_pref", "User prefers dark mode", .{ .custom = "preference" }, "sess-A",
        \\{"subject":"user","predicate":"PREFERS","object":"dark mode","attributed_to":"user"}
    );
    const demoted = try mgr.demoteMemoryFromCore(2, "p05b_demote_pref", "daily");
    try std.testing.expect(demoted); // before the fix this was false (only matched 'core')
    {
        const t = try c0ReadMemoryType(allocator, &mgr, 2, "p05b_demote_pref");
        defer allocator.free(t);
        try std.testing.expectEqualStrings("daily", t);
    }

    // ── (b) H7: demote a CLOSED preference → skipped (validity guard).
    const close_ts: i64 = std.time.timestamp();
    try mgr.upsertMemoryWithMetadata(2, "p05b_demote_closed", "User prefers light mode", .{ .custom = "preference" }, "sess-A",
        \\{"subject":"user","predicate":"PREFERS","object":"light mode","attributed_to":"user"}
    );
    try mgr.setMemoryInvalidation(2, "p05b_demote_closed", close_ts, close_ts);
    const demoted_closed = try mgr.demoteMemoryFromCore(2, "p05b_demote_closed", "daily");
    try std.testing.expect(!demoted_closed); // closed row is LIVE-guarded → not touched
    {
        // type unchanged — still preference (was NOT retyped to daily).
        const t = try c0ReadMemoryType(allocator, &mgr, 2, "p05b_demote_closed");
        defer allocator.free(t);
        try std.testing.expectEqualStrings("preference", t);
    }
}

// H3 — the persistent confidence-decay sweep (temporalDecay) EXEMPTS the
// evergreen types. A `preference` row is NOT decayed; a `daily` row IS, and
// an `open_loop` row IS (open_loop is durable but NOT evergreen).
test "Phase-0.5b H3: persistent decay exempts evergreen, still decays daily + open_loop" {
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;
    var mgr = initPostgresTestManagerWithPool(allocator, 2, 500) catch return error.SkipZigTest;
    defer mgr.deinit();
    try mgr.provisionUser(2, "/tmp/nullalis-zaki-bot-test-p05b-h3/workspace");

    const schema_q = try pg_helpers.quoteIdentifier(allocator, mgr.schemaRaw());
    defer allocator.free(schema_q);

    // Seed three rows with a high starting confidence + an OLD last_accessed_at
    // so the age-based decay window (threshold_days) is satisfied.
    inline for (.{
        .{ "p05b_decay_pref", "preference" },
        .{ "p05b_decay_daily", "daily" },
        .{ "p05b_decay_loop", "open_loop" },
    }) |row| {
        try mgr.upsertMemory(2, row[0], "content for " ++ row[0], .daily, "sess-A");
        const seed_q = try std.fmt.allocPrint(
            allocator,
            "UPDATE {s}.memories SET memory_type = '{s}', confidence_score = 0.8, " ++
                "last_accessed_at = NOW() - INTERVAL '90 days', created_at = NOW() - INTERVAL '90 days' " ++
                "WHERE user_id = 2 AND key = '{s}'",
            .{ schema_q, row[1], row[0] },
        );
        defer allocator.free(seed_q);
        const r = try mgr.exec(seed_q);
        c.PQclear(r);
    }

    // Run the persistent decay sweep: threshold 30d, half-life 30d.
    _ = try mgr.temporalDecay(2, 30, 30);

    // Read back confidence_score per row.
    const Reader = struct {
        fn conf(m: *ManagerImpl, a: std.mem.Allocator, sq: []const u8, key: []const u8) !f64 {
            const q = try std.fmt.allocPrint(a, "SELECT confidence_score FROM {s}.memories WHERE user_id = 2 AND key = '{s}'", .{ sq, key });
            defer a.free(q);
            const res = try m.exec(q);
            defer c.PQclear(res);
            const s = try dupeResultValue(a, res, 0, 0);
            defer a.free(s);
            return std.fmt.parseFloat(f64, s);
        }
    };

    const pref_conf = try Reader.conf(&mgr, allocator, schema_q, "p05b_decay_pref");
    const daily_conf = try Reader.conf(&mgr, allocator, schema_q, "p05b_decay_daily");
    const loop_conf = try Reader.conf(&mgr, allocator, schema_q, "p05b_decay_loop");

    // preference is EVERGREEN → untouched, stays at the seeded 0.8.
    try std.testing.expectApproxEqAbs(@as(f64, 0.8), pref_conf, 1e-9);
    // daily decays below the seed.
    try std.testing.expect(daily_conf < 0.8);
    // open_loop is durable but NOT evergreen → it still decays.
    try std.testing.expect(loop_conf < 0.8);
}

// H7 (backfill) — phase05BackfillRetypeRows only retypes LIVE rows. A CLOSED
// row carrying a predicate is skipped (its memory_type is left untouched),
// so a closed row is never moved from protected → resurrectable.
test "Phase-0.5b H7: phase05Backfill skips a closed row" {
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;
    var mgr = initPostgresTestManagerWithPool(allocator, 2, 500) catch return error.SkipZigTest;
    defer mgr.deinit();
    try mgr.provisionUser(2, "/tmp/nullalis-zaki-bot-test-p05b-h7/workspace");

    const close_ts: i64 = std.time.timestamp();

    // A LIVE daily row with a PREFERS predicate (a retype candidate) and a
    // CLOSED daily row with the same shape. Only the live one should retype.
    try mgr.upsertMemoryWithMetadata(2, "p05b_bf_live", "User prefers dark mode", .daily, "sess-A",
        \\{"subject":"user","predicate":"PREFERS","object":"dark mode","attributed_to":"user"}
    );
    try mgr.upsertMemoryWithMetadata(2, "p05b_bf_closed", "User prefers light mode", .daily, "sess-A",
        \\{"subject":"user","predicate":"PREFERS","object":"light mode","attributed_to":"user"}
    );
    try mgr.setMemoryInvalidation(2, "p05b_bf_closed", close_ts, close_ts);

    const report = try mgr.phase05Backfill(allocator, 2, false);
    // Exactly the LIVE row is retyped; the closed row is skipped.
    try std.testing.expectEqual(@as(usize, 1), report.rows_retyped);

    const live_t = try c0ReadMemoryType(allocator, &mgr, 2, "p05b_bf_live");
    defer allocator.free(live_t);
    try std.testing.expectEqualStrings("preference", live_t); // retyped

    const closed_t = try c0ReadMemoryType(allocator, &mgr, 2, "p05b_bf_closed");
    defer allocator.free(closed_t);
    try std.testing.expectEqualStrings("daily", closed_t); // untouched — still daily, still closed
}

// V1.6 commit 7 — memory_edges round-trip + dedup + cascade-close-out.
//
// Acceptance gates per spec: (a) upsertMemoryEdge inserts a row and the
// UNIQUE INDEX on (user_id, source_key, predicate, target_key) WHERE
// is_latest dedupes re-writes (weight bumps instead); (b) countEdgesForSource
// returns the active edge count; (c) listEdgesForUser returns active edges;
// (d) setMemoryInvalidation cascades — closing a memory closes its edges.
test "V1.6 commit 7 memory_edges insert + dedup + cascade-on-close" {
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;
    const test_url = (env_rebrand.getEnvOwnedWithRebrand(allocator, "NULLALIS_POSTGRES_TEST_URL", "NULLCLAW_POSTGRES_TEST_URL") catch return error.SkipZigTest) orelse return error.SkipZigTest;
    defer allocator.free(test_url);

    var schema_buf: [96]u8 = undefined;
    const schema = try std.fmt.bufPrint(&schema_buf, "zaki_bot_test_{d}", .{std.time.microTimestamp()});
    const cfg = config_types.StateConfig{
        .backend = "postgres",
        .postgres = .{ .connection_string = test_url, .schema = schema },
    };

    var mgr = try ManagerImpl.init(allocator, cfg);
    defer mgr.deinit();
    {
        const schema_q = try pg_helpers.quoteIdentifier(allocator, mgr.schemaRaw());
        defer allocator.free(schema_q);
        const drop_q = try std.fmt.allocPrint(allocator, "DROP SCHEMA IF EXISTS {s} CASCADE", .{schema_q});
        defer allocator.free(drop_q);
        const result = try mgr.exec(drop_q);
        c.PQclear(result);
    }
    try mgr.migrate();
    try mgr.provisionUser(2, "/tmp/nullalis-zaki-bot-test-user-2/workspace");

    // ── Seed a parent memory + an edge from it
    try mgr.upsertMemoryWithMetadata(2, "extracted_helix_pref", "User prefers Helix", .daily, "session-A",
        \\{"subject":"user","predicate":"PREFERS","object_key":"Helix","attributed_to":"user","attribution":"extraction_classifier","confidence":0.95}
    );
    try mgr.upsertMemoryEdge(2, "extracted_helix_pref", "entity_helix", "PREFERS", "extraction_classifier", 0.95);

    // ── Step A: countEdgesForSource sees the active edge
    {
        const n = try mgr.countEdgesForSource(2, "extracted_helix_pref");
        try std.testing.expectEqual(@as(usize, 1), n);
    }

    // ── Step B: re-insert same triple — UNIQUE INDEX dedupes (weight bumps to 2.0)
    try mgr.upsertMemoryEdge(2, "extracted_helix_pref", "entity_helix", "PREFERS", "extraction_classifier", 0.99);
    {
        const n = try mgr.countEdgesForSource(2, "extracted_helix_pref");
        try std.testing.expectEqual(@as(usize, 1), n); // still 1 — deduped
    }

    // ── Step C: different triple from same source → new edge
    try mgr.upsertMemoryEdge(2, "extracted_helix_pref", "entity_neovim", "REPLACES", "extraction_classifier", 0.85);
    {
        const n = try mgr.countEdgesForSource(2, "extracted_helix_pref");
        try std.testing.expectEqual(@as(usize, 2), n);
    }

    // ── Step D: listEdgesForUser returns both active edges
    {
        const edges = try mgr.listEdgesForUser(allocator, 2);
        defer memory_root.freeTypedEdges(allocator, edges);
        try std.testing.expectEqual(@as(usize, 2), edges.len);
    }

    // ── Step E: cascade close-out — closing the memory closes its edges
    const close_ts: i64 = std.time.timestamp();
    try mgr.setMemoryInvalidation(2, "extracted_helix_pref", close_ts, close_ts);
    {
        const n = try mgr.countEdgesForSource(2, "extracted_helix_pref");
        try std.testing.expectEqual(@as(usize, 0), n); // cascade fired — edges hidden
    }
    {
        const edges = try mgr.listEdgesForUser(allocator, 2);
        defer memory_root.freeTypedEdges(allocator, edges);
        try std.testing.expectEqual(@as(usize, 0), edges.len);
    }

    // ── Step F: cascade audit — direct SQL confirms is_latest=false on closed edges
    {
        const audit_q = try std.fmt.allocPrint(
            allocator,
            "SELECT COUNT(*) FROM {s}.memory_edges WHERE user_id = 2 AND is_latest = FALSE",
            .{schema},
        );
        defer allocator.free(audit_q);
        const result = try mgr.exec(audit_q);
        defer c.PQclear(result);
        const closed_count_str = try dupeResultValue(allocator, result, 0, 0);
        defer allocator.free(closed_count_str);
        try std.testing.expectEqualStrings("2", closed_count_str); // both edges closed
    }
}

// Brain-graph activation hardening (C1) — PPR must not be flooded by the
// per-user speaker hub (`user:<id>` USER_MENTIONED edges minted by the entity
// pipeline). The hub is non-discriminative ("user mentioned everything"), and
// findEdgesPPR has no degree normalization, so before activating the entity
// pipeline the recursive traversal must exclude `user:%` endpoints. Otherwise
// a seed one hop from the hub bleeds score into every node the user ever
// mentioned.
//
// Acceptance: from a seed whose ONLY path to a swarm of unrelated nodes runs
// through the speaker hub, PPR returns the genuine 1-hop neighbor but NOT the
// hub or any hub-only-reachable junk node.
test "C1 PPR hub-exclusion — speaker hub does not flood traversal" {
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;
    const test_url = (env_rebrand.getEnvOwnedWithRebrand(allocator, "NULLALIS_POSTGRES_TEST_URL", "NULLCLAW_POSTGRES_TEST_URL") catch return error.SkipZigTest) orelse return error.SkipZigTest;
    defer allocator.free(test_url);

    var schema_buf: [96]u8 = undefined;
    const schema = try std.fmt.bufPrint(&schema_buf, "zaki_bot_test_{d}", .{std.time.microTimestamp()});
    const cfg = config_types.StateConfig{
        .backend = "postgres",
        .postgres = .{ .connection_string = test_url, .schema = schema },
    };
    var mgr = try ManagerImpl.init(allocator, cfg);
    defer mgr.deinit();
    {
        const schema_q = try pg_helpers.quoteIdentifier(allocator, mgr.schemaRaw());
        defer allocator.free(schema_q);
        const drop_q = try std.fmt.allocPrint(allocator, "DROP SCHEMA IF EXISTS {s} CASCADE", .{schema_q});
        defer allocator.free(drop_q);
        const result = try mgr.exec(drop_q);
        c.PQclear(result);
    }
    try mgr.migrate();
    try mgr.provisionUser(2, "/tmp/nullalis-zaki-bot-test-ppr-hub/workspace");

    // Genuine, discriminative chain: seed → A → B (KNOWS edges).
    try mgr.upsertMemoryEdge(2, "mem_seed", "mem_a", "KNOWS", "test", 0.9);
    try mgr.upsertMemoryEdge(2, "mem_a", "mem_b", "KNOWS", "test", 0.9);

    // Per-user speaker/self hub touches the seed AND 30 unrelated junk nodes.
    // Without hub-exclusion, PPR from mem_seed walks the hub edge and floods
    // every junk_* node with score.
    try mgr.upsertMemoryEdge(2, "user:2", "mem_seed", "USER_MENTIONED", "wiki_link", 0.9);
    // Per-session source hub (structural orphan-killer) touches the seed AND a
    // separate swarm of session-junk nodes — same flood risk via a different
    // structural hub.
    try mgr.upsertMemoryEdge(2, "mem_seed", "session:s1", "IN_SESSION", "structural", 1.0);
    var k: usize = 0;
    while (k < 30) : (k += 1) {
        var jkey_buf: [32]u8 = undefined;
        const jkey = try std.fmt.bufPrint(&jkey_buf, "junk_{d}", .{k});
        try mgr.upsertMemoryEdge(2, "user:2", jkey, "USER_MENTIONED", "wiki_link", 0.9);
        var sjkey_buf: [32]u8 = undefined;
        const sjkey = try std.fmt.bufPrint(&sjkey_buf, "sjunk_{d}", .{k});
        try mgr.upsertMemoryEdge(2, "session:s1", sjkey, "IN_SESSION", "structural", 1.0);
    }

    const seeds = [_][]const u8{"mem_seed"};
    const nodes = try mgr.findEdgesPPR(allocator, 2, &seeds, 3, 200);
    defer {
        for (nodes) |n| n.deinit(allocator);
        allocator.free(nodes);
    }

    var saw_a = false;
    var saw_junk = false;
    var saw_hub = false;
    var saw_session = false;
    for (nodes) |n| {
        if (std.mem.eql(u8, n.key, "mem_a")) saw_a = true;
        if (std.mem.startsWith(u8, n.key, "junk_") or std.mem.startsWith(u8, n.key, "sjunk_")) saw_junk = true;
        if (std.mem.startsWith(u8, n.key, "user:")) saw_hub = true;
        if (std.mem.startsWith(u8, n.key, "session:")) saw_session = true;
    }
    try std.testing.expect(saw_a); // genuine neighbor reached
    try std.testing.expect(!saw_hub); // speaker/self hub excluded from traversal
    try std.testing.expect(!saw_session); // session source hub excluded too
    try std.testing.expect(!saw_junk); // hub-only junk fan-out not reachable
}

// Structural orphan-killer: every graph-worthy memory gets a deterministic,
// LLM-free edge to its session source hub the moment it is written, so it is
// never a graph orphan. First-person memories additionally anchor to the
// self/focus hub. Transient `conversation` rows are intentionally NOT graphed.
test "C-struct structural edges connect memories to session + self hub" {
    if (!build_options.enable_postgres) return error.SkipZigTest;
    const allocator = std.testing.allocator;
    const test_url = (env_rebrand.getEnvOwnedWithRebrand(allocator, "NULLALIS_POSTGRES_TEST_URL", "NULLCLAW_POSTGRES_TEST_URL") catch return error.SkipZigTest) orelse return error.SkipZigTest;
    defer allocator.free(test_url);

    var schema_buf: [96]u8 = undefined;
    const schema = try std.fmt.bufPrint(&schema_buf, "zaki_bot_test_{d}", .{std.time.microTimestamp()});
    const cfg = config_types.StateConfig{
        .backend = "postgres",
        .postgres = .{ .connection_string = test_url, .schema = schema },
    };
    var mgr = try ManagerImpl.init(allocator, cfg);
    defer mgr.deinit();
    {
        const schema_q = try pg_helpers.quoteIdentifier(allocator, mgr.schemaRaw());
        defer allocator.free(schema_q);
        const drop_q = try std.fmt.allocPrint(allocator, "DROP SCHEMA IF EXISTS {s} CASCADE", .{schema_q});
        defer allocator.free(drop_q);
        const result = try mgr.exec(drop_q);
        c.PQclear(result);
    }
    try mgr.migrate();
    try mgr.provisionUser(2, "/tmp/nullalis-zaki-bot-test-struct/workspace");

    // Graph-worthy core fact with a session → must get an IN_SESSION edge.
    try mgr.upsertMemoryWithMetadata(2, "fact_dubai", "Lives in Dubai", .core, "sess-1", "{}");
    // First-person fact → IN_SESSION source edge AND an ABOUT_SELF self-hub edge.
    try mgr.upsertMemoryWithMetadata(2, "fact_self", "I love hiking in the mountains", .core, "sess-1", "{}");
    // Transient conversation turn → NOT graphed (stays out by design).
    try mgr.upsertMemoryWithMetadata(2, "turn_noise", "health check", .conversation, "sess-1", "{}");

    const edges = try mgr.listEdgesForUser(allocator, 2);
    defer memory_root.freeTypedEdges(allocator, edges);

    var dubai_session = false;
    var self_session = false;
    var self_about = false;
    var noise_any = false;
    for (edges) |e| {
        if (std.mem.eql(u8, e.source_key, "fact_dubai") and std.mem.eql(u8, e.target_key, "session:sess-1") and std.mem.eql(u8, e.predicate, "IN_SESSION")) dubai_session = true;
        if (std.mem.eql(u8, e.source_key, "fact_self") and std.mem.eql(u8, e.target_key, "session:sess-1")) self_session = true;
        if (std.mem.eql(u8, e.source_key, "fact_self") and std.mem.eql(u8, e.target_key, "user:2") and std.mem.eql(u8, e.predicate, "ABOUT_SELF")) self_about = true;
        if (std.mem.eql(u8, e.source_key, "turn_noise")) noise_any = true;
    }
    try std.testing.expect(dubai_session); // every graph-worthy memory is connected
    try std.testing.expect(self_session); // first-person fact still gets its source edge
    try std.testing.expect(self_about); // ...plus the self-hub anchor
    try std.testing.expect(!noise_any); // transient conversation stays out of the graph

    // Orphan check: fact_dubai is no longer an orphan (has an incident edge).
    const dubai_edges = try mgr.countEdgesForSource(2, "fact_dubai");
    try std.testing.expect(dubai_edges >= 1);
}

// The keystone edge: memory->entity MENTIONS. Unlike the structural session
